const ALL_QUESTIONS = [{"id": 1, "chapter": "第1章_综合内科护理", "original_id": 1, "type": "judge", "question": "非同步直流电除颤后应立即查看患者自主心率是否恢复", "options": {"A": "正确", "B": "错误"}, "answer": "B"}, {"id": 2, "chapter": "第1章_综合内科护理", "original_id": 2, "type": "judge", "question": "火灾应急处理病区疏散支援原则是上二下一不动其余各楼层支援一名（即发生火灾楼层的上面两层及下面一层不动随时准备疏散，其余各楼层安排一名工作人员到达火灾现场支援）", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 3, "chapter": "第1章_综合内科护理", "original_id": 3, "type": "judge", "question": "每日咯血量在500ml以上或一次咯血量大于300ml为大量咯血", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 4, "chapter": "第1章_综合内科护理", "original_id": 4, "type": "judge", "question": "心源性水肿主要是右心衰的表现，为对称性、非凹陷性水肿，颜面部一般不肿", "options": {"A": "正确", "B": "错误"}, "answer": "B"}, {"id": 5, "chapter": "第1章_综合内科护理", "original_id": 5, "type": "judge", "question": "雷诺现象的皮肤颜色变化顺序为白→紫→红", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 6, "chapter": "第1章_综合内科护理", "original_id": 6, "type": "judge", "question": "深部组织损伤期：缺损涉及到组织全层，但溃疡完全被创面的腐肉和焦痂所覆盖", "options": {"A": "正确", "B": "错误"}, "answer": "B"}, {"id": 7, "chapter": "第1章_综合内科护理", "original_id": 7, "type": "judge", "question": "克罗恩病主要累及回肠末段", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 8, "chapter": "第1章_综合内科护理", "original_id": 8, "type": "judge", "question": "洋地黄中毒最严重的不良反应是心律失常", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 9, "chapter": "第1章_综合内科护理", "original_id": 9, "type": "judge", "question": "疼痛是由实际或在的组织损伤，所引起的一种不愉快的感觉和主观体验。已被列为第五大生命体征", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 10, "chapter": "第1章_综合内科护理", "original_id": 10, "type": "judge", "question": "低盐饮食中钠含量应低于1.5g/d", "options": {"A": "正确", "B": "错误"}, "answer": "B"}, {"id": 11, "chapter": "第1章_综合内科护理", "original_id": 11, "type": "single", "question": "引起支气管肺炎最常见的细菌是", "options": {"A": "大肠埃希菌", "B": "变形杆菌", "C": "脑膜炎双球菌", "D": "金黄色葡萄球菌", "E": "肺炎链球菌"}, "answer": "E"}, {"id": 12, "chapter": "第1章_综合内科护理", "original_id": 12, "type": "single", "question": "血管壁功能异常所致的出血性疾病为", "options": {"A": "特发性血小板减少性紫癜", "B": "血友病", "C": "弥散性紫癜", "D": "过敏性紫癜"}, "answer": "D"}, {"id": 13, "chapter": "第1章_综合内科护理", "original_id": 13, "type": "single", "question": "叶某，女，56岁。有\"风湿性心脏病\"病史。自诉心慌。心电图:P波消失，代之以间距、振幅不等的颤动波，QRS波正常，心室率120次/分，R-R间距绝对不等。该病人的心电图诊断为", "options": {"A": "室上性心动过速", "B": "室性心动过速", "C": "房性心动过速", "D": "心房扑动", "E": "心房颤动"}, "answer": "E"}, {"id": 14, "chapter": "第1章_综合内科护理", "original_id": 14, "type": "single", "question": "患者女性，30岁。近日无明显诱因出现咳嗽、乏力、四肢关节酸痛，伴左侧小腿散在出血点，牙龈红肿出血。血常规示：Hb 34g/L，WBC 4.3×10/L，PLT 16×10/L。骨髓穿刺示：骨髓增生活跃，原始白细胞33.5%。根据上述临床表现和检查结果，患者目前最可能的诊断是", "options": {"A": "溶血性贫血", "B": "再生障碍性贫血", "C": "急性白血病", "D": "特发性血小板减少性紫癜", "E": "血友病"}, "answer": "C"}, {"id": 15, "chapter": "第1章_综合内科护理", "original_id": 15, "type": "single", "question": "血糖仪质控时机错误的是", "options": {"A": "每天血糖检测前", "B": "更换新批号试纸条", "C": "每次血糖检测前", "D": "血糖仪更换电池", "E": "器及试纸条可能未处于最佳状态时"}, "answer": "C"}, {"id": 16, "chapter": "第1章_综合内科护理", "original_id": 16, "type": "single", "question": "输血引起溶血反应，最早出现的主要表现为", "options": {"A": "少尿", "B": "寒战、高热", "C": "呼吸困难、血压下降", "D": "瘙痒、皮疹", "E": "头部胀痛、面部潮红、恶心、呕吐、腰背部剧痛"}, "answer": "E"}, {"id": 17, "chapter": "第1章_综合内科护理", "original_id": 17, "type": "single", "question": "关于颅神经说法错误的是（）", "options": {"A": "嗅神经，主要负责鼻子的嗅觉", "B": "外展神经，主管眼球向外下方的运动", "C": "视神经，主管眼睛的视物功能", "D": "滑车神经，主管眼球向外下方的运动"}, "answer": "B"}, {"id": 18, "chapter": "第1章_综合内科护理", "original_id": 18, "type": "single", "question": "急性前壁心肌梗死的特征性心电图改变见于（）（1分）", "options": {"A": "V1-V6导联", "B": "V1-V3导联", "C": "V3-V5导联", "D": "I、aVL导联", "E": "V1-V3及I、aVL导联"}, "answer": "C"}, {"id": 19, "chapter": "第1章_综合内科护理", "original_id": 19, "type": "single", "question": "人体铁剂吸收的主要部位是（）（1分）", "options": {"A": "胃体部", "B": "胃窦部", "C": "十二指肠及空肠上部", "D": "十二指肠球部", "E": "空肠与回肠"}, "answer": "C"}, {"id": 20, "chapter": "第1章_综合内科护理", "original_id": 20, "type": "single", "question": "抢救糖尿病酮症酸中毒病人最首要和关键的措施是（）（1分）", "options": {"A": "治疗诱因", "B": "使用小剂量胰岛素", "C": "补液", "D": "纠正电解质紊乱及酸碱平衡失调", "E": "纠正脑水肿"}, "answer": "C"}, {"id": 21, "chapter": "第1章_综合内科护理", "original_id": 21, "type": "single", "question": "保护具不适用于（1分）", "options": {"A": "躁动不安者", "B": "高热者", "C": "谵妄者", "D": "昏迷者", "E": "不愿配合治疗者"}, "answer": "E"}, {"id": 22, "chapter": "第1章_综合内科护理", "original_id": 22, "type": "single", "question": "细胞内液最主要的阳离子为（1分）", "options": {"A": "K+", "B": "Ca2+", "C": "NA+", "D": "Fe2+", "E": "Mg2+"}, "answer": "A"}, {"id": 23, "chapter": "第1章_综合内科护理", "original_id": 23, "type": "single", "question": "患者女性，25岁。因患系统性红斑狼疮住院2次，本次住院面部红斑明显，伴有乏力、食欲减退等。造成该患者皮肤红斑的主要原因是（1分）", "options": {"A": "日晒过多", "B": "皮肤过敏", "C": "长期使用免疫抑制剂", "D": "青春期痤疮", "E": "免疫复合物沉积"}, "answer": "E"}, {"id": 24, "chapter": "第1章_综合内科护理", "original_id": 24, "type": "single", "question": "阿司匹林治疗脑动脉硬化的原理是（1分）", "options": {"A": "降低血黏度", "B": "增加血管壁弹性", "C": "扩张小动脉", "D": "降低毛细血管通透性"}, "answer": "A"}, {"id": 25, "chapter": "第1章_综合内科护理", "original_id": 25, "type": "single", "question": "肝豆状核变性是由于下列哪种元素在体内的沉积引起的（1分）", "options": {"A": "铁", "B": "钙", "C": "铜", "D": "汞"}, "answer": "C"}, {"id": 26, "chapter": "第1章_综合内科护理", "original_id": 26, "type": "single", "question": "缺铁性贫血病人服铁剂停药时间原则为（1分）", "options": {"A": "服至血红蛋白及红细胞接近正常", "B": "服至血红蛋白及红细胞正常", "C": "服至血红蛋白及红细胞正常后半个月", "D": "服至血红蛋白及红细胞正常后1个月", "E": "服至血红蛋白及红细胞正常后3-6个月"}, "answer": "E"}, {"id": 27, "chapter": "第1章_综合内科护理", "original_id": 27, "type": "single", "question": "高血糖高渗性昏迷应首先采取的抢救措施为（1分）", "options": {"A": "大量补充液体", "B": "积极纠正酸中毒", "C": "小剂量胰岛素治疗", "D": "平衡电解质紊乱", "E": "使用中枢兴奋剂"}, "answer": "A"}, {"id": 28, "chapter": "第1章_综合内科护理", "original_id": 28, "type": "single", "question": "高血压危象紧急处理的关键是（1分）", "options": {"A": "绝对卧床休息", "B": "降低颅内压", "C": "迅速降低血压", "D": "给予氧气吸入", "E": "限制钠盐摄入"}, "answer": "B"}, {"id": 29, "chapter": "第1章_综合内科护理", "original_id": 29, "type": "single", "question": "护理频繁呕吐伴有突然头痛的患者时，突然发现其意识不清脉搏呼吸减慢，左右瞳孔明显不等大，应考虑（1分）", "options": {"A": "蛛网膜下腔出血", "B": "脑疝形成", "C": "高血压危象", "D": "癫痫发作", "E": "脑血栓形成"}, "answer": "B"}, {"id": 30, "chapter": "第1章_综合内科护理", "original_id": 30, "type": "single", "question": "药液漏出血管外，可导致局部缺血坏死的药物是（1分）", "options": {"A": "麻黄碱", "B": "异丙肾上腺素", "C": "去甲肾上腺素", "D": "肾上腺素"}, "answer": "C"}, {"id": 31, "chapter": "第1章_综合内科护理", "original_id": 31, "type": "single", "question": "董某，男，20岁。因车祸入院。身体评估:呼之不应，问之不答，压眶时可见痛苦表情和肢体躲避反应。该病人的意识障碍属于", "options": {"A": "嗜睡", "B": "意识模糊", "C": "昏睡", "D": "浅昏迷", "E": "深昏迷"}, "answer": "D"}, {"id": 32, "chapter": "第1章_综合内科护理", "original_id": 32, "type": "single", "question": "苏某，女，34岁。1周前被诊断患有慢性肾小球肾炎，查血尿素氮和血肌酐均明显高于正常。目前该病人的蛋白质摄入应为", "options": {"A": "正常量", "B": "低蛋白饮食", "C": "零蛋白饮食", "D": "1.0~1.2g/(kg·d)", "E": "0.6~0.8g/(kg·d)的优质蛋白"}, "answer": "E"}, {"id": 33, "chapter": "第1章_综合内科护理", "original_id": 33, "type": "single", "question": "大量蛋白尿是指尿蛋白定量大于", "options": {"A": "1.5g/d", "B": "3.5g/d", "C": "4.0g/d", "D": "5.0g/d"}, "answer": "B"}, {"id": 34, "chapter": "第1章_综合内科护理", "original_id": 34, "type": "single", "question": "下列有关心电图记录纸描述错误的是（1分）", "options": {"A": "横线代表时间", "B": "纵线代表电压", "C": "走纸速度25mm/s时，每小格(横向)代表0.02s", "D": "走纸速度25mm/s时，每小格(横向)代表0.04s", "E": "标准电压10mm/Mv时，每小格(纵向)代表0.1Mv"}, "answer": "C"}, {"id": 35, "chapter": "第1章_综合内科护理", "original_id": 35, "type": "single", "question": "李某，女，26岁。淋暴雨后突然出现高热，体温最高达39.8℃，伴咳嗽、咳痰，痰液为铁锈色。该病人最可能的诊断是（）", "options": {"A": "肺炎球菌肺炎", "B": "阿米巴肺脓肿", "C": "急性肺水肿", "D": "克雷伯杆菌肺炎", "E": "普通感冒"}, "answer": "A"}, {"id": 36, "chapter": "第1章_综合内科护理", "original_id": 36, "type": "single", "question": "某心脏病患者，在日常活动中爬2层楼楼梯即会感觉胸闷气喘，需休息一会才能缓解", "options": {"A": "I级", "B": "II级", "C": "III级", "D": "IV级"}, "answer": "B"}, {"id": 37, "chapter": "第1章_综合内科护理", "original_id": 37, "type": "single", "question": "使颅内压增高的因素不包括", "options": {"A": "PaCO2增高", "B": "脑血流量减少", "C": "血压升高", "D": "中心静脉压增高", "E": "PaO2下降"}, "answer": "B"}, {"id": 38, "chapter": "第1章_综合内科护理", "original_id": 38, "type": "single", "question": "下列哪项属浅反射", "options": {"A": "肛门反射", "B": "桡反射", "C": "踝反射", "D": "肱二头肌反射"}, "answer": "A"}, {"id": 39, "chapter": "第1章_综合内科护理", "original_id": 39, "type": "single", "question": "颅内压增高的典型表现是", "options": {"A": "眩晕伴呕吐", "B": "头痛、呕吐、视盘水肿", "C": "躁动不安、胡言乱语", "D": "短暂意识丧失、脉搏加速"}, "answer": "B"}, {"id": 40, "chapter": "第1章_综合内科护理", "original_id": 40, "type": "single", "question": "常用于反映肾小球滤过功能的指标是()", "options": {"A": "血肌酐", "B": "尿渗量", "C": "尿蛋白", "D": "昼夜尿比重", "E": "尿β微球蛋白"}, "answer": "A"}, {"id": 41, "chapter": "第1章_综合内科护理", "original_id": 41, "type": "single", "question": "患者，李先生，68岁，有慢性支气管炎，肺气肿病30年，今日中午在家抬重物，突然右侧胸部刺痛，逐渐加重，伴有气急，发绀。最可能发生的是", "options": {"A": "心肌梗死", "B": "胸腔积液", "C": "自发性气胸", "D": "胸栓塞", "E": "支气管栓塞"}, "answer": "C"}, {"id": 42, "chapter": "第1章_综合内科护理", "original_id": 42, "type": "single", "question": "脑出血最好发的部位在", "options": {"A": "脑桥", "B": "内囊", "C": "小脑", "D": "大脑皮质", "E": "中脑"}, "answer": "B"}, {"id": 43, "chapter": "第1章_综合内科护理", "original_id": 43, "type": "single", "question": "纠正缺氧和二氧化碳潴留最重要的措施是", "options": {"A": "氧气疗法", "B": "保持呼吸道通畅", "C": "开放气道", "D": "纠正酸碱平衡失调", "E": "提高呼吸系统兴奋性"}, "answer": "B"}, {"id": 44, "chapter": "第1章_综合内科护理", "original_id": 44, "type": "single", "question": "急性肺栓塞的溶栓时间窗（1分）", "options": {"A": "14天", "B": "6h", "C": "12h", "D": "14h"}, "answer": "A"}, {"id": 45, "chapter": "第1章_综合内科护理", "original_id": 45, "type": "single", "question": "老年患者突然发生寒战、高热、咳嗽、咳痰、痰粘稠，砖红色，胶脓状，引起感染最可能的病原菌是（1分）", "options": {"A": "肺炎克雷白杆菌", "B": "流感嗜血杆菌", "C": "嗜肺军团杆菌", "D": "葡萄球菌", "E": "铜绿假单胞菌"}, "answer": "A"}, {"id": 46, "chapter": "第1章_综合内科护理", "original_id": 46, "type": "single", "question": "患者女性，20岁。诊断为特发性癫痫，病史4年，表现为全身性强直一阵挛发作，每月发作3～4次。强直，阵挛发作的特征是（1分）", "options": {"A": "发作时意识清楚", "B": "自主神经症状明显", "C": "肢体有针刺和麻木感", "D": "突然、短暂、快速的肌肉收缩", "E": "全身对称性抽搐和意识丧失"}, "answer": "E"}, {"id": 47, "chapter": "第1章_综合内科护理", "original_id": 47, "type": "single", "question": "董某，男，32岁，教师。慢性周期性上腹痛1年余，头晕及活动后心悸气促1周。血常规:Hb72g/L。该病人贫血的严重程度为（）", "options": {"A": "轻度", "B": "中度", "C": "重度", "D": "极重度", "E": "轻至中度"}, "answer": "B"}, {"id": 48, "chapter": "第1章_综合内科护理", "original_id": 48, "type": "single", "question": "自然光线下，瞳孔直径小于多少毫米为缩小（1分）", "options": {"A": "4MM", "B": "3MM", "C": "2MM", "D": "1MM"}, "answer": "C"}, {"id": 49, "chapter": "第1章_综合内科护理", "original_id": 49, "type": "single", "question": "胃溃疡的疼痛特点是（）", "options": {"A": "疼痛-进食-疼痛", "B": "疼痛-进食-缓解", "C": "进食-疼痛-瘀痛", "D": "进食-疼痛-缓解", "E": "疼痛无规律"}, "answer": "D"}, {"id": 50, "chapter": "第1章_综合内科护理", "original_id": 50, "type": "single", "question": "肝性脑病灌肠时不能选用（）", "options": {"A": "清水", "B": "肥皂水", "C": "生理盐水", "D": "弱酸性溶液", "E": "新霉素液"}, "answer": "B"}, {"id": 51, "chapter": "第1章_综合内科护理", "original_id": 51, "type": "single", "question": "爆发痛药物解救剂量为前24H药物总量的？（1分）", "options": {"A": "5-10%", "B": "10-20%", "C": "20-30%", "D": "30-40%"}, "answer": "B"}, {"id": 52, "chapter": "第1章_综合内科护理", "original_id": 52, "type": "single", "question": "白血病的特异性体征为（）", "options": {"A": "头痛", "B": "关节痛", "C": "胸骨下段压痛", "D": "肢体瘫痪", "E": "皮肤瘀点"}, "answer": "C"}, {"id": 53, "chapter": "第1章_综合内科护理", "original_id": 53, "type": "single", "question": "女性乳腺癌的好发年龄是（1分）", "options": {"A": "20~30岁", "B": "30~40岁", "C": "40~49岁", "D": "50~55岁"}, "answer": "C"}, {"id": 54, "chapter": "第1章_综合内科护理", "original_id": 54, "type": "single", "question": "原发性肝癌最早、最常见的转移方式是（）", "options": {"A": "淋巴转移", "B": "肝内血行转移", "C": "肝外血行转移", "D": "消化道转移", "E": "种植转移"}, "answer": "B"}, {"id": 55, "chapter": "第1章_综合内科护理", "original_id": 55, "type": "single", "question": "如果病人膀胱过度膨胀，一次放尿量不超过", "options": {"A": "500ML", "B": "800ML", "C": "1000ML", "D": "1200ML"}, "answer": "C"}, {"id": 56, "chapter": "第1章_综合内科护理", "original_id": 56, "type": "single", "question": "最能反应昏迷病人病情的体征变化是", "options": {"A": "体温", "B": "脉搏", "C": "呼吸", "D": "瞳孔", "E": "神志"}, "answer": "D"}, {"id": 57, "chapter": "第1章_综合内科护理", "original_id": 57, "type": "single", "question": "短暂性脑缺血发作，持续时间为", "options": {"A": "不超过24H", "B": "不超过1H", "C": "不超过一周", "D": "不超过2日"}, "answer": "A"}, {"id": 58, "chapter": "第1章_综合内科护理", "original_id": 58, "type": "single", "question": "叶某，女，33岁。间歇性发热、纳差，伴腕膝关节酸痛1月余。抗Sm抗体(+)。你认为目前该病人可能患有的疾病是", "options": {"A": "风湿性关节炎", "B": "类风湿关节炎", "C": "系统性红斑狼疮", "D": "急性肾小球肾炎", "E": "病毒性肝炎"}, "answer": "C"}, {"id": 59, "chapter": "第1章_综合内科护理", "original_id": 59, "type": "single", "question": "胡某，男，45岁。身高175cm，体重60kg。因肺部感染诱发酮症酸中毒，急诊入院。该病人应每小时泵入胰岛素", "options": {"A": "4U", "B": "5U", "C": "6U", "D": "7U", "E": "8U"}, "answer": "C"}, {"id": 60, "chapter": "第1章_综合内科护理", "original_id": 60, "type": "single", "question": "急性心肌梗死时出现的室性心律失常，首选用药是", "options": {"A": "利多卡因", "B": "洋地黄", "C": "普罗帕酮", "D": "异搏定", "E": "美托洛尔"}, "answer": "A"}, {"id": 61, "chapter": "第1章_综合内科护理", "original_id": 61, "type": "single", "question": "当患者血压高于正常范围，心电监护报警上限设置范围？", "options": {"A": "5-10%", "B": "15-20%", "C": "10-15%", "D": "20-30%"}, "answer": "A"}, {"id": 62, "chapter": "第1章_综合内科护理", "original_id": 62, "type": "single", "question": "急进型肾炎的病理下述哪项不正确", "options": {"A": "肾小球囊腔内新月体形成", "B": "根据病理表现不同分为三型", "C": "II型为免疫复合物型", "D": "基本发病机制为免疫反应", "E": "III型为抗肾小球基膜型"}, "answer": "E"}, {"id": 63, "chapter": "第1章_综合内科护理", "original_id": 63, "type": "single", "question": "下列哪项不是轴线翻身的目的", "options": {"A": "协助脊椎损伤的患者在床上翻身", "B": "预防压疮", "C": "预防脊椎再损伤", "D": "协助颅骨牵引的患者在床上翻身", "E": "协助昏迷病人在床上翻身"}, "answer": "E"}, {"id": 64, "chapter": "第1章_综合内科护理", "original_id": 64, "type": "single", "question": "引起肺血栓栓塞症的血栓几乎不来自", "options": {"A": "下腔静脉径路", "B": "上腔静脉径路", "C": "左心腔", "D": "右心腔", "E": "下肢深静脉"}, "answer": "C"}, {"id": 65, "chapter": "第1章_综合内科护理", "original_id": 65, "type": "single", "question": "系统性红斑狼疮最常发生的脏器或组织损害是", "options": {"A": "肾", "B": "肌肉、关节", "C": "皮肤", "D": "心血管", "E": "肺和胸膜"}, "answer": "A"}, {"id": 66, "chapter": "第1章_综合内科护理", "original_id": 66, "type": "single", "question": "出现脑疝应立即", "options": {"A": "降体温", "B": "输氧", "C": "气管切开", "D": "快速静脉滴注脱水剂"}, "answer": "D"}, {"id": 67, "chapter": "第1章_综合内科护理", "original_id": 67, "type": "single", "question": "以下哪项不是有助于系统性红斑狼疮诊断的实验室辅助检查", "options": {"A": "血小板减少", "B": "抗核抗体阳性", "C": "抗dsDNA抗体阳性", "D": "γ球蛋白下降", "E": "补体C3下降"}, "answer": "D"}, {"id": 68, "chapter": "第1章_综合内科护理", "original_id": 68, "type": "single", "question": "PICC导管留置时间一般不超过多少个月", "options": {"A": "3", "B": "6", "C": "9", "D": "12", "E": "24"}, "answer": "D"}, {"id": 69, "chapter": "第1章_综合内科护理", "original_id": 69, "type": "single", "question": "扩张型心肌病患者的最主要的临床表现是", "options": {"A": "呼吸道感染", "B": "室性心律失常", "C": "心力衰竭", "D": "晕厥", "E": "房室传导阻滞"}, "answer": "C"}, {"id": 70, "chapter": "第1章_综合内科护理", "original_id": 70, "type": "single", "question": "低盐饮食每日烹调食盐的量", "options": {"A": "不超过2g", "B": "不超过1.5g", "C": "不少于2g", "D": "不超过3g"}, "answer": "A"}, {"id": 71, "chapter": "第1章_综合内科护理", "original_id": 71, "type": "multi", "question": "全胃肠外营养支持患者可能发生的代谢性并发症有", "options": {"A": "低血糖", "B": "空气栓塞", "C": "导管败血症", "D": "肝功能异常", "E": "高渗性非酮症性昏迷"}, "answer": "A、E"}, {"id": 72, "chapter": "第1章_综合内科护理", "original_id": 72, "type": "multi", "question": "NRS-2002营养风险筛查表中属于3分项的包括", "options": {"A": "头部损伤患者", "B": "骨髓移植患者", "C": "ICU患者", "D": "腹部大手术患者", "E": "恶性肿瘤患者"}, "answer": "A、B、C"}, {"id": 73, "chapter": "第1章_综合内科护理", "original_id": 73, "type": "multi", "question": "腹膜的生理作用包括", "options": {"A": "润滑作用", "B": "吸收作用", "C": "渗出作用", "D": "防御作用", "E": "营养作用"}, "answer": "A、B、C、D"}, {"id": 74, "chapter": "第1章_综合内科护理", "original_id": 74, "type": "multi", "question": "下面哪些是上腔静脉压迫综合征的表现", "options": {"A": "头面部浮肿", "B": "呼吸困难", "C": "颈静脉怒张", "D": "上肢浮肿", "E": "口唇发绀"}, "answer": "A、B、C、D、E"}, {"id": 75, "chapter": "第1章_综合内科护理", "original_id": 75, "type": "multi", "question": "向心性肥胖的特点是（）", "options": {"A": "黏液性水肿面容", "B": "满月脸", "C": "肢端肥大", "D": "水牛背", "E": "全身肥胖"}, "answer": "B、D"}, {"id": 76, "chapter": "第1章_综合内科护理", "original_id": 76, "type": "multi", "question": "病毒性脑膜炎的临床主要表现为（）", "options": {"A": "发热", "B": "头痛", "C": "脑膜刺激征", "D": "偏瘫", "E": "眼部损伤"}, "answer": "A、B、C"}, {"id": 77, "chapter": "第1章_综合内科护理", "original_id": 77, "type": "multi", "question": "心电图检查的注意事项（）", "options": {"A": "检查前不能饱饮、饱食、吃冷饮和抽烟，需要平静休息20min。", "B": "嘱受检者在检查时确保无手机、手表等电、磁、金属物品与患者接触。", "C": "胸导联在擦拭导电膏或酒精时要注意各导分开。", "D": "请勿将左右脚串连在一起只用3个肢夹。", "E": "如正在服用洋地黄、钾盐、钙类及抗心律失常药物，应告知医生。"}, "answer": "A、B、C、D、E"}, {"id": 78, "chapter": "第1章_综合内科护理", "original_id": 78, "type": "multi", "question": "脑卒中的危险因素包括（）", "options": {"A": "肥胖", "B": "颈动脉狭窄", "C": "高同型半胱氨酸血症", "D": "早期营养不良", "E": "长期被动吸烟"}, "answer": "A、B、C、E"}, {"id": 79, "chapter": "第1章_综合内科护理", "original_id": 79, "type": "multi", "question": "下列关于短暂性脑缺血发作的叙述，正确的是（）", "options": {"A": "症状持续数分钟至数小时", "B": "无CT或MRI显示的责任病灶", "C": "简称为TIA", "D": "不会反复发作", "E": "发作后不遗留神经功能缺损症状"}, "answer": "A、B、C、E"}, {"id": 80, "chapter": "第1章_综合内科护理", "original_id": 80, "type": "multi", "question": "消化道穿孔患者必须禁食和胃肠减压的目的包括（）", "options": {"A": "减少胃内容物流入腹腔", "B": "有利于纠正酸碱平衡", "C": "改善胃壁血液循环", "D": "维持有效循环血量", "E": "促进胃肠道恢复蠕动"}, "answer": "A、C、E"}, {"id": 81, "chapter": "第1章_综合内科护理", "original_id": 81, "type": "multi", "question": "何某，男，24岁。因双下肢水肿7天，眼睑水肿2天，伴泡沫尿就诊，诊断为肾病综合征。该病人可能发生的并发症是（）", "options": {"A": "急性肾损伤", "B": "血栓形成、栓塞", "C": "营养不良", "D": "感染", "E": "高血压脑病"}, "answer": "A、B、C、D"}, {"id": 82, "chapter": "第1章_综合内科护理", "original_id": 82, "type": "multi", "question": "使用简易呼吸囊常见的并发症有（）", "options": {"A": "急性胃扩张", "B": "窒息", "C": "气压伤", "D": "低氧血症", "E": "心律失常"}, "answer": "A、B、C、D"}, {"id": 83, "chapter": "第1章_综合内科护理", "original_id": 83, "type": "multi", "question": "以下属于肺癌非转移性的全身症状的是（）", "options": {"A": "骨关节病综合征", "B": "Cushing综合征", "C": "重症肌无力", "D": "男性乳腺增大", "E": "女性闭经"}, "answer": "A、B、C、D"}, {"id": 84, "chapter": "第1章_综合内科护理", "original_id": 84, "type": "multi", "question": "付女士,55岁,因刺激性干咳5个月,视物不清10天入院,胸部X线示右上肺不规则阴影,造成了Horner综合征,表现属于Horner综合征的是（）", "options": {"A": "同侧上眼睑下垂", "B": "声音嘶哑", "C": "眼球内陷", "D": "面部无汗", "E": "瞳孔缩小"}, "answer": "A、C、D、E"}, {"id": 85, "chapter": "第1章_综合内科护理", "original_id": 85, "type": "multi", "question": "电除颤技术常见的并发症有（）", "options": {"A": "皮肤灼伤", "B": "栓塞", "C": "心肌损伤", "D": "心律失常", "E": "肋骨骨折"}, "answer": "A、B、C、D"}, {"id": 86, "chapter": "第2-3章_呼吸循环", "original_id": 86, "type": "judge", "question": "呼吸系统解剖中，右主支气管较左主支气管粗、短且陡直，因此异物吸入更易进入右主支气管。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 87, "chapter": "第2-3章_呼吸循环", "original_id": 87, "type": "judge", "question": "慢性阻塞性肺疾病（COPD）患者进行家庭氧疗时，应采用高流量吸氧（6~8L/min），以迅速纠正低氧血症。", "options": {"A": "正确", "B": "错误"}, "answer": "B"}, {"id": 88, "chapter": "第2-3章_呼吸循环", "original_id": 88, "type": "judge", "question": "Ⅱ型呼吸衰竭患者给予氧疗时，应遵循低浓度（<35%）、持续吸氧的原则，以避免抑制呼吸中枢的化学感受器对CO₂的敏感性。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 89, "chapter": "第2-3章_呼吸循环", "original_id": 89, "type": "judge", "question": "咯血量每日在100~500ml为中等量咯血，每日超过500ml或一次咯血量超过300ml为大咯血。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 90, "chapter": "第2-3章_呼吸循环", "original_id": 90, "type": "judge", "question": "支气管哮喘急性发作时，若PaCO₂正常或升高，提示病情较轻，预后良好。", "options": {"A": "正确", "B": "错误"}, "answer": "B"}, {"id": 91, "chapter": "第2-3章_呼吸循环", "original_id": 91, "type": "judge", "question": "结核性胸膜炎患者的胸腔积液为渗出液，其腺苷脱氨酶（ADA）常明显升高。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 92, "chapter": "第2-3章_呼吸循环", "original_id": 92, "type": "judge", "question": "张力性气胸的急救处理首选胸腔闭式引流，引流瓶应高于患者胸腔平面以保证引流效果。", "options": {"A": "正确", "B": "错误"}, "answer": "B"}, {"id": 93, "chapter": "第2-3章_呼吸循环", "original_id": 93, "type": "judge", "question": "肺癌患者出现Horner综合征是由于肿瘤压迫或侵犯颈交感神经链所致，表现为患侧眼睑下垂、瞳孔缩小、眼球内陷、额部少汗。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 94, "chapter": "第2-3章_呼吸循环", "original_id": 94, "type": "judge", "question": "支气管镜检查术后，患者应禁食2小时，以免因咽喉部麻醉未消退而发生误吸。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 95, "chapter": "第2-3章_呼吸循环", "original_id": 95, "type": "judge", "question": "急性呼吸窘迫综合征（ARDS）的典型病理改变为肺毛细血管内皮细胞和肺泡上皮细胞损伤导致的弥漫性肺水肿和肺透明膜形成。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 96, "chapter": "第2-3章_呼吸循环", "original_id": 96, "type": "single", "question": "李某，男，68岁。有吸烟史40年，近5年来反复咳嗽、咳痰，每年持续3个月以上。近1周咳嗽加重，痰量增多，呈黄色脓性，伴气促。查体：桶状胸，双肺可闻及散在湿啰音及哮鸣音。肺功能检查：FEV₁/FVC为62%，FEV₁占预计值55%。该患者最可能的诊断是", "options": {"A": "支气管哮喘", "B": "慢性支气管炎急性发作期", "C": "慢性阻塞性肺疾病急性加重期", "D": "支气管扩张症", "E": "肺结核"}, "answer": "C"}, {"id": 97, "chapter": "第2-3章_呼吸循环", "original_id": 97, "type": "single", "question": "王某，女，45岁。因\"肺结核\"入院，医嘱给予异烟肼、利福平、吡嗪酰胺、乙胺丁醇联合化疗。护士在指导患者用药时，应重点告知可能出现的不良反应是", "options": {"A": "听力下降", "B": "周围神经炎和肝功能损害", "C": "心律失常", "D": "血糖升高", "E": "甲状腺功能减退"}, "answer": "B"}, {"id": 98, "chapter": "第2-3章_呼吸循环", "original_id": 98, "type": "single", "question": "陈某，男，52岁。因反复发作性喘息入院。查体：呼气相延长，双肺满布哮鸣音。血气分析：pH 7.48，PaO₂ 62mmHg，PaCO₂ 30mmHg。该患者的酸碱平衡紊乱类型为", "options": {"A": "代谢性酸中毒", "B": "呼吸性酸中毒", "C": "呼吸性碱中毒", "D": "代谢性碱中毒", "E": "混合型酸碱失衡"}, "answer": "C"}, {"id": 99, "chapter": "第2-3章_呼吸循环", "original_id": 99, "type": "single", "question": "赵某，女，60岁。诊断为肺源性心脏病。查体：口唇发绀，颈静脉怒张，肝颈静脉回流征阳性，双下肢凹陷性水肿。该患者出现右心衰竭的主要机制是", "options": {"A": "心肌收缩力原发性下降", "B": "肺动脉高压导致右心室后负荷增加", "C": "心脏瓣膜病变", "D": "冠状动脉供血不足", "E": "心包积液限制心脏舒张"}, "answer": "B"}, {"id": 100, "chapter": "第2-3章_呼吸循环", "original_id": 100, "type": "single", "question": "张某，男，72岁。因\"慢性阻塞性肺疾病、Ⅱ型呼吸衰竭\"入院。医嘱给予持续低流量吸氧。护士向患者解释低流量吸氧的原因是", "options": {"A": "高流量氧会引起氧中毒", "B": "高流量氧可抑制呼吸中枢，加重CO₂潴留", "C": "低流量氧吸收效率更高", "D": "高流量氧会导致肺不张", "E": "低流量氧可稀释痰液"}, "answer": "B"}, {"id": 101, "chapter": "第2-3章_呼吸循环", "original_id": 101, "type": "single", "question": "刘某，女，35岁。受凉后出现寒战、高热，体温39.6℃，咳嗽、咳铁锈色痰，伴右侧胸痛。查体：右肺呼吸音减低，可闻及支气管呼吸音。胸部X线示右肺下叶大片均匀致密影。该患者最可能的诊断是", "options": {"A": "支原体肺炎", "B": "克雷伯杆菌肺炎", "C": "肺炎链球菌肺炎", "D": "金黄色葡萄球菌肺炎", "E": "病毒性肺炎"}, "answer": "C"}, {"id": 102, "chapter": "第2-3章_呼吸循环", "original_id": 102, "type": "single", "question": "孙某，男，58岁。确诊小细胞肺癌。近日出现头痛、呕吐、视乳头水肿等症状。最可能发生的并发症是", "options": {"A": "肺部感染", "B": "脑转移", "C": "肝转移", "D": "骨转移", "E": "上腔静脉阻塞综合征"}, "answer": "B"}, {"id": 103, "chapter": "第2-3章_呼吸循环", "original_id": 103, "type": "single", "question": "周某，女，28岁。因系统性红斑狼疮长期服用糖皮质激素。近1周出现咳嗽、低热、盗汗、乏力。PPD试验强阳性。胸部X线示右上肺斑片状阴影伴空洞形成。该患者肺结核最可能的临床类型是", "options": {"A": "原发型肺结核", "B": "血行播散型肺结核", "C": "浸润型肺结核", "D": "慢性纤维空洞型肺结核", "E": "结核性胸膜炎"}, "answer": "C"}, {"id": 104, "chapter": "第2-3章_呼吸循环", "original_id": 104, "type": "single", "question": "吴某，男，65岁。长期卧床，突发胸痛、呼吸困难，伴咯血。查体：呼吸急促，口唇发绀，肺动脉瓣区第二心音亢进。D-二聚体明显升高。CT肺动脉造影示左肺动脉主干内充盈缺损。该患者最可能的诊断是", "options": {"A": "急性心肌梗死", "B": "自发性气胸", "C": "肺栓塞", "D": "急性心包炎", "E": "主动脉夹层"}, "answer": "C"}, {"id": 105, "chapter": "第2-3章_呼吸循环", "original_id": 105, "type": "single", "question": "郑某，男，45岁。因支气管扩张大咯血入院。突发咯血过程中咯血突然减少，表情紧张，双手乱抓，口唇发绀。护士首先应采取的急救措施是", "options": {"A": "立即吸氧", "B": "立即取头低脚高位，轻拍背部，协助排出积血", "C": "立即静脉注射止血药", "D": "立即行气管插管", "E": "立即通知医生"}, "answer": "B"}, {"id": 106, "chapter": "第2-3章_呼吸循环", "original_id": 106, "type": "single", "question": "患者男性，38岁。突发左侧胸痛，呈刀割样，伴呼吸困难。查体：左侧胸廓饱满，呼吸运动减弱，叩诊呈鼓音，呼吸音消失。胸部X线示左肺压缩约70%。该患者最可能的诊断是", "options": {"A": "急性胸膜炎", "B": "胸腔积液", "C": "自发性气胸", "D": "肺不张", "E": "肺栓塞"}, "answer": "C"}, {"id": 107, "chapter": "第2-3章_呼吸循环", "original_id": 107, "type": "single", "question": "何某，女，55岁。因\"支气管哮喘\"入院，目前处于哮喘持续状态，经支气管舒张剂和全身糖皮质激素治疗后效果不佳。血气分析示PaO₂ 50mmHg，PaCO₂ 52mmHg。护士评估该患者目前哮喘的严重程度分级为", "options": {"A": "轻度", "B": "中度", "C": "重度", "D": "危重", "E": "间歇发作"}, "answer": "D"}, {"id": 108, "chapter": "第2-3章_呼吸循环", "original_id": 108, "type": "single", "question": "冯某，男，62岁。COPD病史15年。护士指导患者进行缩唇呼吸训练时，正确的指导是", "options": {"A": "用鼻呼气，经口吸气", "B": "吸气与呼气时间比为1:2或1:3", "C": "缩唇程度以能吹灭面前30cm处蜡烛火焰为宜", "D": "吸气时腹部内收", "E": "每日练习2次即可"}, "answer": "B"}, {"id": 109, "chapter": "第2-3章_呼吸循环", "original_id": 109, "type": "single", "question": "蒋某，女，50岁。反复咳嗽、咳大量脓痰20年，痰液静置后分三层。近日咯血约100ml。查体：左下肺可闻及固定性湿啰音。胸部CT示左下肺支气管呈囊状扩张。该患者咯血的分级属于", "options": {"A": "痰中带血", "B": "小量咯血", "C": "中等量咯血", "D": "大量咯血", "E": "窒息先兆"}, "answer": "B"}, {"id": 110, "chapter": "第2-3章_呼吸循环", "original_id": 110, "type": "single", "question": "杨某，男，70岁。因\"Ⅰ型呼吸衰竭\"入院。血气分析：PaO₂ 50mmHg，PaCO₂ 35mmHg。护士为该患者氧疗时应选择的吸氧浓度为", "options": {"A": "FiO₂ 24%~28%", "B": "FiO₂ 28%~35%", "C": "FiO₂ 35%~50%", "D": "FiO₂ >50%", "E": "纯氧吸入"}, "answer": "C"}, {"id": 111, "chapter": "第2-3章_呼吸循环", "original_id": 111, "type": "single", "question": "田某，女，48岁。因胸腔积液化验入院。胸腔穿刺抽取胸腔液进行检查。护士配合胸腔穿刺术时，下列操作正确的是", "options": {"A": "穿刺点选在肩胛线第7~8肋间", "B": "穿刺点选在锁骨中线第2肋间", "C": "穿刺针沿下一肋骨上缘进针", "D": "穿刺针沿下一肋骨下缘进针", "E": "每次抽液量不超过1500ml"}, "answer": "C"}, {"id": 112, "chapter": "第2-3章_呼吸循环", "original_id": 112, "type": "single", "question": "许某，男，56岁。肺癌根治术后第2天，行胸腔闭式引流。护士巡视时发现引流管水柱波动消失，引流液减少，患者气促加重。最可能的原因是", "options": {"A": "引流管脱出", "B": "引流管堵塞", "C": "肺已完全复张", "D": "胸腔内活动性出血", "E": "引流瓶位置过高"}, "answer": "B"}, {"id": 113, "chapter": "第2-3章_呼吸循环", "original_id": 113, "type": "single", "question": "高某，女，42岁。确诊肺结核，痰涂片抗酸杆菌阳性。关于该患者的隔离措施，下列正确的是", "options": {"A": "接触隔离", "B": "消化道隔离", "C": "呼吸道隔离", "D": "严密隔离", "E": "保护性隔离"}, "answer": "C"}, {"id": 114, "chapter": "第2-3章_呼吸循环", "original_id": 114, "type": "single", "question": "患者男性，65岁。机械通气治疗中。护士发现呼吸机高压报警，最可能的原因是", "options": {"A": "气管导管脱出", "B": "气路管道脱落", "C": "气道分泌物过多导致气道阻塞", "D": "气源压力不足", "E": "患者自主呼吸增强"}, "answer": "C"}, {"id": 115, "chapter": "第2-3章_呼吸循环", "original_id": 115, "type": "single", "question": "马某，男，48岁。因ARDS行机械通气治疗。目前采用肺保护性通气策略，潮气量设置为6ml/kg。该策略的主要目的是", "options": {"A": "增加心输出量", "B": "避免肺泡过度膨胀和反复开闭造成的肺损伤", "C": "降低气道峰压", "D": "促进CO₂排出", "E": "改善患者舒适度"}, "answer": "B"}, {"id": 116, "chapter": "第2-3章_呼吸循环", "original_id": 116, "type": "single", "question": "邓某，女，30岁。春游后出现喘息、咳嗽、胸闷。查体：呼吸28次/分，双肺满布哮鸣音，心率110次/分。既往有类似发作史，可自行缓解。该患者最可能的诱因是", "options": {"A": "呼吸道感染", "B": "吸入花粉等变应原", "C": "剧烈运动", "D": "药物过敏", "E": "精神紧张"}, "answer": "B"}, {"id": 117, "chapter": "第2-3章_呼吸循环", "original_id": 117, "type": "single", "question": "罗某，男，55岁。诊断为肺脓肿，痰量约600ml/日，有恶臭。该患者痰液静置后的典型特征是", "options": {"A": "痰液为铁锈色", "B": "痰液为粉红色泡沫样", "C": "痰液静置后分为四层", "D": "痰液静置后分为三层，上层为泡沫，中层为浑浊黏液，下层为脓性物和坏死组织", "E": "痰液为果酱样"}, "answer": "D"}, {"id": 118, "chapter": "第2-3章_呼吸循环", "original_id": 118, "type": "single", "question": "谢某，女，70岁。COPD病史20年。近3天因受凉后出现咳喘加重、痰多不易咳出、嗜睡。查体：口唇明显发绀，球结膜水肿。血气分析：pH 7.28，PaO₂ 42mmHg，PaCO₂ 85mmHg。该患者最可能出现的并发症是", "options": {"A": "肺性脑病", "B": "急性呼吸窘迫综合征", "C": "自发性气胸", "D": "肺栓塞", "E": "心力衰竭"}, "answer": "A"}, {"id": 119, "chapter": "第2-3章_呼吸循环", "original_id": 119, "type": "single", "question": "曹某，男，40岁。支气管镜检查术后2小时，护士评估患者时，首要观察的内容是", "options": {"A": "体温变化", "B": "有无咯血、呼吸困难等并发症", "C": "痰液颜色", "D": "肺部啰音变化", "E": "心率变化"}, "answer": "B"}, {"id": 120, "chapter": "第2-3章_呼吸循环", "original_id": 120, "type": "single", "question": "宋某，女，55岁。因肺癌行化疗期间出现口腔溃疡，口腔分泌物涂片发现白色念珠菌。护士为其进行口腔护理时，应选用的漱口液是", "options": {"A": "0.9%氯化钠溶液", "B": "0.1%醋酸溶液", "C": "1%~4%碳酸氢钠溶液", "D": "3%过氧化氢溶液", "E": "0.08%甲硝唑溶液"}, "answer": "C"}, {"id": 121, "chapter": "第2-3章_呼吸循环", "original_id": 121, "type": "single", "question": "蔡某，男，48岁。因\"肺结核\"行HRZE方案化疗2个月，近日出现视力模糊、视力下降。最可能与此相关的药物是", "options": {"A": "异烟肼", "B": "利福平", "C": "吡嗪酰胺", "D": "乙胺丁醇", "E": "链霉素"}, "answer": "D"}, {"id": 122, "chapter": "第2-3章_呼吸循环", "original_id": 122, "type": "single", "question": "患者女性，60岁。慢性肺心病病史8年。近1周因肺部感染后出现呼吸困难加重、下肢水肿。查体：颈静脉怒张，肝肋下3cm，双下肢水肿。该患者目前首要的护理诊断是", "options": {"A": "气体交换受损", "B": "体液过多", "C": "活动无耐力", "D": "焦虑", "E": "营养失调"}, "answer": "A"}, {"id": 123, "chapter": "第2-3章_呼吸循环", "original_id": 123, "type": "single", "question": "梁某，男，52岁。确诊为中央型肺癌，近日出现面部、颈部及上肢水肿，胸壁静脉曲张。该表现提示肿瘤压迫了", "options": {"A": "喉返神经", "B": "上腔静脉", "C": "膈神经", "D": "交感神经链", "E": "气管"}, "answer": "B"}, {"id": 124, "chapter": "第2-3章_呼吸循环", "original_id": 124, "type": "single", "question": "韩某，女，38岁。因胸腔穿刺抽液过程中出现头晕、面色苍白、出冷汗、心悸。护士判断该患者发生了胸膜反应，应立即采取的措施是", "options": {"A": "加快抽液速度", "B": "减慢抽液速度，继续观察", "C": "立即停止抽液，让患者平卧，必要时皮下注射肾上腺素", "D": "给予高流量吸氧", "E": "静脉注射地塞米松"}, "answer": "C"}, {"id": 125, "chapter": "第2-3章_呼吸循环", "original_id": 125, "type": "single", "question": "于某，男，66岁。COPD急性加重期，血气分析示pH 7.32，PaO₂ 48mmHg，PaCO₂ 72mmHg。护士判断该患者属于", "options": {"A": "Ⅰ型呼吸衰竭", "B": "Ⅱ型呼吸衰竭", "C": "代谢性酸中毒", "D": "代谢性碱中毒", "E": "急性呼吸窘迫综合征"}, "answer": "B"}, {"id": 126, "chapter": "第2-3章_呼吸循环", "original_id": 126, "type": "multi", "question": "关于慢性阻塞性肺疾病（COPD）患者的呼吸功能锻炼，下列正确的有", "options": {"A": "缩唇呼吸可延长呼气时间，防止小气道过早塌陷", "B": "腹式呼吸时吸气时腹部鼓起，呼气时腹部内收", "C": "吸气与呼气时间比应为2:1", "D": "训练应循序渐进，避免过度疲劳", "E": "可配合上肢运动进行综合训练"}, "answer": "A、B、D、E"}, {"id": 127, "chapter": "第2-3章_呼吸循环", "original_id": 127, "type": "multi", "question": "支气管哮喘患者使用糖皮质激素的注意事项包括", "options": {"A": "吸入型糖皮质激素使用后应漱口", "B": "全身用药时应注意逐渐减量，不可突然停药", "C": "长期全身使用可出现骨质疏松、血糖升高等不良反应", "D": "吸入型激素是哮喘长期治疗的首选抗炎药物", "E": "口服激素起效比静脉用药更快"}, "answer": "A、B、C、D"}, {"id": 128, "chapter": "第2-3章_呼吸循环", "original_id": 128, "type": "multi", "question": "患者男性，58岁。COPD病史10年，近日病情加重入院。护士为其制定护理计划，下列措施正确的有", "options": {"A": "给予持续低流量吸氧（1~2L/min）", "B": "鼓励患者多饮水以稀释痰液", "C": "指导患者有效咳嗽排痰", "D": "给予高浓度氧疗以迅速改善缺氧", "E": "提供高蛋白、高维生素、易消化饮食"}, "answer": "A、B、C、E"}, {"id": 129, "chapter": "第2-3章_呼吸循环", "original_id": 129, "type": "multi", "question": "方某，女，50岁。确诊肺结核，痰结核菌检查阳性。关于该患者的护理措施，下列正确的有", "options": {"A": "执行呼吸道隔离", "B": "痰液应焚烧处理或经消毒后倒掉", "C": "餐具煮沸消毒", "D": "病室每日紫外线消毒", "E": "嘱患者将痰吐在纸巾上焚烧处理"}, "answer": "A、B、D、E"}, {"id": 130, "chapter": "第2-3章_呼吸循环", "original_id": 130, "type": "multi", "question": "方某，男，45岁。支气管扩张病史15年，今日突发大咯血，一次咯血量约400ml，伴心慌、面色苍白。护士在制定护理计划时，下列措施正确的有", "options": {"A": "取患侧卧位或平卧位头偏向一侧", "B": "密切观察生命体征和咯血量", "C": "嘱患者屏气以减少出血", "D": "备好急救物品，如吸引器、气管插管用物", "E": "保持大便通畅，避免用力排便"}, "answer": "A、B、D、E"}, {"id": 131, "chapter": "第2-3章_呼吸循环", "original_id": 131, "type": "multi", "question": "胸腔闭式引流患者，提示引流管通畅的表现有", "options": {"A": "水封瓶内液面随呼吸上下波动", "B": "引流管内有液体流出", "C": "水柱波动范围为4~6cm", "D": "患者呼吸困难症状减轻", "E": "水封瓶内无气泡冒出即说明肺已完全复张"}, "answer": "A、B、C、D"}, {"id": 132, "chapter": "第2-3章_呼吸循环", "original_id": 132, "type": "multi", "question": "关于支气管哮喘缓解期患者的健康教育，下列正确的有", "options": {"A": "避免接触已知过敏原", "B": "遵医嘱规律使用吸入型糖皮质激素", "C": "学会正确使用峰流速仪监测肺功能", "D": "症状缓解后可自行停用控制药物", "E": "进行适度体育锻炼，增强机体抵抗力"}, "answer": "A、B、C、E"}, {"id": 133, "chapter": "第2-3章_呼吸循环", "original_id": 133, "type": "multi", "question": "肺炎链球菌肺炎患者的典型临床表现包括", "options": {"A": "起病急骤，寒战高热", "B": "咳铁锈色痰", "C": "胸痛", "D": "肺部可闻及湿啰音", "E": "胸部X线示肺叶或肺段实变影"}, "answer": "A、B、C、D、E"}, {"id": 134, "chapter": "第2-3章_呼吸循环", "original_id": 134, "type": "multi", "question": "韩某，男，72岁。COPD急性加重、Ⅱ型呼吸衰竭，行气管插管机械通气治疗第5天。护士为预防呼吸机相关性肺炎（VAP），下列措施正确的有", "options": {"A": "床头抬高30°~45°", "B": "每日进行口腔护理", "C": "及时清除呼吸机管路中的冷凝水", "D": "气囊压力维持在25~30cmH₂O", "E": "每日更换呼吸机管路"}, "answer": "A、B、C、D"}, {"id": 135, "chapter": "第2-3章_呼吸循环", "original_id": 135, "type": "multi", "question": "下列属于肺癌肺外表现（副癌综合征）的有", "options": {"A": "肥大性骨关节病", "B": "异位ACTH综合征", "C": "Horner综合征", "D": "低钠血症（抗利尿激素分泌异常综合征）", "E": "重症肌无力样综合征（Lambert-Eaton综合征）"}, "answer": "A、B、D、E"}, {"id": 136, "chapter": "第2-3章_呼吸循环", "original_id": 136, "type": "multi", "question": "沈某，男，32岁。确诊肺结核，痰涂片抗酸杆菌阳性，医嘱给予2HRZE/4HR方案化疗。护士在指导患者化疗时应遵循的原则包括", "options": {"A": "早期治疗", "B": "联合用药", "C": "适量用药", "D": "规律用药", "E": "全程治疗"}, "answer": "A、B、C、D、E"}, {"id": 137, "chapter": "第2-3章_呼吸循环", "original_id": 137, "type": "multi", "question": "患者男性，70岁。支气管扩张病史30年，近期反复咯血。护士应指导该患者注意的事项包括", "options": {"A": "保持情绪稳定，避免紧张焦虑", "B": "进食温凉清淡的流质或半流质饮食", "C": "咯血时屏气以减少出血", "D": "保持大便通畅", "E": "大咯血时暂禁食"}, "answer": "A、B、D、E"}, {"id": 138, "chapter": "第2-3章_呼吸循环", "original_id": 138, "type": "multi", "question": "关于自发性气胸患者的护理措施，下列正确的有", "options": {"A": "卧床休息，避免用力", "B": "少量气胸（肺压缩<20%）可保守治疗，自行吸收", "C": "大量气胸需行胸腔穿刺抽气或胸腔闭式引流", "D": "引流瓶应低于胸腔60~100cm", "E": "拔管后嘱患者深呼吸"}, "answer": "A、B、C、D"}, {"id": 139, "chapter": "第2-3章_呼吸循环", "original_id": 139, "type": "multi", "question": "关于Ⅱ型呼吸衰竭的氧疗护理，下列正确的有", "options": {"A": "给予持续低流量吸氧（1~2L/min）", "B": "吸氧浓度不超过35%", "C": "因患者缺氧严重，可给予高浓度氧疗", "D": "氧疗期间监测血气分析变化", "E": "低流量吸氧可避免抑制呼吸中枢化学感受器"}, "answer": "A、B、D、E"}, {"id": 140, "chapter": "第2-3章_呼吸循环", "original_id": 140, "type": "multi", "question": "护士对肺栓塞患者进行健康指导时，应告知预防措施包括", "options": {"A": "长期卧床者应定时翻身、活动下肢", "B": "下肢深静脉血栓患者应进行抗凝治疗", "C": "大手术后应早期下床活动", "D": "口服避孕药的女性无需关注血栓风险", "E": "高危人群可穿弹力袜促进静脉回流"}, "answer": "A、B、C、E"}, {"id": 141, "chapter": "第2-3章_呼吸循环", "original_id": 141, "type": "multi", "question": "陆某，女，50岁。因重症肺炎入院，次日出现进行性呼吸困难，呼吸频率36次/分，口唇发绀。血气分析（吸氧浓度50%）：PaO₂ 50mmHg，PaCO₂ 30mmHg。胸部X线示双肺弥漫性渗出影。医生诊断为ARDS。该患者的临床特点包括", "options": {"A": "急性起病，进行性呼吸困难", "B": "常规氧疗难以纠正的低氧血症", "C": "胸部X线示双肺弥漫性浸润影", "D": "肺毛细血管楔压（PCWP）>18mmHg", "E": "PaO₂/FiO₂≤300mmHg"}, "answer": "A、B、C、E"}, {"id": 142, "chapter": "第2-3章_呼吸循环", "original_id": 142, "type": "multi", "question": "支气管镜检查术后的护理观察要点包括", "options": {"A": "观察有无咯血", "B": "观察有无呼吸困难加重", "C": "术后2小时内禁食禁饮", "D": "监测体温变化，警惕感染", "E": "术后即可正常进食饮水"}, "answer": "A、B、C、D"}, {"id": 143, "chapter": "第2-3章_呼吸循环", "original_id": 143, "type": "multi", "question": "关于胸腔穿刺术的护理配合，下列正确的有", "options": {"A": "穿刺前排空膀胱，避免穿刺时损伤", "B": "协助患者取坐位或半坐卧位", "C": "首次抽液量不超过700ml", "D": "穿刺过程中密切观察患者有无头晕、面色苍白等胸膜反应", "E": "抽液后嘱患者健侧卧位休息"}, "answer": "A、B、C、D"}, {"id": 144, "chapter": "第2-3章_呼吸循环", "original_id": 144, "type": "multi", "question": "COPD患者营养支持的原则包括", "options": {"A": "高热量摄入，以满足呼吸做功增加的能量消耗", "B": "适量蛋白质补充", "C": "适当增加脂肪比例，减少碳水化合物比例", "D": "少食多餐，避免过饱影响呼吸", "E": "限制液体摄入以减少心脏负担"}, "answer": "A、B、C、D"}, {"id": 145, "chapter": "第2-3章_呼吸循环", "original_id": 145, "type": "multi", "question": "患者男性，45岁。因支气管哮喘急性发作入院，护士在评估时应重点关注的有", "options": {"A": "呼吸频率、节律和深度", "B": "哮喘发作的诱因", "C": "既往发作史和用药情况", "D": "肺部哮鸣音的范围和强度", "E": "血气分析结果"}, "answer": "A、B、C、D、E"}, {"id": 146, "chapter": "第2-3章_呼吸循环", "original_id": 146, "type": "judge", "question": "心力衰竭患者使用洋地黄类药物时，若脉搏低于60次/分应暂停给药并报告医生。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 147, "chapter": "第2-3章_呼吸循环", "original_id": 147, "type": "judge", "question": "心脏骤停后4~6分钟是脑细胞发生不可逆损害的时间窗，因此心肺复苏应争分夺秒进行。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 148, "chapter": "第2-3章_呼吸循环", "original_id": 148, "type": "judge", "question": "急性心肌梗死患者发病后24小时内绝对卧床休息，以降低心肌耗氧量。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 149, "chapter": "第2-3章_呼吸循环", "original_id": 149, "type": "judge", "question": "二尖瓣狭窄最典型的体征是在心尖部可闻及收缩期吹风样杂音。", "options": {"A": "正确", "B": "错误"}, "answer": "B"}, {"id": 150, "chapter": "第2-3章_呼吸循环", "original_id": 150, "type": "judge", "question": "心房颤动患者的心电图特征包括P波消失，代之以大小不等、形态各异的f波，心室律绝对不规则。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 151, "chapter": "第2-3章_呼吸循环", "original_id": 151, "type": "judge", "question": "高血压患者血压控制目标为一般患者<140/90mmHg，合并糖尿病或肾病患者<130/80mmHg。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 152, "chapter": "第2-3章_呼吸循环", "original_id": 152, "type": "judge", "question": "植入永久心脏起搏器术后患者应避免术侧肢体过度活动，且应远离高压电场和强磁场。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 153, "chapter": "第2-3章_呼吸循环", "original_id": 153, "type": "judge", "question": "急性心肌梗死心电图定位中，V₁~V₃导联ST段抬高提示为前壁心肌梗死。", "options": {"A": "正确", "B": "错误"}, "answer": "B"}, {"id": 154, "chapter": "第2-3章_呼吸循环", "original_id": 154, "type": "judge", "question": "感染性心内膜炎最常见的致病微生物是草绿色链球菌，抗生素治疗原则为早期、足量、长疗程的静脉给药。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 155, "chapter": "第2-3章_呼吸循环", "original_id": 155, "type": "judge", "question": "心包积液患者出现心脏压塞时的典型表现为Beck三联征：静脉压升高（颈静脉怒张）、心音遥远、动脉血压下降。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 156, "chapter": "第2-3章_呼吸循环", "original_id": 156, "type": "single", "question": "张某，男，65岁。有高血压病史20年。近半年来劳累后出现心悸、气短，休息后可缓解。近1周夜间不能平卧，需端坐呼吸，伴双下肢水肿。查体：血压150/95mmHg，心率110次/分，双肺底可闻及湿啰音，心界向左扩大。该患者心功能按NYHA分级属于", "options": {"A": "Ⅰ级", "B": "Ⅱ级", "C": "Ⅲ级", "D": "Ⅳ级", "E": "0级"}, "answer": "C"}, {"id": 157, "chapter": "第2-3章_呼吸循环", "original_id": 157, "type": "single", "question": "王某，女，58岁。风心病二尖瓣狭窄病史15年。心电图示P波消失，代之以大小不等、形态各异的f波，心室率110次/分，R-R间距绝对不等。该患者的心电图诊断为", "options": {"A": "心房扑动", "B": "心房颤动", "C": "室性心动过速", "D": "窦性心律不齐", "E": "房室传导阻滞"}, "answer": "B"}, {"id": 158, "chapter": "第2-3章_呼吸循环", "original_id": 158, "type": "single", "question": "李某，男，55岁。突发胸骨后压榨性疼痛2小时，伴大汗、恶心。心电图示V₁~V₃导联ST段弓背向上抬高0.4mV，可见病理性Q波。该患者心肌梗死的定位诊断是", "options": {"A": "前间壁心肌梗死", "B": "广泛前壁心肌梗死", "C": "下壁心肌梗死", "D": "侧壁心肌梗死", "E": "后壁心肌梗死"}, "answer": "A"}, {"id": 159, "chapter": "第2-3章_呼吸循环", "original_id": 159, "type": "single", "question": "陈某，女，70岁。高血压病史30年，血压最高达200/110mmHg。突然出现剧烈头痛、呕吐、意识模糊。查体：血压210/120mmHg。该患者最可能的诊断是", "options": {"A": "高血压1级", "B": "高血压2级", "C": "高血压3级", "D": "高血压脑病", "E": "高血压危象"}, "answer": "D"}, {"id": 160, "chapter": "第2-3章_呼吸循环", "original_id": 160, "type": "single", "question": "赵某，男，50岁。突发意识丧失，大动脉搏动消失，呼吸停止。护士立即行胸外心脏按压，正确的按压部位和频率是", "options": {"A": "胸骨中上1/3交界处，80~100次/分", "B": "胸骨中下1/3交界处，100~120次/分", "C": "心前区，80~100次/分", "D": "胸骨中下1/3交界处，60~80次/分", "E": "剑突上方，120~140次/分"}, "answer": "B"}, {"id": 161, "chapter": "第2-3章_呼吸循环", "original_id": 161, "type": "single", "question": "孙某，男，60岁。急性广泛前壁心肌梗死入院第2天，突发心悸、气促。心电图示室性心动过速，心率180次/分，血压70/40mmHg。护士应首先配合医生采取的措施是", "options": {"A": "静脉注射胺碘酮", "B": "静脉注射利多卡因", "C": "同步直流电复律", "D": "静脉注射普罗帕酮", "E": "观察等待"}, "answer": "C"}, {"id": 162, "chapter": "第2-3章_呼吸循环", "original_id": 162, "type": "single", "question": "周某，女，45岁。因\"扩张型心肌病\"入院。查体：心界向两侧扩大，心率90次/分，可闻及第三心音奔马律。超声心动图示左心室明显扩大，室壁运动普遍减弱，射血分数30%。该患者目前最主要的治疗原则是", "options": {"A": "抗凝治疗", "B": "改善心功能，控制心力衰竭", "C": "心脏移植", "D": "抗心律失常", "E": "抗感染治疗"}, "answer": "B"}, {"id": 163, "chapter": "第2-3章_呼吸循环", "original_id": 163, "type": "single", "question": "吴某，男，52岁。急性下壁心肌梗死入院。心电图示Ⅱ、Ⅲ、aVF导联ST段弓背向上抬高。该患者最可能出现的并发症是", "options": {"A": "室壁瘤", "B": "房室传导阻滞", "C": "肺栓塞", "D": "二尖瓣关闭不全", "E": "心包炎"}, "answer": "B"}, {"id": 164, "chapter": "第2-3章_呼吸循环", "original_id": 164, "type": "single", "question": "郑某，男，58岁。冠心病行PCI术后返回病房。护士观察穿刺部位时，发现股动脉穿刺处肿胀、渗血，足背动脉搏动减弱。此时首要的护理措施是", "options": {"A": "加压包扎穿刺部位", "B": "立即通知医生", "C": "抬高患肢", "D": "热敷穿刺部位", "E": "继续观察"}, "answer": "A"}, {"id": 165, "chapter": "第2-3章_呼吸循环", "original_id": 165, "type": "single", "question": "患者女性，40岁。反复发热3个月，体温38~39℃，伴乏力、纳差。既往有风湿性心脏病二尖瓣关闭不全病史。查体：皮肤可见Osler结，心脏听诊可闻及杂音性质改变。血培养阳性。最可能的诊断是", "options": {"A": "风湿热复发", "B": "感染性心内膜炎", "C": "心肌炎", "D": "肺结核", "E": "败血症"}, "answer": "B"}, {"id": 166, "chapter": "第2-3章_呼吸循环", "original_id": 166, "type": "single", "question": "刘某，男，62岁。心包大量积液。查体：端坐位，颈静脉怒张，心音低钝遥远，血压80/60mmHg，奇脉。该患者出现了心脏压塞征象。护士应立即协助医生进行的处理是", "options": {"A": "静脉注射呋塞米", "B": "心包穿刺引流", "C": "静脉滴注多巴胺", "D": "吸氧观察", "E": "静脉注射毛花苷C"}, "answer": "B"}, {"id": 167, "chapter": "第2-3章_呼吸循环", "original_id": 167, "type": "single", "question": "杨某，女，68岁。心力衰竭长期服用地高辛0.25mg/日。近日出现恶心、呕吐、视物模糊，心率48次/分，心电图示室性期前收缩二联律。护士判断该患者最可能发生了", "options": {"A": "心力衰竭加重", "B": "洋地黄中毒", "C": "低钾血症", "D": "急性心肌梗死", "E": "肺部感染"}, "answer": "B"}, {"id": 168, "chapter": "第2-3章_呼吸循环", "original_id": 168, "type": "single", "question": "何某，男，48岁。因心绞痛入院。护士在为其进行健康指导时，告知硝酸甘油舌下含服的正确方法是", "options": {"A": "咀嚼后咽下", "B": "舌下含服，1~2分钟起效，5分钟后不缓解可再含服1片", "C": "用温水送服", "D": "含于颊黏膜处", "E": "嚼碎后舌下含服"}, "answer": "B"}, {"id": 169, "chapter": "第2-3章_呼吸循环", "original_id": 169, "type": "single", "question": "冯某，女，55岁。急性心肌梗死行溶栓治疗后，护士判断血管再通的指标不包括", "options": {"A": "胸痛迅速缓解", "B": "心电图抬高的ST段于2小时内回降>50%", "C": "出现再灌注性心律失常", "D": "心肌酶峰值提前出现", "E": "血压明显升高"}, "answer": "E"}, {"id": 170, "chapter": "第2-3章_呼吸循环", "original_id": 170, "type": "single", "question": "患者男性，65岁。因\"心房颤动\"入院。医嘱给予华法林抗凝治疗。护士在监测抗凝效果时，应关注的指标是", "options": {"A": "血小板计数", "B": "活化部分凝血活酶时间（APTT）", "C": "凝血酶原时间（PT）和国际标准化比值（INR）", "D": "纤维蛋白原", "E": "D-二聚体"}, "answer": "C"}, {"id": 171, "chapter": "第2-3章_呼吸循环", "original_id": 171, "type": "single", "question": "蒋某，男，60岁。高血压病史15年，一直服用氨氯地平。近日测血压180/110mmHg。按高血压分级标准，该患者属于", "options": {"A": "正常高值", "B": "高血压1级", "C": "高血压2级", "D": "高血压3级", "E": "单纯收缩期高血压"}, "answer": "D"}, {"id": 172, "chapter": "第2-3章_呼吸循环", "original_id": 172, "type": "single", "question": "田某，女，50岁。植入永久心脏起搏器术后第1天。护士指导患者活动时，应告知", "options": {"A": "术侧上肢可自由活动", "B": "术后24小时内术侧肢体应制动", "C": "可高举术侧上肢取物", "D": "术后即可进行剧烈运动", "E": "无需限制活动"}, "answer": "B"}, {"id": 173, "chapter": "第2-3章_呼吸循环", "original_id": 173, "type": "single", "question": "许某，男，56岁。心绞痛发作时含服硝酸甘油后头痛，护士应告知患者", "options": {"A": "立即停药", "B": "此为药物常见不良反应，可逐渐耐受", "C": "减量服用", "D": "更换为口服硝酸酯类", "E": "给予镇痛药"}, "answer": "B"}, {"id": 174, "chapter": "第2-3章_呼吸循环", "original_id": 174, "type": "single", "question": "高某，女，65岁。风心病主动脉瓣关闭不全病史10年。查体：胸骨左缘第3、4肋间可闻及舒张期叹气样杂音。该杂音向哪个方向传导", "options": {"A": "向颈部传导", "B": "向心尖部传导", "C": "向右肩部传导", "D": "向背部传导", "E": "不传导"}, "answer": "B"}, {"id": 175, "chapter": "第2-3章_呼吸循环", "original_id": 175, "type": "single", "question": "马某，男，45岁。行同步直流电复律术治疗心房颤动。术前护士应做的准备不包括", "options": {"A": "遵医嘱停用洋地黄类药物", "B": "术前禁食6小时", "C": "建立静脉通路", "D": "备好急救物品", "E": "术前行心脏超声检查"}, "answer": "B"}, {"id": 176, "chapter": "第2-3章_呼吸循环", "original_id": 176, "type": "single", "question": "邓某，女，72岁。慢性心力衰竭病史5年。近日因感冒后出现呼吸困难加重，不能平卧，咳粉红色泡沫痰。查体：端坐位，双肺满布湿啰音和哮鸣音，心率130次/分。该患者发生了", "options": {"A": "右心衰竭加重", "B": "急性左心衰竭", "C": "急性右心衰竭", "D": "全心衰竭", "E": "支气管哮喘发作"}, "answer": "B"}, {"id": 177, "chapter": "第2-3章_呼吸循环", "original_id": 177, "type": "single", "question": "蔡某，男，55岁。冠心病心绞痛患者。护士在为其进行饮食指导时，应告知每日胆固醇摄入量应控制在", "options": {"A": "<100mg", "B": "<200mg", "C": "<300mg", "D": "<400mg", "E": "<500mg"}, "answer": "C"}, {"id": 178, "chapter": "第2-3章_呼吸循环", "original_id": 178, "type": "single", "question": "宋某，女，48岁。肥厚型梗阻性心肌病患者。查体：胸骨左缘第3~4肋间可闻及粗糙的喷射性收缩期杂音。护士配合医生行Valsalva动作检查时，该杂音的变化是", "options": {"A": "减弱", "B": "增强", "C": "不变", "D": "先增强后减弱", "E": "消失"}, "answer": "B"}, {"id": 179, "chapter": "第2-3章_呼吸循环", "original_id": 179, "type": "single", "question": "患者男性，60岁。急性心肌梗死发病6小时入院。心电图示ST段弓背向上抬高。遵医嘱行急诊PCI。术前护士准备工作中，不正确的是", "options": {"A": "建立静脉通道", "B": "采集血液标本", "C": "给予抗血小板药物负荷剂量", "D": "术前给予高脂饮食以储备能量", "E": "完善术前检查"}, "answer": "D"}, {"id": 180, "chapter": "第2-3章_呼吸循环", "original_id": 180, "type": "single", "question": "梁某，男，68岁。慢性心力衰竭，长期卧床。近日出现右下肢肿胀、疼痛，Homans征阳性。最可能的并发症是", "options": {"A": "下肢静脉曲张", "B": "下肢深静脉血栓形成", "C": "动脉栓塞", "D": "淋巴水肿", "E": "蜂窝织炎"}, "answer": "B"}, {"id": 181, "chapter": "第2-3章_呼吸循环", "original_id": 181, "type": "single", "question": "韩某，女，35岁。风湿性心脏病二尖瓣狭窄。查体：心尖部可闻及舒张期隆隆样杂音。该患者最可能出现的早期症状是", "options": {"A": "劳力性呼吸困难", "B": "端坐呼吸", "C": "夜间阵发性呼吸困难", "D": "急性肺水肿", "E": "右心衰竭表现"}, "answer": "A"}, {"id": 182, "chapter": "第2-3章_呼吸循环", "original_id": 182, "type": "single", "question": "于某，男，50岁。诊断为原发性高血压，血压175/105mmHg，合并糖尿病。该患者的高血压分级和危险分层为", "options": {"A": "2级，低危", "B": "2级，中危", "C": "2级，高危", "D": "3级，高危", "E": "3级，极高危"}, "answer": "E"}, {"id": 183, "chapter": "第2-3章_呼吸循环", "original_id": 183, "type": "single", "question": "谢某，女，62岁。心衰患者，长期服用ACEI类药物。护士应告知患者最常见的不良反应是", "options": {"A": "心动过缓", "B": "干咳", "C": "肝功能损害", "D": "低血糖", "E": "便秘"}, "answer": "B"}, {"id": 184, "chapter": "第2-3章_呼吸循环", "original_id": 184, "type": "single", "question": "曹某，男，58岁。急性心肌梗死急性期。遵医嘱给予极化液（GIK）治疗。极化液的组成是", "options": {"A": "葡萄糖+胰岛素+氯化钾", "B": "葡萄糖+胰岛素+氯化钠", "C": "氯化钾+胰岛素+硫酸镁", "D": "葡萄糖+氯化钾+维生素C", "E": "葡萄糖+胰高血糖素+氯化钾"}, "answer": "A"}, {"id": 185, "chapter": "第2-3章_呼吸循环", "original_id": 185, "type": "single", "question": "患者女性，45岁。阵发性室上性心动过速反复发作。此次发作时心率200次/分，BP 100/60mmHg。护士配合医生首先应采用的治疗措施是", "options": {"A": "Valsalva动作", "B": "压迫颈动脉窦", "C": "静脉注射腺苷", "D": "压迫眼球", "E": "诱导恶心"}, "answer": "C"}, {"id": 186, "chapter": "第2-3章_呼吸循环", "original_id": 186, "type": "multi", "question": "患者男性，65岁。慢性心力衰竭长期服用地高辛。护士应告知患者警惕洋地黄中毒的诱发因素包括", "options": {"A": "低钾血症", "B": "低镁血症", "C": "肾功能不全", "D": "合用胺碘酮", "E": "高钾血症"}, "answer": "A、B、C、D"}, {"id": 187, "chapter": "第2-3章_呼吸循环", "original_id": 187, "type": "multi", "question": "急性左心衰竭的急救护理措施包括", "options": {"A": "取端坐位，双腿下垂", "B": "高流量吸氧（6~8L/min），经20%~30%乙醇湿化", "C": "遵医嘱给予吗啡镇静", "D": "快速利尿，静脉注射呋塞米", "E": "快速补液以维持血容量"}, "answer": "A、B、C、D"}, {"id": 188, "chapter": "第2-3章_呼吸循环", "original_id": 188, "type": "multi", "question": "患者男性，58岁。急性下壁心肌梗死入院第3天。护士在评估患者时应重点关注的并发症有", "options": {"A": "乳头肌功能失调或断裂", "B": "心脏破裂", "C": "心室壁瘤", "D": "栓塞", "E": "心肌梗死后综合征"}, "answer": "A、B、C、D、E"}, {"id": 189, "chapter": "第2-3章_呼吸循环", "original_id": 189, "type": "multi", "question": "高血压患者生活方式干预的措施包括", "options": {"A": "限制钠盐摄入，每日<6g", "B": "控制体重，BMI<24", "C": "适量运动，每周至少150分钟中等强度有氧运动", "D": "戒烟限酒", "E": "增加钾盐摄入，多吃新鲜蔬菜水果"}, "answer": "A、B、C、D、E"}, {"id": 190, "chapter": "第2-3章_呼吸循环", "original_id": 190, "type": "multi", "question": "患者女性，55岁。风心病二尖瓣置换术后，长期口服华法林抗凝。护士应告知患者的注意事项包括", "options": {"A": "定期监测INR，目标值2.0~3.0", "B": "避免食用富含维生素K的食物（如大量绿叶蔬菜）", "C": "注意观察有无出血征象", "D": "如出现牙龈出血、皮肤瘀斑应及时就医", "E": "可自行调整华法林剂量"}, "answer": "A、B、C、D"}, {"id": 191, "chapter": "第2-3章_呼吸循环", "original_id": 191, "type": "multi", "question": "关于急性心肌梗死溶栓治疗的护理，下列正确的有", "options": {"A": "溶栓前详细询问有无禁忌证", "B": "溶栓给药时间应尽早，最好在发病12小时内", "C": "溶栓过程中密切监测心电图变化", "D": "观察有无出血并发症", "E": "溶栓后2小时内评估再通指标"}, "answer": "A、B、C、D、E"}, {"id": 192, "chapter": "第2-3章_呼吸循环", "original_id": 192, "type": "multi", "question": "患者男性，60岁。心力衰竭。护士为其进行利尿剂用药护理时应注意的事项包括", "options": {"A": "监测电解质，尤其是血钾水平", "B": "记录24小时出入量", "C": "利尿剂宜在早晨或上午服用，避免夜间排尿过多", "D": "观察体重变化，每日同一时间测量", "E": "鼓励患者大量饮水以促进利尿"}, "answer": "A、B、C、D"}, {"id": 193, "chapter": "第2-3章_呼吸循环", "original_id": 193, "type": "multi", "question": "关于冠心病患者的饮食指导，下列正确的有", "options": {"A": "低盐、低脂、低胆固醇饮食", "B": "增加膳食纤维摄入", "C": "适当增加深海鱼类摄入", "D": "限制总热量摄入，防止肥胖", "E": "可适量饮酒以活血化瘀"}, "answer": "A、B、C、D"}, {"id": 194, "chapter": "第2-3章_呼吸循环", "original_id": 194, "type": "multi", "question": "张某，女，68岁。因\"心力衰竭\"入院，医嘱给予利尿剂、ACEI、β受体阻滞剂联合治疗。护士在用药护理中应注意的事项有", "options": {"A": "β受体阻滞剂应从小剂量开始，逐渐加量", "B": "利尿期间监测电解质", "C": "ACEI可引起干咳，需注意观察", "D": "β受体阻滞剂禁用于急性心衰发作期", "E": "用药期间监测心率和血压"}, "answer": "A、B、C、D、E"}, {"id": 195, "chapter": "第2-3章_呼吸循环", "original_id": 195, "type": "multi", "question": "关于心脏骤停后心肺复苏的要点，下列正确的有", "options": {"A": "胸外按压与人工呼吸比为30:2", "B": "按压深度5~6cm", "C": "按压频率100~120次/分", "D": "每次按压后确保胸廓完全回弹", "E": "尽量减少按压中断时间"}, "answer": "A、B、C、D、E"}, {"id": 196, "chapter": "第2-3章_呼吸循环", "original_id": 196, "type": "multi", "question": "患者男性，70岁。慢性心力衰竭。护士评估其心衰加重的诱因时应考虑的因素包括", "options": {"A": "感染（尤其是肺部感染）", "B": "过度劳累或情绪激动", "C": "钠盐摄入过多", "D": "输液速度过快", "E": "自行停药或不规律用药"}, "answer": "A、B、C、D、E"}, {"id": 197, "chapter": "第2-3章_呼吸循环", "original_id": 197, "type": "multi", "question": "关于心律失常患者的护理措施，下列正确的有", "options": {"A": "严重心律失常患者应绝对卧床休息", "B": "持续心电监护，及时发现致命性心律失常", "C": "备好除颤仪和急救药品", "D": "避免诱发因素如情绪激动、饮浓茶咖啡等", "E": "抗心律失常药物可随意更换剂量"}, "answer": "A、B、C、D"}, {"id": 198, "chapter": "第2-3章_呼吸循环", "original_id": 198, "type": "multi", "question": "患者女性，52岁。确诊为扩张型心肌病。护士为其进行健康指导时应包括的内容有", "options": {"A": "注意休息，避免剧烈活动", "B": "遵医嘱长期服药，不可自行停药", "C": "预防感染，尤其是呼吸道感染", "D": "定期复查心脏超声", "E": "可妊娠以改善心功能"}, "answer": "A、B、C、D"}, {"id": 199, "chapter": "第2-3章_呼吸循环", "original_id": 199, "type": "multi", "question": "关于冠状动脉介入治疗（PCI）术后护理，下列正确的有", "options": {"A": "穿刺部位加压包扎，观察有无渗血和血肿", "B": "术侧肢体制动6~8小时（股动脉穿刺）", "C": "观察足背动脉搏动情况", "D": "鼓励患者多饮水以促进造影剂排出", "E": "术后即可下床活动"}, "answer": "A、B、C、D"}, {"id": 200, "chapter": "第2-3章_呼吸循环", "original_id": 200, "type": "multi", "question": "患者男性，55岁。高血压危象入院。护士在配合医生进行降压处理时应注意的原则包括", "options": {"A": "降压速度不宜过快", "B": "第1小时内血压下降不超过治疗前的25%", "C": "subsequent 2~6小时内将血压降至160/100mmHg左右", "D": "静脉给予降压药物，便于调控", "E": "迅速将血压降至正常水平"}, "answer": "A、B、C、D"}, {"id": 201, "chapter": "第2-3章_呼吸循环", "original_id": 201, "type": "multi", "question": "关于β受体阻滞剂在心力衰竭治疗中的应用，下列正确的有", "options": {"A": "适用于慢性心衰稳定期患者", "B": "从小剂量开始，逐渐加至目标剂量或最大耐受量", "C": "急性心衰失代偿期禁用", "D": "用药期间心率不应低于55次/分", "E": "可与ACEI联合应用"}, "answer": "A、B、C、D、E"}, {"id": 202, "chapter": "第2-3章_呼吸循环", "original_id": 202, "type": "multi", "question": "患者女性，60岁。风心病主动脉瓣狭窄。护士在评估该患者时应关注的典型三联征包括", "options": {"A": "呼吸困难", "B": "心绞痛", "C": "晕厥", "D": "咯血", "E": "发绀"}, "answer": "A、B、C"}, {"id": 203, "chapter": "第2-3章_呼吸循环", "original_id": 203, "type": "multi", "question": "关于心包穿刺术的护理配合，下列正确的有", "options": {"A": "术前做好患者解释，消除恐惧心理", "B": "协助患者取坐位或半坐卧位", "C": "穿刺过程中密切观察患者面色、脉搏、血压", "D": "首次抽液量不宜超过300~500ml", "E": "抽液后标本及时送检"}, "answer": "A、B、C、D、E"}, {"id": 204, "chapter": "第2-3章_呼吸循环", "original_id": 204, "type": "multi", "question": "护士对冠心病患者进行出院健康指导时应包括", "options": {"A": "坚持长期规律服药", "B": "合理饮食，低盐低脂", "C": "适度运动，循序渐进", "D": "定期复查心电图、血脂等指标", "E": "教会患者识别心绞痛发作先兆及自救方法"}, "answer": "A、B、C、D、E"}, {"id": 205, "chapter": "第2-3章_呼吸循环", "original_id": 205, "type": "multi", "question": "患者男性，48岁。因\"室性心动过速\"行电复律治疗。术后护士应观察的内容包括", "options": {"A": "心律、心率变化", "B": "血压、呼吸变化", "C": "穿刺部位有无出血", "D": "有无血栓栓塞征象", "E": "皮肤有无电灼伤"}, "answer": "A、B、D、E"}, {"id": 206, "chapter": "第4-6章_消化泌尿血液", "original_id": 206, "type": "judge", "question": "幽门螺杆菌（Hp）感染是慢性胃炎最常见的病因。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 207, "chapter": "第4-6章_消化泌尿血液", "original_id": 207, "type": "judge", "question": "消化性溃疡最常见的并发症是癌变。", "options": {"A": "正确", "B": "错误"}, "answer": "B"}, {"id": 208, "chapter": "第4-6章_消化泌尿血液", "original_id": 208, "type": "judge", "question": "肝硬化患者出现腹水时，每日饮水量应限制在1000ml以内。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 209, "chapter": "第4-6章_消化泌尿血液", "original_id": 209, "type": "judge", "question": "急性胰腺炎患者血清淀粉酶一般在起病后6-12小时开始升高，48小时开始下降。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 210, "chapter": "第4-6章_消化泌尿血液", "original_id": 210, "type": "judge", "question": "溃疡性结肠炎病变多位于直肠和乙状结肠，也可延伸到降结肠甚至整个结肠。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 211, "chapter": "第4-6章_消化泌尿血液", "original_id": 211, "type": "judge", "question": "三腔二囊管插管压迫止血时，食管囊注气压力应维持在30-45mmHg。", "options": {"A": "正确", "B": "错误"}, "answer": "B"}, {"id": 212, "chapter": "第4-6章_消化泌尿血液", "original_id": 212, "type": "judge", "question": "肝性脑病患者应给予高蛋白饮食以补充营养。", "options": {"A": "正确", "B": "错误"}, "answer": "B"}, {"id": 213, "chapter": "第4-6章_消化泌尿血液", "original_id": 213, "type": "judge", "question": "肠易激综合征是一种功能性肠道疾病，与精神心理因素无关。", "options": {"A": "正确", "B": "错误"}, "answer": "B"}, {"id": 214, "chapter": "第4-6章_消化泌尿血液", "original_id": 214, "type": "single", "question": "王某，男，58岁。反复上腹部隐痛5年，多于餐后半小时出现，持续1-2小时逐渐缓解，伴反酸、嗳气。近1周症状加重，今日排黑色糊状便2次。查体：上腹部偏右轻压痛。粪便隐血试验强阳性。该患者最可能的诊断是", "options": {"A": "十二指肠溃疡", "B": "胃溃疡", "C": "急性糜烂出血性胃炎", "D": "胃癌", "E": "慢性胃炎急性发作"}, "answer": "B"}, {"id": 215, "chapter": "第4-6章_消化泌尿血液", "original_id": 215, "type": "single", "question": "李某，男，45岁。有乙肝病史15年。近半年来感乏力、食欲减退、腹胀，体格检查发现面色灰暗、巩膜黄染、蜘蛛痣、肝掌，腹部膨隆，移动性浊音阳性。该患者腹部膨隆最可能的原因是", "options": {"A": "胃肠胀气", "B": "巨大卵巢囊肿", "C": "肝硬化腹水", "D": "巨大腹腔肿瘤", "E": "急性胃扩张"}, "answer": "C"}, {"id": 216, "chapter": "第4-6章_消化泌尿血液", "original_id": 216, "type": "single", "question": "赵某，女，52岁。因\"肝硬化失代偿期\"入院。今晨护士查房时发现患者性格轻度亢奋，言语不清，定向力尚可，扑翼样震颤阳性。该患者目前处于肝性脑病的", "options": {"A": "前驱期", "B": "昏迷前期", "C": "昏睡期", "D": "昏迷期", "E": "亚临床期"}, "answer": "B"}, {"id": 217, "chapter": "第4-6章_消化泌尿血液", "original_id": 217, "type": "single", "question": "张某，男，42岁。饱餐及饮酒后突然出现上腹部持续性剧痛5小时，伴恶心、呕吐，呕吐后腹痛无缓解。查体：体温38.5℃，上腹部压痛明显，反跳痛(+)，腹肌紧张。血清淀粉酶960U/L（Somogyi法）。该患者最可能的诊断是", "options": {"A": "急性胆囊炎", "B": "消化性溃疡穿孔", "C": "急性胰腺炎", "D": "急性阑尾炎", "E": "肠梗阻"}, "answer": "C"}, {"id": 218, "chapter": "第4-6章_消化泌尿血液", "original_id": 218, "type": "single", "question": "孙某，男，60岁。有\"肝硬化\"病史8年。今日突然呕血约800ml，色暗红，伴头晕、心悸、出汗。查体：血压85/50mmHg，心率120次/分，面色苍白。该患者上消化道出血最可能的原因是", "options": {"A": "消化性溃疡", "B": "急性胃黏膜病变", "C": "食管胃底静脉曲张破裂", "D": "胃癌", "E": "贲门黏膜撕裂综合征"}, "answer": "C"}, {"id": 219, "chapter": "第4-6章_消化泌尿血液", "original_id": 219, "type": "single", "question": "刘某，女，35岁。因\"克罗恩病\"入院，护士对其进行饮食指导。下列饮食建议中不正确的是", "options": {"A": "高蛋白", "B": "高热量", "C": "高纤维", "D": "低渣", "E": "富含维生素"}, "answer": "C"}, {"id": 220, "chapter": "第4-6章_消化泌尿血液", "original_id": 220, "type": "single", "question": "陈某，男，50岁。诊断为\"原发性肝癌\"，行肝动脉化疗栓塞术（TACE）后返回病房。术后护理措施不正确的是", "options": {"A": "密切观察穿刺部位有无渗血", "B": "术后禁食2-3小时", "C": "术后取半卧位", "D": "监测体温变化", "E": "鼓励患者术后早期下床活动"}, "answer": "E"}, {"id": 221, "chapter": "第4-6章_消化泌尿血液", "original_id": 221, "type": "single", "question": "周某，女，28岁。反复腹泻、黏液脓血便3个月，每日4-6次，伴左下腹隐痛，便后可缓解。结肠镜检查示直肠及乙状结肠弥漫性充血水肿、脆性增加、散在浅溃疡。该患者最可能的诊断是", "options": {"A": "克罗恩病", "B": "溃疡性结肠炎", "C": "肠结核", "D": "结肠癌", "E": "细菌性痢疾"}, "answer": "B"}, {"id": 222, "chapter": "第4-6章_消化泌尿血液", "original_id": 222, "type": "single", "question": "吴某，男，55岁。因\"上消化道出血\"入院，行三腔二囊管压迫止血。插管后24小时，护士应首先注意观察的是", "options": {"A": "体温变化", "B": "引流液的颜色和量", "C": "血压和脉搏", "D": "有无呼吸困难", "E": "有无烦躁不安"}, "answer": "D"}, {"id": 223, "chapter": "第4-6章_消化泌尿血液", "original_id": 223, "type": "single", "question": "郑某，女，62岁。胃镜检查发现胃窦部溃疡，直径约2cm，边缘不规则，底部凹凸不平，覆有污秽苔。活检病理示低分化腺癌。该患者目前最主要的护理诊断是", "options": {"A": "疼痛", "B": "营养失调：低于机体需要量", "C": "焦虑/恐惧", "D": "知识缺乏", "E": "潜在并发症：出血"}, "answer": "C"}, {"id": 224, "chapter": "第4-6章_消化泌尿血液", "original_id": 224, "type": "single", "question": "钱某，男，38岁。诊断为\"幽门螺杆菌阳性十二指肠球部溃疡\"，护士指导其服用标准四联疗法。下列用药指导正确的是", "options": {"A": "质子泵抑制剂餐前服用", "B": "铋剂餐后服用", "C": "两种抗生素均餐前服用", "D": "疗程一般为3-5天", "E": "抗生素之间应间隔4小时服用"}, "answer": "A"}, {"id": 225, "chapter": "第4-6章_消化泌尿血液", "original_id": 225, "type": "single", "question": "冯某，女，68岁。肝硬化腹水患者，利尿治疗后出现腹胀、乏力、心悸。查血钾2.8mmol/L。此时最恰当的护理措施是", "options": {"A": "继续利尿治疗", "B": "口服氯化钾缓释片", "C": "静脉补充氯化钾，浓度不超过0.3%", "D": "限制含钾食物摄入", "E": "立即停用所有药物"}, "answer": "C"}, {"id": 226, "chapter": "第4-6章_消化泌尿血液", "original_id": 226, "type": "single", "question": "许某，男，48岁。行结肠镜检查前，护士进行肠道准备指导。下列指导内容不正确的是", "options": {"A": "检查前一天进低渣半流质饮食", "B": "检查当日晨起禁食", "C": "检查前4-6小时口服聚乙二醇电解质散", "D": "服用泻剂期间应多活动促进排便", "E": "肠道准备完成后粪便应为清水样"}, "answer": "B"}, {"id": 227, "chapter": "第4-6章_消化泌尿血液", "original_id": 227, "type": "single", "question": "消化性溃疡发生的主要攻击因子是", "options": {"A": "胃酸和胃蛋白酶", "B": "非甾体抗炎药", "C": "幽门螺杆菌", "D": "胆汁反流", "E": "乙醇"}, "answer": "A"}, {"id": 228, "chapter": "第4-6章_消化泌尿血液", "original_id": 228, "type": "single", "question": "关于慢性胃炎患者的饮食指导，正确的是", "options": {"A": "急性发作期应进食高脂肪食物", "B": "胃酸缺乏者可适当摄入醋和酸性食物", "C": "所有患者均需严格禁食", "D": "应大量摄入粗纤维食物", "E": "胃酸分泌过多者宜多喝浓肉汤"}, "answer": "B"}, {"id": 229, "chapter": "第4-6章_消化泌尿血液", "original_id": 229, "type": "single", "question": "克罗恩病与溃疡性结肠炎最主要的鉴别点是", "options": {"A": "病变部位", "B": "腹泻程度", "C": "病变呈节段性分布 vs 连续性弥漫性分布", "D": "有无腹痛", "E": "有无发热"}, "answer": "C"}, {"id": 230, "chapter": "第4-6章_消化泌尿血液", "original_id": 230, "type": "single", "question": "上消化道出血最常见的病因是", "options": {"A": "食管胃底静脉曲张破裂", "B": "消化性溃疡", "C": "急性糜烂出血性胃炎", "D": "胃癌", "E": "Mallory-Weiss综合征"}, "answer": "B"}, {"id": 231, "chapter": "第4-6章_消化泌尿血液", "original_id": 231, "type": "single", "question": "肝硬化门脉高压的三大临床表现是", "options": {"A": "腹水、脾大、侧支循环建立", "B": "黄疸、出血、肝性脑病", "C": "蜘蛛痣、肝掌、男性乳房发育", "D": "腹水、黄疸、肝大", "E": "脾大、贫血、血小板减少"}, "answer": "A"}, {"id": 232, "chapter": "第4-6章_消化泌尿血液", "original_id": 232, "type": "single", "question": "肝性脑病患者使用乳果糖的主要目的是", "options": {"A": "补充能量", "B": "酸化肠道环境，减少氨的吸收", "C": "促进肠蠕动", "D": "补充膳食纤维", "E": "抑制肠道细菌生长"}, "answer": "B"}, {"id": 233, "chapter": "第4-6章_消化泌尿血液", "original_id": 233, "type": "single", "question": "急性胰腺炎患者禁食、胃肠减压的主要目的是", "options": {"A": "防止呕吐", "B": "减少胃酸分泌，从而减少胰腺分泌", "C": "减轻腹胀", "D": "防止胃扩张", "E": "预防感染"}, "answer": "B"}, {"id": 234, "chapter": "第4-6章_消化泌尿血液", "original_id": 234, "type": "single", "question": "关于上消化道出血患者的护理，错误的是", "options": {"A": "大出血时取平卧位，头偏向一侧", "B": "应迅速建立静脉通道", "C": "食管胃底静脉曲张破裂出血时应放置普通胃管洗胃", "D": "应密切观察呕吐物和粪便的颜色、量", "E": "出血期应禁食"}, "answer": "C"}, {"id": 235, "chapter": "第4-6章_消化泌尿血液", "original_id": 235, "type": "single", "question": "肠易激综合征最主要的治疗措施是", "options": {"A": "抗生素治疗", "B": "手术治疗", "C": "调整饮食及心理治疗", "D": "免疫抑制剂", "E": "化疗"}, "answer": "C"}, {"id": 236, "chapter": "第4-6章_消化泌尿血液", "original_id": 236, "type": "single", "question": "原发性肝癌最特异的肿瘤标志物是", "options": {"A": "CEA", "B": "CA19-9", "C": "AFP", "D": "CA125", "E": "PSA"}, "answer": "C"}, {"id": 237, "chapter": "第4-6章_消化泌尿血液", "original_id": 237, "type": "single", "question": "肝硬化患者出现全血细胞减少的最主要原因是", "options": {"A": "造血原料缺乏", "B": "脾功能亢进", "C": "骨髓造血功能抑制", "D": "消化道出血", "E": "叶酸缺乏"}, "answer": "B"}, {"id": 238, "chapter": "第4-6章_消化泌尿血液", "original_id": 238, "type": "single", "question": "急性重症胰腺炎最常见的局部并发症是", "options": {"A": "胰腺假性囊肿", "B": "胰腺脓肿", "C": "胰瘘", "D": "胰腺坏死", "E": "腹腔间隔室综合征"}, "answer": "A"}, {"id": 239, "chapter": "第4-6章_消化泌尿血液", "original_id": 239, "type": "single", "question": "溃疡性结肠炎患者首选的治疗药物是", "options": {"A": "抗生素", "B": "氨基水杨酸制剂", "C": "糖皮质激素", "D": "免疫抑制剂", "E": "生物制剂"}, "answer": "B"}, {"id": 240, "chapter": "第4-6章_消化泌尿血液", "original_id": 240, "type": "single", "question": "三腔二囊管拔管的指征是", "options": {"A": "出血停止后即可拔管", "B": "出血停止后24小时", "C": "出血停止后48-72小时可先放空气囊观察24小时，无再出血则拔管", "D": "放置满72小时必须拔管", "E": "患者主诉舒适即可拔管"}, "answer": "C"}, {"id": 241, "chapter": "第4-6章_消化泌尿血液", "original_id": 241, "type": "single", "question": "关于肝硬化腹水患者的护理，错误的是", "options": {"A": "取半卧位以减轻呼吸困难", "B": "每日测量腹围和体重", "C": "腹腔穿刺放液后应束紧腹带", "D": "每日进液量约2000ml", "E": "给予高蛋白、高钠饮食"}, "answer": "E"}, {"id": 242, "chapter": "第4-6章_消化泌尿血液", "original_id": 242, "type": "multi", "question": "韩某，男，55岁。因\"肝硬化腹水\"入院，给予腹腔穿刺放液术。术后护士应观察的内容包括", "options": {"A": "穿刺点有无渗液", "B": "生命体征变化", "C": "有无腹部体征改变", "D": "有无肝性脑病先兆", "E": "尿量变化"}, "answer": "A、B、C、D、E"}, {"id": 243, "chapter": "第4-6章_消化泌尿血液", "original_id": 243, "type": "multi", "question": "曹某，女，48岁。诊断为\"消化性溃疡伴Hp感染\"。护士对其进行健康教育，内容包括", "options": {"A": "遵医嘱完成四联疗法疗程", "B": "避免服用非甾体抗炎药", "C": "戒烟限酒", "D": "停药后立即复查胃镜", "E": "规律进餐，避免刺激性食物"}, "answer": "A、B、C、E"}, {"id": 244, "chapter": "第4-6章_消化泌尿血液", "original_id": 244, "type": "multi", "question": "丁某，男，62岁。肝硬化病史10年，今日出现意识模糊、定向力丧失，诊断为肝性脑病。针对该患者的护理措施正确的有", "options": {"A": "限制蛋白质摄入", "B": "保持大便通畅", "C": "使用弱碱性灌肠液灌肠", "D": "静脉输注支链氨基酸", "E": "使用米醋或稀醋酸灌肠"}, "answer": "A、B、D、E"}, {"id": 245, "chapter": "第4-6章_消化泌尿血液", "original_id": 245, "type": "multi", "question": "魏某，女，40岁。反复腹痛、腹泻1年，体重下降5kg。肠镜示回肠末端及升结肠节段性病变，可见纵行溃疡、鹅卵石样改变，诊断为克罗恩病。该患者可能出现的并发症有", "options": {"A": "肠梗阻", "B": "腹腔脓肿", "C": "肠瘘", "D": "癌变", "E": "肛周病变"}, "answer": "A、B、C、D、E"}, {"id": 246, "chapter": "第4-6章_消化泌尿血液", "original_id": 246, "type": "multi", "question": "方某，男，52岁。因\"食管胃底静脉曲张破裂出血\"行三腔二囊管压迫止血，置管期间护士的护理要点包括", "options": {"A": "保持鼻腔黏膜清洁湿润", "B": "定时测量气囊压力", "C": "每隔12-24小时放空气囊10-20分钟", "D": "观察有无窒息征象", "E": "口腔护理每日2-3次"}, "answer": "A、B、C、D、E"}, {"id": 247, "chapter": "第4-6章_消化泌尿血液", "original_id": 247, "type": "multi", "question": "田某，女，36岁。因\"急性胰腺炎\"入院，腹痛剧烈，血清淀粉酶显著升高。对该患者应采取的护理措施有", "options": {"A": "禁食、胃肠减压", "B": "取屈膝侧卧位", "C": "遵医嘱给予镇痛药", "D": "密切监测生命体征", "E": "记录24小时出入量"}, "answer": "A、B、C、D、E"}, {"id": 248, "chapter": "第4-6章_消化泌尿血液", "original_id": 248, "type": "multi", "question": "慢性萎缩性胃炎的临床特点包括", "options": {"A": "胃酸分泌减少", "B": "血清胃泌素水平降低", "C": "可出现恶性贫血", "D": "Hp感染是常见病因", "E": "属于癌前疾病"}, "answer": "A、C、D、E"}, {"id": 249, "chapter": "第4-6章_消化泌尿血液", "original_id": 249, "type": "multi", "question": "上消化道大量出血的临床表现包括", "options": {"A": "呕血和黑便", "B": "失血性周围循环衰竭", "C": "发热", "D": "氮质血症", "E": "血象改变"}, "answer": "A、B、C、D、E"}, {"id": 250, "chapter": "第4-6章_消化泌尿血液", "original_id": 250, "type": "multi", "question": "肝硬化患者出血倾向的原因包括", "options": {"A": "肝脏合成凝血因子减少", "B": "脾功能亢进致血小板减少", "C": "毛细血管脆性增加", "D": "维生素K吸收障碍", "E": "纤维蛋白溶解增加"}, "answer": "A、B、C、D"}, {"id": 251, "chapter": "第4-6章_消化泌尿血液", "original_id": 251, "type": "multi", "question": "关于肝性脑病的诱发因素，正确的有", "options": {"A": "大量排钾利尿", "B": "高蛋白饮食", "C": "上消化道出血", "D": "便秘", "E": "感染"}, "answer": "A、B、C、D、E"}, {"id": 252, "chapter": "第4-6章_消化泌尿血液", "original_id": 252, "type": "multi", "question": "原发性肝癌的临床表现包括", "options": {"A": "肝区疼痛", "B": "肝大", "C": "黄疸", "D": "肝硬化征象", "E": "伴癌综合征"}, "answer": "A、B、C、D、E"}, {"id": 253, "chapter": "第4-6章_消化泌尿血液", "original_id": 253, "type": "multi", "question": "急性胰腺炎患者血清淀粉酶变化的特点包括", "options": {"A": "起病后6-12小时开始升高", "B": "48小时开始下降", "C": "持续3-5天", "D": "淀粉酶高低与病情严重程度完全一致", "E": "血淀粉酶>500U/L（Somogyi法）有诊断价值"}, "answer": "A、B、C、E"}, {"id": 254, "chapter": "第4-6章_消化泌尿血液", "original_id": 254, "type": "multi", "question": "消化性溃疡的常见并发症包括", "options": {"A": "出血", "B": "穿孔", "C": "幽门梗阻", "D": "癌变", "E": "瘘管形成"}, "answer": "A、B、C、D"}, {"id": 255, "chapter": "第4-6章_消化泌尿血液", "original_id": 255, "type": "multi", "question": "关于炎症性肠病的饮食护理，正确的有", "options": {"A": "急性发作期应进无渣流质饮食", "B": "避免牛奶及乳制品", "C": "高蛋白质饮食", "D": "高纤维素饮食", "E": "避免生冷、辛辣食物"}, "answer": "A、B、C、E"}, {"id": 256, "chapter": "第4-6章_消化泌尿血液", "original_id": 256, "type": "multi", "question": "溃疡性结肠炎患者使用糖皮质激素期间应注意观察", "options": {"A": "感染征象", "B": "血糖变化", "C": "电解质紊乱", "D": "消化道出血", "E": "骨质疏松"}, "answer": "A、B、C、D、E"}, {"id": 257, "chapter": "第4-6章_消化泌尿血液", "original_id": 257, "type": "multi", "question": "上消化道出血患者内镜检查的护理配合包括", "options": {"A": "检查前禁食8小时", "B": "建立静脉通道", "C": "准备好急救药品和设备", "D": "检查后立即给予进食", "E": "检查后观察有无呕血、黑便"}, "answer": "A、B、C、E"}, {"id": 258, "chapter": "第4-6章_消化泌尿血液", "original_id": 258, "type": "multi", "question": "肝硬化腹水患者的饮食原则包括", "options": {"A": "低盐或无盐饮食", "B": "适量蛋白质", "C": "高热量", "D": "高维生素", "E": "限制水的摄入"}, "answer": "A、B、C、D、E"}, {"id": 259, "chapter": "第4-6章_消化泌尿血液", "original_id": 259, "type": "multi", "question": "关于三腔二囊管的护理，正确的有", "options": {"A": "插管前应先检查气囊有无漏气", "B": "胃囊注气约150-200ml", "C": "食管囊注气约100ml", "D": "牵引重量约0.5kg", "E": "拔管前需口服石蜡油"}, "answer": "A、B、C、D、E"}, {"id": 260, "chapter": "第4-6章_消化泌尿血液", "original_id": 260, "type": "multi", "question": "急性胰腺炎的局部并发症包括", "options": {"A": "胰腺假性囊肿", "B": "胰腺脓肿", "C": "胰腺坏死感染", "D": "多器官功能衰竭", "E": "胰瘘"}, "answer": "A、B、C、E"}, {"id": 261, "chapter": "第4-6章_消化泌尿血液", "original_id": 261, "type": "judge", "question": "肾病综合征的典型表现为大量蛋白尿、低白蛋白血症、高度水肿和高脂血症。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 262, "chapter": "第4-6章_消化泌尿血液", "original_id": 262, "type": "judge", "question": "急性肾小球肾炎最常见的病因为β-溶血性链球菌感染。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 263, "chapter": "第4-6章_消化泌尿血液", "original_id": 263, "type": "judge", "question": "慢性肾衰竭患者出现代谢性酸中毒时，可表现为呼吸深大。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 264, "chapter": "第4-6章_消化泌尿血液", "original_id": 264, "type": "judge", "question": "腹膜透析患者最常见的并发症是腹膜炎。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 265, "chapter": "第4-6章_消化泌尿血液", "original_id": 265, "type": "judge", "question": "血液透析时常用的抗凝剂为枸橼酸钠。", "options": {"A": "正确", "B": "错误"}, "answer": "B"}, {"id": 266, "chapter": "第4-6章_消化泌尿血液", "original_id": 266, "type": "judge", "question": "肾移植术后患者应密切观察尿量和移植肾功能情况，急性排斥反应多发生在术后1周内。", "options": {"A": "正确", "B": "错误"}, "answer": "B"}, {"id": 267, "chapter": "第4-6章_消化泌尿血液", "original_id": 267, "type": "judge", "question": "尿路感染最常见的致病菌为大肠埃希菌。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 268, "chapter": "第4-6章_消化泌尿血液", "original_id": 268, "type": "judge", "question": "慢性肾脏病（CKD）5期的肾小球滤过率（GFR）为<15ml/min。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 269, "chapter": "第4-6章_消化泌尿血液", "original_id": 269, "type": "single", "question": "马某，女，28岁。2周前曾有咽痛、发热史。近3天出现眼睑水肿、尿色发红，每日尿量约400ml。查体：血压150/95mmHg，颜面及双下肢轻度水肿。尿常规：蛋白(++)，红细胞(+++)，可见红细胞管型。血清补体C3降低。该患者最可能的诊断是", "options": {"A": "慢性肾小球肾炎", "B": "急性肾小球肾炎", "C": "急进性肾小球肾炎", "D": "肾病综合征", "E": "IgA肾病"}, "answer": "B"}, {"id": 270, "chapter": "第4-6章_消化泌尿血液", "original_id": 270, "type": "single", "question": "何某，女，10岁。因\"颜面及双下肢水肿1周\"入院。查体：血压正常，全身高度水肿。实验室检查：尿蛋白(++++)，24小时尿蛋白定量5.8g，血清白蛋白18g/L，胆固醇12.5mmol/L。该患者符合的诊断是", "options": {"A": "急性肾炎", "B": "慢性肾炎", "C": "肾病综合征", "D": "隐匿性肾炎", "E": "急进性肾炎"}, "answer": "C"}, {"id": 271, "chapter": "第4-6章_消化泌尿血液", "original_id": 271, "type": "single", "question": "梁某，女，65岁。糖尿病病史15年，近1年来双下肢水肿逐渐加重，伴泡沫尿。查体：血压160/90mmHg，双下肢凹陷性水肿。实验室检查：24小时尿蛋白3.2g，血清白蛋白25g/L，血肌酐186μmol/L。最可能的诊断是", "options": {"A": "原发性肾病综合征", "B": "糖尿病肾病", "C": "高血压肾损害", "D": "慢性肾小球肾炎", "E": "急性肾损伤"}, "answer": "B"}, {"id": 272, "chapter": "第4-6章_消化泌尿血液", "original_id": 272, "type": "single", "question": "胡某，女，32岁。尿频、尿急、尿痛3天，伴腰痛、发热，体温38.8℃。查体：双侧肾区叩击痛(+)。尿常规：白细胞满视野，可见白细胞管型。中段尿培养示大肠埃希菌>10⁵/ml。最可能的诊断是", "options": {"A": "急性膀胱炎", "B": "急性肾盂肾炎", "C": "慢性肾盂肾炎", "D": "泌尿系结核", "E": "尿道炎"}, "answer": "B"}, {"id": 273, "chapter": "第4-6章_消化泌尿血液", "original_id": 273, "type": "single", "question": "宋某，男，72岁。前列腺增生病史10年。近1周排尿困难加重，下腹胀痛，今日无尿。查体：耻骨上区膨隆，叩诊呈浊音。膀胱残余尿量800ml。该患者出现的肾功能不全最可能属于", "options": {"A": "肾前性急性肾损伤", "B": "肾性急性肾损伤", "C": "肾后性急性肾损伤", "D": "慢性肾脏病3期", "E": "慢性肾脏病5期"}, "answer": "C"}, {"id": 274, "chapter": "第4-6章_消化泌尿血液", "original_id": 274, "type": "single", "question": "朱某，男，58岁。慢性肾脏病史5年，近1个月来恶心、呕吐、皮肤瘙痒加重。实验室检查：血肌酐980μmol/L，尿素氮35mmol/L，血钾5.8mmol/L，血钙1.6mmol/L，Hb 65g/L。该患者目前最适宜的治疗方式是", "options": {"A": "保守治疗", "B": "血液透析或腹膜透析", "C": "单纯药物治疗", "D": "肾切除", "E": "血浆置换"}, "answer": "B"}, {"id": 275, "chapter": "第4-6章_消化泌尿血液", "original_id": 275, "type": "single", "question": "蒋某，女，45岁。维持性血液透析3年，透析过程中突然出现胸闷、气促、出冷汗，血压80/50mmHg。护士首先应考虑", "options": {"A": "空气栓塞", "B": "失衡综合征", "C": "低血压", "D": "心律失常", "E": "透析器反应"}, "answer": "C"}, {"id": 276, "chapter": "第4-6章_消化泌尿血液", "original_id": 276, "type": "single", "question": "袁某，女，38岁。因\"肾病综合征\"口服泼尼松治疗3个月。今日复查出现满月脸、水牛背、血糖升高。护士对其进行健康指导，正确的是", "options": {"A": "立即自行停药", "B": "加快减量速度", "C": "应遵医嘱逐渐减量，不可骤停", "D": "继续原剂量长期使用", "E": "改用免疫抑制剂替代激素"}, "answer": "C"}, {"id": 277, "chapter": "第4-6章_消化泌尿血液", "original_id": 277, "type": "single", "question": "夏某，男，50岁。慢性肾衰竭维持性血液透析患者，今晨透析前查血钾7.2mmol/L，心电图示T波高尖。护士应立即采取的措施是", "options": {"A": "限制含钾食物摄入", "B": "口服降钾树脂", "C": "立即给予紧急透析治疗", "D": "静脉注射10%葡萄糖酸钙", "E": "嘱患者多饮水"}, "answer": "D"}, {"id": 278, "chapter": "第4-6章_消化泌尿血液", "original_id": 278, "type": "single", "question": "范某，男，42岁。肾移植术后第3天，突然出现尿量减少、移植肾区胀痛、体温38.5℃、血肌酐较前升高。该患者最可能发生了", "options": {"A": "超急性排斥反应", "B": "急性排斥反应", "C": "慢性排斥反应", "D": "移植物抗宿主病", "E": "术后感染"}, "answer": "B"}, {"id": 279, "chapter": "第4-6章_消化泌尿血液", "original_id": 279, "type": "single", "question": "任某，女，55岁。腹膜透析置管术后1个月开始行持续性非卧床腹膜透析（CAPD）。今日透析液浑浊，伴腹痛、发热。护士应首先考虑", "options": {"A": "导管移位", "B": "腹膜炎", "C": "腹膜透析液外渗", "D": "引流不畅", "E": "腹壁疝"}, "answer": "B"}, {"id": 280, "chapter": "第4-6章_消化泌尿血液", "original_id": 280, "type": "single", "question": "陆某，女，22岁。因\"急性肾小球肾炎\"入院。入院第2天出现头痛、视物模糊、恶心呕吐，测血压180/110mmHg。护士判断该患者可能并发了", "options": {"A": "急性肺水肿", "B": "高血压脑病", "C": "脑出血", "D": "蛛网膜下腔出血", "E": "颅内感染"}, "answer": "B"}, {"id": 281, "chapter": "第4-6章_消化泌尿血液", "original_id": 281, "type": "single", "question": "急性肾小球肾炎患者水肿的首要护理措施是", "options": {"A": "限制蛋白质摄入", "B": "卧床休息", "C": "利尿", "D": "限盐限水", "E": "抗感染治疗"}, "answer": "D"}, {"id": 282, "chapter": "第4-6章_消化泌尿血液", "original_id": 282, "type": "single", "question": "肾病综合征患者水肿的主要原因是", "options": {"A": "肾小球滤过率下降", "B": "醛固酮分泌增多", "C": "血浆胶体渗透压下降", "D": "抗利尿激素分泌增多", "E": "毛细血管通透性增加"}, "answer": "C"}, {"id": 283, "chapter": "第4-6章_消化泌尿血液", "original_id": 283, "type": "single", "question": "慢性肾脏病患者贫血的主要原因是", "options": {"A": "铁缺乏", "B": "促红细胞生成素不足", "C": "叶酸缺乏", "D": "红细胞寿命缩短", "E": "消化道隐性失血"}, "answer": "B"}, {"id": 284, "chapter": "第4-6章_消化泌尿血液", "original_id": 284, "type": "single", "question": "血液透析时最常用的抗凝剂是", "options": {"A": "枸橼酸钠", "B": "肝素", "C": "华法林", "D": "低分子肝素", "E": "阿司匹林"}, "answer": "B"}, {"id": 285, "chapter": "第4-6章_消化泌尿血液", "original_id": 285, "type": "single", "question": "腹膜透析液灌入腹腔时的适宜温度为", "options": {"A": "25-28℃", "B": "30-32℃", "C": "37℃左右", "D": "40-42℃", "E": "45-48℃"}, "answer": "C"}, {"id": 286, "chapter": "第4-6章_消化泌尿血液", "original_id": 286, "type": "single", "question": "留置导尿管患者预防尿路感染最重要的护理措施是", "options": {"A": "每日更换引流袋", "B": "保持引流通畅", "C": "每日进行会阴部护理", "D": "鼓励多饮水", "E": "严格无菌操作"}, "answer": "E"}, {"id": 287, "chapter": "第4-6章_消化泌尿血液", "original_id": 287, "type": "single", "question": "慢性肾衰竭患者出现高钾血症时，最有效的治疗措施是", "options": {"A": "静脉注射葡萄糖酸钙", "B": "口服降钾树脂", "C": "静脉滴注胰岛素+葡萄糖", "D": "碳酸氢钠静脉滴注", "E": "透析治疗"}, "answer": "E"}, {"id": 288, "chapter": "第4-6章_消化泌尿血液", "original_id": 288, "type": "single", "question": "关于肾移植术后免疫抑制治疗，正确的是", "options": {"A": "术后无需长期服药", "B": "仅需使用一种免疫抑制剂", "C": "常用钙调磷酸酶抑制剂（如他克莫司）为基础的联合方案", "D": "出现排斥反应时应加用抗生素", "E": "免疫抑制剂无需监测血药浓度"}, "answer": "C"}, {"id": 289, "chapter": "第4-6章_消化泌尿血液", "original_id": 289, "type": "single", "question": "慢性肾小球肾炎患者尿蛋白控制目标为", "options": {"A": "<0.5g/d", "B": "<1.0g/d", "C": "<1.5g/d", "D": "<2.0g/d", "E": "完全转阴"}, "answer": "B"}, {"id": 290, "chapter": "第4-6章_消化泌尿血液", "original_id": 290, "type": "single", "question": "急性肾损伤少尿期最危险的并发症是", "options": {"A": "水中毒", "B": "高钾血症", "C": "代谢性酸中毒", "D": "低钠血症", "E": "感染"}, "answer": "B"}, {"id": 291, "chapter": "第4-6章_消化泌尿血液", "original_id": 291, "type": "single", "question": "尿路感染患者多饮水的目的是", "options": {"A": "降低体温", "B": "稀释尿液减轻刺激", "C": "冲洗尿路促进细菌排出", "D": "减轻水肿", "E": "预防肾结石"}, "answer": "C"}, {"id": 292, "chapter": "第4-6章_消化泌尿血液", "original_id": 292, "type": "single", "question": "肾病综合征患者饮食中蛋白质的摄入量应为", "options": {"A": "0.5g/(kg·d)", "B": "0.8g/(kg·d)", "C": "1.0g/(kg·d)", "D": "1.5g/(kg·d)", "E": "2.0g/(kg·d)"}, "answer": "C"}, {"id": 293, "chapter": "第4-6章_消化泌尿血液", "original_id": 293, "type": "single", "question": "慢性肾脏病5期患者饮食中磷的摄入应限制在", "options": {"A": "<300mg/d", "B": "<500mg/d", "C": "<800mg/d", "D": "<1000mg/d", "E": "<1500mg/d"}, "answer": "C"}, {"id": 294, "chapter": "第4-6章_消化泌尿血液", "original_id": 294, "type": "multi", "question": "邵某，男，55岁。慢性肾脏病史8年，目前维持性血液透析。护士对其进行饮食指导，正确的内容包括", "options": {"A": "优质高蛋白", "B": "限制水的摄入", "C": "限制钠的摄入", "D": "限制钾、磷的摄入", "E": "补充水溶性维生素"}, "answer": "A、B、C、D、E"}, {"id": 295, "chapter": "第4-6章_消化泌尿血液", "original_id": 295, "type": "multi", "question": "彭某，女，25岁。肾病综合征患者，使用环磷酰胺治疗期间，护士应观察的不良反应有", "options": {"A": "骨髓抑制", "B": "出血性膀胱炎", "C": "消化道反应", "D": "脱发", "E": "肝功能损害"}, "answer": "A、B、C、D、E"}, {"id": 296, "chapter": "第4-6章_消化泌尿血液", "original_id": 296, "type": "multi", "question": "杨某，女，70岁。慢性肾衰竭，开始腹膜透析治疗。护士指导患者预防腹膜炎的措施包括", "options": {"A": "操作前严格洗手、戴口罩", "B": "保持换液环境清洁", "C": "严格遵守无菌操作规程", "D": "出口处定期换药", "E": "透析液加温后使用"}, "answer": "A、B、C、D"}, {"id": 297, "chapter": "第4-6章_消化泌尿血液", "original_id": 297, "type": "multi", "question": "罗某，女，35岁。急性肾盂肾炎患者，护士对其进行健康指导，内容包括", "options": {"A": "多饮水、勤排尿", "B": "注意会阴部清洁", "C": "遵医嘱足疗程使用抗生素", "D": "治愈后可不必复查", "E": "避免劳累、增强免疫力"}, "answer": "A、B、C、E"}, {"id": 298, "chapter": "第4-6章_消化泌尿血液", "original_id": 298, "type": "multi", "question": "曾某，男，48岁。肾移植术后第5天，使用他克莫司+吗替麦考酚酯+泼尼松三联抗排斥方案。护士应监测的指标有", "options": {"A": "他克莫司血药浓度", "B": "血常规", "C": "肝肾功能", "D": "血糖", "E": "感染征象"}, "answer": "A、B、C、D、E"}, {"id": 299, "chapter": "第4-6章_消化泌尿血液", "original_id": 299, "type": "multi", "question": "廖某，女，60岁。急性肾损伤少尿期，血钾6.5mmol/L。针对高钾血症的护理措施包括", "options": {"A": "禁止摄入含钾食物和药物", "B": "静脉注射10%葡萄糖酸钙", "C": "静脉滴注胰岛素+葡萄糖", "D": "口服降钾树脂", "E": "紧急透析"}, "answer": "A、B、C、D、E"}, {"id": 300, "chapter": "第4-6章_消化泌尿血液", "original_id": 300, "type": "multi", "question": "肾病综合征的常见并发症包括", "options": {"A": "感染", "B": "血栓及栓塞", "C": "急性肾损伤", "D": "蛋白质及脂肪代谢紊乱", "E": "心力衰竭"}, "answer": "A、B、C、D"}, {"id": 301, "chapter": "第4-6章_消化泌尿血液", "original_id": 301, "type": "multi", "question": "急性肾小球肾炎的典型表现包括", "options": {"A": "血尿", "B": "蛋白尿", "C": "水肿", "D": "高血压", "E": "一过性肾功能不全"}, "answer": "A、B、C、D、E"}, {"id": 302, "chapter": "第4-6章_消化泌尿血液", "original_id": 302, "type": "multi", "question": "慢性肾衰竭患者钙磷代谢紊乱表现为", "options": {"A": "低钙血症", "B": "高磷血症", "C": "活性维生素D₃减少", "D": "继发性甲状旁腺功能亢进", "E": "高钙血症"}, "answer": "A、B、C、D"}, {"id": 303, "chapter": "第4-6章_消化泌尿血液", "original_id": 303, "type": "multi", "question": "血液透析的常见并发症包括", "options": {"A": "低血压", "B": "肌肉痉挛", "C": "失衡综合征", "D": "致热源反应", "E": "出血"}, "answer": "A、B、C、D、E"}, {"id": 304, "chapter": "第4-6章_消化泌尿血液", "original_id": 304, "type": "multi", "question": "关于尿路感染的护理措施，正确的有", "options": {"A": "急性期注意休息", "B": "鼓励多饮水，每日>2000ml", "C": "保持会阴部清洁", "D": "抗生素症状消失后立即停药", "E": "碱化尿液可减轻膀胱刺激症状"}, "answer": "A、B、C、E"}, {"id": 305, "chapter": "第4-6章_消化泌尿血液", "original_id": 305, "type": "multi", "question": "关于肾小球肾炎患者使用糖皮质激素的原则，正确的有", "options": {"A": "起始量要足", "B": "用药时间要长", "C": "减量要慢", "D": "维持时间要长", "E": "症状缓解后立即停药"}, "answer": "A、B、C、D"}, {"id": 306, "chapter": "第4-6章_消化泌尿血液", "original_id": 306, "type": "multi", "question": "腹膜透析的禁忌证包括", "options": {"A": "腹膜炎", "B": "腹腔内肿瘤", "C": "严重腹部外伤", "D": "严重肺功能不全", "E": "晚期妊娠"}, "answer": "A、B、C、D、E"}, {"id": 307, "chapter": "第4-6章_消化泌尿血液", "original_id": 307, "type": "multi", "question": "慢性肾脏病患者健康教育的内容包括", "options": {"A": "饮食指导", "B": "药物使用注意事项", "C": "避免使用肾毒性药物", "D": "自我监测血压、体重、尿量", "E": "预防感染"}, "answer": "A、B、C、D、E"}, {"id": 308, "chapter": "第4-6章_消化泌尿血液", "original_id": 308, "type": "multi", "question": "肾移植术后排斥反应的分类包括", "options": {"A": "超急性排斥反应", "B": "加速性排斥反应", "C": "急性排斥反应", "D": "慢性排斥反应", "E": "亚急性排斥反应"}, "answer": "A、B、C、D"}, {"id": 309, "chapter": "第4-6章_消化泌尿血液", "original_id": 309, "type": "multi", "question": "留置导尿管患者的护理要点包括", "options": {"A": "保持引流通畅", "B": "引流袋低于膀胱水平", "C": "定期更换导尿管", "D": "每日进行会阴护理", "E": "鼓励患者多饮水"}, "answer": "A、B、C、D、E"}, {"id": 310, "chapter": "第4-6章_消化泌尿血液", "original_id": 310, "type": "multi", "question": "急性肾损伤多尿期的护理要点包括", "options": {"A": "密切观察尿量变化", "B": "注意补液量，量出为入", "C": "监测电解质变化", "D": "预防感染", "E": "限制蛋白质摄入"}, "answer": "A、B、C、D"}, {"id": 311, "chapter": "第4-6章_消化泌尿血液", "original_id": 311, "type": "judge", "question": "缺铁性贫血患者口服铁剂应在餐前服用以促进吸收。", "options": {"A": "正确", "B": "错误"}, "answer": "B"}, {"id": 312, "chapter": "第4-6章_消化泌尿血液", "original_id": 312, "type": "judge", "question": "再生障碍性贫血最突出的临床表现是贫血、出血和感染。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 313, "chapter": "第4-6章_消化泌尿血液", "original_id": 313, "type": "judge", "question": "特发性血小板减少性紫癜（ITP）患者骨髓检查示巨核细胞数量减少。", "options": {"A": "正确", "B": "错误"}, "answer": "B"}, {"id": 314, "chapter": "第4-6章_消化泌尿血液", "original_id": 314, "type": "judge", "question": "过敏性紫癜属于血小板数量异常引起的出血性疾病。", "options": {"A": "正确", "B": "错误"}, "answer": "B"}, {"id": 315, "chapter": "第4-6章_消化泌尿血液", "original_id": 315, "type": "judge", "question": "弥散性血管内凝血（DIC）最常见的病因是感染。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 316, "chapter": "第4-6章_消化泌尿血液", "original_id": 316, "type": "judge", "question": "白血病患者化疗期间出现口腔溃疡时，应使用软毛牙刷并予口腔护理。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 317, "chapter": "第4-6章_消化泌尿血液", "original_id": 317, "type": "judge", "question": "造血干细胞移植后最严重的并发症是移植物抗宿主病（GVHD）。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 318, "chapter": "第4-6章_消化泌尿血液", "original_id": 318, "type": "judge", "question": "巨幼细胞性贫血是由于缺乏维生素B₁₂和/或叶酸引起的。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 319, "chapter": "第4-6章_消化泌尿血液", "original_id": 319, "type": "single", "question": "顾某，女，30岁。近半年来月经量明显增多，伴头晕、乏力、心悸。查体：面色苍白，睑结膜苍白，心率96次/分。实验室检查：Hb 65g/L，MCV 70fl，MCH 25pg，MCHC 29%，血清铁蛋白10μg/L。该患者最可能的诊断是", "options": {"A": "巨幼细胞性贫血", "B": "缺铁性贫血", "C": "再生障碍性贫血", "D": "溶血性贫血", "E": "慢性病性贫血"}, "answer": "B"}, {"id": 320, "chapter": "第4-6章_消化泌尿血液", "original_id": 320, "type": "single", "question": "姜某，男，65岁。反复上腹不适半年，近1个月加重伴黑便。查体：面色苍白，消瘦。实验室检查：Hb 72g/L，MCV 76fl，MCH 26pg。粪便隐血(+++)。胃镜示胃窦部溃疡。该患者贫血的最可能原因是", "options": {"A": "营养不良", "B": "慢性失血导致缺铁性贫血", "C": "再生障碍性贫血", "D": "骨髓增生异常综合征", "E": "巨幼细胞性贫血"}, "answer": "B"}, {"id": 321, "chapter": "第4-6章_消化泌尿血液", "original_id": 321, "type": "single", "question": "秦某，女，45岁。因\"再生障碍性贫血\"入院。近1周来反复鼻出血、牙龈出血，皮肤散在瘀点瘀斑。实验室检查：Hb 52g/L，WBC 1.8×10⁹/L，PLT 12×10⁹/L。护士对该患者进行护理时应特别注意", "options": {"A": "加强营养", "B": "预防颅内出血", "C": "促进铁吸收", "D": "增加活动量", "E": "给予高蛋白饮食"}, "answer": "B"}, {"id": 322, "chapter": "第4-6章_消化泌尿血液", "original_id": 322, "type": "single", "question": "邓某，女，22岁。反复皮肤瘀点、瘀斑及月经量增多1年。实验室检查：PLT 28×10⁹/L，骨髓检查示巨核细胞增多，以幼稚型巨核细胞为主，产板型巨核细胞减少。该患者最可能的诊断是", "options": {"A": "再生障碍性贫血", "B": "过敏性紫癜", "C": "特发性血小板减少性紫癜", "D": "弥散性血管内凝血", "E": "血栓性血小板减少性紫癜"}, "answer": "C"}, {"id": 323, "chapter": "第4-6章_消化泌尿血液", "original_id": 323, "type": "single", "question": "白某，女，8岁。双下肢出现对称性紫癜3天，紫癜略高出皮面，压之不退色，伴关节肿痛、腹痛。血小板计数正常，出凝血时间正常。尿常规：红细胞(++)，蛋白(+)。该患者最可能的诊断是", "options": {"A": "特发性血小板减少性紫癜", "B": "过敏性紫癜", "C": "弥散性血管内凝血", "D": "再生障碍性贫血", "E": "血友病"}, "answer": "B"}, {"id": 324, "chapter": "第4-6章_消化泌尿血液", "original_id": 324, "type": "single", "question": "邹某，男，48岁。诊断为\"急性白血病\"，行DA方案（柔红霉素+阿糖胞苷）化疗第5天。血常规示：WBC 0.8×10⁹/L，ANC 0.3×10⁹/L，PLT 25×10⁹/L，Hb 68g/L。今晨体温39.2℃。该患者目前最关键的护理措施是", "options": {"A": "给予高热量饮食", "B": "预防和控制感染", "C": "预防出血", "D": "纠正贫血", "E": "心理护理"}, "answer": "B"}, {"id": 325, "chapter": "第4-6章_消化泌尿血液", "original_id": 325, "type": "single", "question": "廖某，女，38岁。被诊断为\"系统性红斑狼疮\"合并贫血。实验室检查：Hb 78g/L，MCV 92fl，网织红细胞8.5%，血清胆红素升高，Coombs试验阳性。该患者贫血的类型最可能是", "options": {"A": "缺铁性贫血", "B": "巨幼细胞性贫血", "C": "自身免疫性溶血性贫血", "D": "再生障碍性贫血", "E": "慢性病性贫血"}, "answer": "C"}, {"id": 326, "chapter": "第4-6章_消化泌尿血液", "original_id": 326, "type": "single", "question": "武某，男，55岁。牙龈出血不止2周，伴皮肤瘀斑。实验室检查：PT 28秒（对照12秒），APTT 65秒（对照35秒），FIB 0.8g/L，D-二聚体>20mg/L，PLT 45×10⁹/L。外周血涂片可见红细胞碎片。该患者最可能的诊断是", "options": {"A": "特发性血小板减少性紫癜", "B": "弥散性血管内凝血", "C": "血友病", "D": "再生障碍性贫血", "E": "急性白血病"}, "answer": "B"}, {"id": 327, "chapter": "第4-6章_消化泌尿血液", "original_id": 327, "type": "single", "question": "石某，男，12岁。反复关节肿痛出血8年，每次轻微外伤后关节肿胀明显，持续时间较长。实验室检查：APTT明显延长，PT正常，FⅧ:C 3%。该患者最可能的诊断是", "options": {"A": "血管性血友病", "B": "血友病A", "C": "血友病B", "D": "DIC", "E": "ITP"}, "answer": "B"}, {"id": 328, "chapter": "第4-6章_消化泌尿血液", "original_id": 328, "type": "single", "question": "崔某，女，52岁。乏力、面色苍白6个月，伴舌痛、手足麻木感。实验室检查：Hb 68g/L，MCV 120fl，MCH 40pg。血清维生素B₁₂ 80pg/ml（正常>200pg/ml）。该患者首选的治疗药物是", "options": {"A": "硫酸亚铁", "B": "叶酸", "C": "维生素B₁₂肌内注射", "D": "促红细胞生成素", "E": "雄激素"}, "answer": "C"}, {"id": 329, "chapter": "第4-6章_消化泌尿血液", "original_id": 329, "type": "single", "question": "段某，男，40岁。确诊\"慢性粒细胞白血病\"，口服伊马替尼治疗。护士对其进行用药指导，正确的是", "options": {"A": "药物应与食物同服", "B": "出现轻微水肿无需处理", "C": "应定期监测血常规和肝功能", "D": "症状缓解后可自行停药", "E": "服药期间无需监测任何指标"}, "answer": "C"}, {"id": 330, "chapter": "第4-6章_消化泌尿血液", "original_id": 330, "type": "single", "question": "邢某，女，28岁。因\"急性白血病\"行异基因造血干细胞移植。移植后第15天出现皮疹、腹泻（水样便每日800ml）、黄疸。该患者最可能发生了", "options": {"A": "预处理毒性反应", "B": "急性移植物抗宿主病", "C": "慢性移植物抗宿主病", "D": "移植后感染", "E": "肝静脉闭塞病"}, "answer": "B"}, {"id": 331, "chapter": "第4-6章_消化泌尿血液", "original_id": 331, "type": "single", "question": "缺铁性贫血患者口服铁剂治疗时，能促进铁吸收的物质是", "options": {"A": "茶", "B": "牛奶", "C": "维生素C", "D": "咖啡", "E": "抗酸药"}, "answer": "C"}, {"id": 332, "chapter": "第4-6章_消化泌尿血液", "original_id": 332, "type": "single", "question": "再生障碍性贫血的治疗首选药物是", "options": {"A": "糖皮质激素", "B": "雄激素", "C": "免疫球蛋白", "D": "造血生长因子", "E": "铁剂"}, "answer": "B"}, {"id": 333, "chapter": "第4-6章_消化泌尿血液", "original_id": 333, "type": "single", "question": "过敏性紫癜与特发性血小板减少性紫癜最重要的鉴别点是", "options": {"A": "发病年龄", "B": "出血部位", "C": "血小板计数", "D": "出血时间", "E": "凝血时间"}, "answer": "C"}, {"id": 334, "chapter": "第4-6章_消化泌尿血液", "original_id": 334, "type": "single", "question": "DIC高凝期首选的治疗药物是", "options": {"A": "止血药", "B": "肝素", "C": "纤溶药物", "D": "补充凝血因子", "E": "糖皮质激素"}, "answer": "B"}, {"id": 335, "chapter": "第4-6章_消化泌尿血液", "original_id": 335, "type": "single", "question": "白血病患者化疗期间出现肿瘤溶解综合征，最危险的代谢紊乱是", "options": {"A": "低钾血症", "B": "高尿酸血症", "C": "高磷血症", "D": "高钾血症", "E": "低钙血症"}, "answer": "D"}, {"id": 336, "chapter": "第4-6章_消化泌尿血液", "original_id": 336, "type": "single", "question": "缺铁性贫血患者铁剂治疗有效的最早表现是", "options": {"A": "血红蛋白升高", "B": "红细胞计数增加", "C": "网织红细胞升高", "D": "面色改善", "E": "血清铁蛋白升高"}, "answer": "C"}, {"id": 337, "chapter": "第4-6章_消化泌尿血液", "original_id": 337, "type": "single", "question": "慢性淋巴细胞白血病最常见的首发症状是", "options": {"A": "发热", "B": "出血", "C": "无痛性淋巴结肿大", "D": "骨痛", "E": "贫血"}, "answer": "C"}, {"id": 338, "chapter": "第4-6章_消化泌尿血液", "original_id": 338, "type": "single", "question": "血友病A患者出血时应避免的治疗措施是", "options": {"A": "输注冷沉淀", "B": "输注新鲜冰冻血浆", "C": "输注重组FⅧ", "D": "肌内注射止血药", "E": "局部压迫止血"}, "answer": "D"}, {"id": 339, "chapter": "第4-6章_消化泌尿血液", "original_id": 339, "type": "single", "question": "造血干细胞移植前预处理的主要目的不包括", "options": {"A": "抑制受者免疫功能", "B": "清除体内残留的肿瘤细胞", "C": "为供者干细胞\"腾出空间\"", "D": "预防感染", "E": "促进植入"}, "answer": "D"}, {"id": 340, "chapter": "第4-6章_消化泌尿血液", "original_id": 340, "type": "single", "question": "淋巴瘤患者最典型的临床表现是", "options": {"A": "发热", "B": "无痛性进行性淋巴结肿大", "C": "消瘦", "D": "皮肤瘙痒", "E": "盗汗"}, "answer": "B"}, {"id": 341, "chapter": "第4-6章_消化泌尿血液", "original_id": 341, "type": "single", "question": "溶血性贫血患者黄疸的主要原因是", "options": {"A": "肝细胞损伤", "B": "胆道梗阻", "C": "红细胞破坏增多导致胆红素升高", "D": "肝内胆汁淤积", "E": "药物性肝损伤"}, "answer": "C"}, {"id": 342, "chapter": "第4-6章_消化泌尿血液", "original_id": 342, "type": "single", "question": "关于白血病患者的口腔护理，错误的是", "options": {"A": "使用软毛牙刷", "B": "口腔溃疡时可用碳酸氢钠溶液漱口", "C": "口腔护理动作应轻柔", "D": "有出血倾向时可使用牙线", "E": "真菌感染时可用制霉菌素涂敷"}, "answer": "D"}, {"id": 343, "chapter": "第4-6章_消化泌尿血液", "original_id": 343, "type": "single", "question": "贫血患者最常见的护理诊断是", "options": {"A": "活动无耐力", "B": "有感染的危险", "C": "有出血的危险", "D": "营养失调", "E": "知识缺乏"}, "answer": "A"}, {"id": 344, "chapter": "第4-6章_消化泌尿血液", "original_id": 344, "type": "multi", "question": "叶某，女，56岁。有\"风湿性心脏病\"病史。自诉心慌。心电图:P波消失，代之以间距、振幅不等的颤动波，QRS波正常，心室率120次/分，R-R间距绝对不等。因长期口服华法林抗凝，今查INR 5.8，全身皮肤散在出血点。针对该患者使用华法林过量的护理措施包括", "options": {"A": "立即停用华法林", "B": "遵医嘱给予维生素K₁", "C": "密切监测凝血功能", "D": "观察有无内脏出血征象", "E": "必要时输注新鲜冰冻血浆"}, "answer": "A、B、C、D、E"}, {"id": 345, "chapter": "第4-6章_消化泌尿血液", "original_id": 345, "type": "multi", "question": "杜某，男，35岁。确诊\"急性髓系白血病\"，行HA方案化疗。化疗期间血常规示WBC 0.5×10⁹/L，ANC 0.2×10⁹/L。针对该患者粒细胞缺乏期的护理措施正确的有", "options": {"A": "入住层流病房", "B": "严格限制探视", "C": "每日口腔护理4次", "D": "监测体温变化", "E": "预防性使用抗生素"}, "answer": "A、B、C、D、E"}, {"id": 346, "chapter": "第4-6章_消化泌尿血液", "original_id": 346, "type": "multi", "question": "蔡某，女，18岁。确诊\"缺铁性贫血\"，给予硫酸亚铁口服治疗。护士指导患者服用铁剂的注意事项包括", "options": {"A": "餐后服用以减少胃肠道刺激", "B": "同时服用维生素C促进吸收", "C": "避免与茶、牛奶同服", "D": "服药期间大便可呈黑色", "E": "液体铁剂可用吸管服用以避免牙齿染色"}, "answer": "A、B、C、D、E"}, {"id": 347, "chapter": "第4-6章_消化泌尿血液", "original_id": 347, "type": "multi", "question": "尹某，男，50岁。淋巴瘤化疗后出现骨髓抑制，WBC 1.0×10⁹/L，PLT 30×10⁹/L。针对该患者的护理措施正确的有", "options": {"A": "监测血常规变化", "B": "避免去人群密集场所", "C": "使用软毛牙刷", "D": "避免肌肉注射", "E": "观察有无发热、出血征象"}, "answer": "A、B、C、D、E"}, {"id": 348, "chapter": "第4-6章_消化泌尿血液", "original_id": 348, "type": "multi", "question": "管某，女，32岁。诊断为\"系统性红斑狼疮\"，长期口服糖皮质激素，出现药物性库欣综合征。该患者目前需要监测的指标有", "options": {"A": "血糖", "B": "血压", "C": "电解质", "D": "血常规", "E": "骨密度"}, "answer": "A、B、C、D、E"}, {"id": 349, "chapter": "第4-6章_消化泌尿血液", "original_id": 349, "type": "multi", "question": "缺铁性贫血的实验室检查特点包括", "options": {"A": "小细胞低色素性贫血", "B": "血清铁降低", "C": "总铁结合力升高", "D": "血清铁蛋白降低", "E": "骨髓铁染色示细胞外铁增加"}, "answer": "A、B、C、D"}, {"id": 350, "chapter": "第4-6章_消化泌尿血液", "original_id": 350, "type": "multi", "question": "再生障碍性贫血的诊断标准包括", "options": {"A": "全血细胞减少", "B": "网织红细胞绝对值降低", "C": "骨髓增生减低", "D": "一般无肝脾淋巴结肿大", "E": "骨髓中非造血细胞增多"}, "answer": "A、B、C、D、E"}, {"id": 351, "chapter": "第4-6章_消化泌尿血液", "original_id": 351, "type": "multi", "question": "ITP患者的临床表现特点包括", "options": {"A": "皮肤黏膜出血", "B": "内脏出血少见", "C": "脾脏一般不增大或仅轻度增大", "D": "骨髓巨核细胞增多但成熟障碍", "E": "血小板寿命缩短"}, "answer": "A、B、C、D、E"}, {"id": 352, "chapter": "第4-6章_消化泌尿血液", "original_id": 352, "type": "multi", "question": "弥散性血管内凝血（DIC）的临床表现包括", "options": {"A": "出血", "B": "休克", "C": "微血管栓塞", "D": "微血管病性溶血", "E": "多器官功能障碍"}, "answer": "A、B、C、D、E"}, {"id": 353, "chapter": "第4-6章_消化泌尿血液", "original_id": 353, "type": "multi", "question": "溶血性贫血的临床表现包括", "options": {"A": "贫血", "B": "黄疸", "C": "脾大", "D": "血红蛋白尿", "E": "网织红细胞增高"}, "answer": "A、B、C、D、E"}, {"id": 354, "chapter": "第4-6章_消化泌尿血液", "original_id": 354, "type": "multi", "question": "急性白血病患者化疗期间发生感染的常见部位有", "options": {"A": "口腔", "B": "肺部", "C": "肛周", "D": "泌尿系", "E": "皮肤"}, "answer": "A、B、C、D、E"}, {"id": 355, "chapter": "第4-6章_消化泌尿血液", "original_id": 355, "type": "multi", "question": "关于造血干细胞移植的护理，正确的有", "options": {"A": "术前做好心理护理", "B": "预处理期间密切观察不良反应", "C": "干细胞输注时注意观察过敏反应", "D": "术后严格隔离防护", "E": "密切观察GVHD征象"}, "answer": "A、B、C、D、E"}, {"id": 356, "chapter": "第4-6章_消化泌尿血液", "original_id": 356, "type": "multi", "question": "过敏性紫癜的护理措施包括", "options": {"A": "急性期卧床休息", "B": "避免接触过敏原", "C": "观察皮疹变化", "D": "监测尿常规", "E": "给予高蛋白质、高维生素饮食"}, "answer": "A、B、C、D、E"}, {"id": 357, "chapter": "第4-6章_消化泌尿血液", "original_id": 357, "type": "multi", "question": "巨幼细胞性贫血的特点包括", "options": {"A": "大细胞性贫血", "B": "可有神经系统症状（维生素B₁₂缺乏时）", "C": "骨髓示巨幼样变", "D": "血清维生素B₁₂或叶酸降低", "E": "多见于青少年"}, "answer": "A、B、C、D"}, {"id": 358, "chapter": "第4-6章_消化泌尿血液", "original_id": 358, "type": "multi", "question": "DIC的实验室检查特点包括", "options": {"A": "血小板减少", "B": "PT延长", "C": "FIB降低", "D": "D-二聚体升高", "E": "外周血可见破碎红细胞"}, "answer": "A、B、C、D、E"}, {"id": 359, "chapter": "第4-6章_消化泌尿血液", "original_id": 359, "type": "multi", "question": "关于出血性疾病患者的健康教育，正确的有", "options": {"A": "避免使用抗血小板药物", "B": "学会自我观察出血征象", "C": "避免剧烈运动和外伤", "D": "定期复查血常规和凝血功能", "E": "有出血倾向时可用牙签剔牙"}, "answer": "A、B、C、D"}, {"id": 360, "chapter": "第4-6章_消化泌尿血液", "original_id": 360, "type": "multi", "question": "关于白血病化疗药物的不良反应，正确的有", "options": {"A": "柔红霉素可引起心脏毒性", "B": "阿糖胞苷可引起小脑毒性", "C": "甲氨蝶呤可引起口腔溃疡", "D": "环磷酰胺可引起出血性膀胱炎", "E": "长春新碱可引起周围神经炎"}, "answer": "A、B、C、D、E"}, {"id": 361, "chapter": "第7-9章_内分泌风湿神经", "original_id": 361, "type": "judge", "question": "甲状腺功能亢进症病人出现突眼时，应嘱其睡眠时取平卧位，以减轻眼部水肿。", "options": {"A": "正确", "B": "错误"}, "answer": "B"}, {"id": 362, "chapter": "第7-9章_内分泌风湿神经", "original_id": 362, "type": "judge", "question": "糖尿病酮症酸中毒病人呼吸中可出现烂苹果味，系酮体中丙酮经呼吸道排出所致。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 363, "chapter": "第7-9章_内分泌风湿神经", "original_id": 363, "type": "judge", "question": "胰岛素注射部位应规律轮换，同一部位相邻两次注射点间距至少1cm，以避免皮下脂肪萎缩或增生。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 364, "chapter": "第7-9章_内分泌风湿神经", "original_id": 364, "type": "judge", "question": "痛风急性发作期应鼓励病人多饮水，每日饮水量应达到2000mL以上，以促进尿酸排泄。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 365, "chapter": "第7-9章_内分泌风湿神经", "original_id": 365, "type": "judge", "question": "皮质醇增多症（Cushing综合征）病人因蛋白质分解代谢增强，应给予高蛋白饮食以补充消耗。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 366, "chapter": "第7-9章_内分泌风湿神经", "original_id": 366, "type": "judge", "question": "口服葡萄糖耐量试验（OGTT）中，服糖后2小时血糖≥7.8mmol/L且<11.1mmol/L即可诊断为糖尿病。", "options": {"A": "正确", "B": "错误"}, "answer": "B"}, {"id": 367, "chapter": "第7-9章_内分泌风湿神经", "original_id": 367, "type": "single", "question": "廖某，女，28岁。近2个月来出现怕热、多汗、心悸、食欲亢进但体重下降约8kg，查体见甲状腺Ⅱ度肿大，可闻及血管杂音。心率118次/分，双手细颤阳性。该病人最可能的诊断是", "options": {"A": "单纯性甲状腺肿", "B": "甲状腺功能亢进症", "C": "甲状腺癌", "D": "亚急性甲状腺炎", "E": "桥本甲状腺炎"}, "answer": "B"}, {"id": 368, "chapter": "第7-9章_内分泌风湿神经", "original_id": 368, "type": "single", "question": "甲状腺功能亢进症病人使用丙硫氧嘧啶治疗期间，护士应重点观察的不良反应是", "options": {"A": "甲状腺功能低下", "B": "粒细胞减少", "C": "胃肠道反应", "D": "肝功能损害", "E": "皮疹"}, "answer": "B"}, {"id": 369, "chapter": "第7-9章_内分泌风湿神经", "original_id": 369, "type": "single", "question": "甲亢危象病人高热时，不宜使用的降温措施是", "options": {"A": "物理降温", "B": "人工冬眠", "C": "乙酰水杨酸类退热药", "D": "冰袋冷敷大血管处", "E": "降低室温"}, "answer": "C"}, {"id": 370, "chapter": "第7-9章_内分泌风湿神经", "original_id": 370, "type": "single", "question": "刘某，女，42岁。因甲亢行甲状腺次全切除术。术后返回病房，护士发现其饮水时出现呛咳，最可能的原因是", "options": {"A": "喉返神经损伤", "B": "喉上神经外支损伤", "C": "喉上神经内支损伤", "D": "甲状旁腺损伤", "E": "甲状腺危象先兆"}, "answer": "C"}, {"id": 371, "chapter": "第7-9章_内分泌风湿神经", "original_id": 371, "type": "single", "question": "Graves病病人突眼的主要发病机制是", "options": {"A": "甲状腺激素分泌过多导致眼球后组织水肿", "B": "自身免疫反应导致球后组织黏液性水肿和脂肪增生", "C": "交感神经兴奋性增高导致眼外肌收缩", "D": "甲状腺肿大压迫眶内组织", "E": "长期高代谢导致眶内脂肪消耗减少"}, "answer": "B"}, {"id": 372, "chapter": "第7-9章_内分泌风湿神经", "original_id": 372, "type": "single", "question": "陈某，女，52岁。近半年来出现畏寒、乏力、嗜睡、体重增加、便秘。查体：体温35.8℃，颜面水肿，表情淡漠，皮肤干燥粗糙，心率56次/分。血清TSH升高，FT4降低。该病人最可能的诊断是", "options": {"A": "甲状腺功能亢进症", "B": "甲状腺功能减退症", "C": "单纯性甲状腺肿", "D": "甲状腺腺瘤", "E": "亚急性甲状腺炎"}, "answer": "B"}, {"id": 373, "chapter": "第7-9章_内分泌风湿神经", "original_id": 373, "type": "single", "question": "周某，男，55岁。近半年来出现满月脸，水牛背，腹部及大腿内侧见紫纹，血压160/100mmHg，空腹血糖8.2mmol/L，血皮质醇昼夜节律消失。最可能的诊断是", "options": {"A": "甲状腺功能亢进症", "B": "嗜铬细胞瘤", "C": "皮质醇增多症（Cushing综合征）", "D": "原发性醛固酮增多症", "E": "肢端肥大症"}, "answer": "C"}, {"id": 374, "chapter": "第7-9章_内分泌风湿神经", "original_id": 374, "type": "single", "question": "Cushing综合征病人出现低钾性碱中毒的主要原因是", "options": {"A": "肾脏排钾增多", "B": "呕吐丢失钾离子", "C": "摄入钾不足", "D": "皮质醇增多促进肾脏保钠排钾", "E": "腹泻丢失钾离子"}, "answer": "D"}, {"id": 375, "chapter": "第7-9章_内分泌风湿神经", "original_id": 375, "type": "single", "question": "郭某，女，40岁。反复发作性高血压，最高达220/120mmHg，伴头痛、心悸、多汗。发作时尿儿茶酚胺明显升高。CT示左侧肾上腺占位。该病人高血压发作时首选的降压药物是", "options": {"A": "硝普钠", "B": "酚妥拉明", "C": "卡托普利", "D": "美托洛尔", "E": "硝苯地平"}, "answer": "B"}, {"id": 376, "chapter": "第7-9章_内分泌风湿神经", "original_id": 376, "type": "single", "question": "嗜铬细胞瘤病人在进行肿瘤切除术前，护士应特别注意的护理措施是", "options": {"A": "限制液体摄入", "B": "术前充分扩容，鼓励高钠饮食", "C": "给予高蛋白低热量饮食", "D": "绝对卧床休息", "E": "术前禁食12小时"}, "answer": "B"}, {"id": 377, "chapter": "第7-9章_内分泌风湿神经", "original_id": 377, "type": "single", "question": "范某，男，45岁。身高175cm，体重60kg。因肺部感染诱发酮症酸中毒，急诊入院。该病人应每小时泵入胰岛素", "options": {"A": "1～2U", "B": "4～6U", "C": "8～10U", "D": "12～16U", "E": "20～24U"}, "answer": "B"}, {"id": 378, "chapter": "第7-9章_内分泌风湿神经", "original_id": 378, "type": "single", "question": "糖尿病酮症酸中毒病人补液治疗时，首先应选用的液体是", "options": {"A": "5%葡萄糖注射液", "B": "10%葡萄糖注射液", "C": "0.9%氯化钠注射液", "D": "5%碳酸氢钠注射液", "E": "林格液"}, "answer": "C"}, {"id": 379, "chapter": "第7-9章_内分泌风湿神经", "original_id": 379, "type": "single", "question": "吴某，男，62岁。2型糖尿病病史10年，长期使用胰岛素治疗。某日凌晨出现头晕、心悸、出冷汗、饥饿感，测血糖2.8mmol/L。此时最紧急的处理措施是", "options": {"A": "立即皮下注射胰岛素", "B": "立即口服或静脉补充葡萄糖", "C": "给予高蛋白饮食", "D": "加快胰岛素泵入速度", "E": "嘱其卧床休息，继续观察"}, "answer": "B"}, {"id": 380, "chapter": "第7-9章_内分泌风湿神经", "original_id": 380, "type": "single", "question": "张某，女，72岁。2型糖尿病史15年，近1周来出现多尿、多饮加重，伴严重脱水表现。急查血糖38.5mmol/L，血钠155mmol/L，血浆渗透压345mOsm/L，尿酮体阴性。该病人最可能的诊断是", "options": {"A": "糖尿病酮症酸中毒", "B": "糖尿病高渗性昏迷", "C": "乳酸性酸中毒", "D": "低血糖昏迷", "E": "脑卒中"}, "answer": "B"}, {"id": 381, "chapter": "第7-9章_内分泌风湿神经", "original_id": 381, "type": "single", "question": "何某，女，35岁。被诊断为1型糖尿病，目前使用胰岛素强化治疗方案（三餐前注射门冬胰岛素，睡前注射甘精胰岛素）。下列胰岛素注射时间正确的是", "options": {"A": "餐前即刻注射门冬胰岛素", "B": "餐后立即注射门冬胰岛素", "C": "睡前注射门冬胰岛素", "D": "三餐前注射甘精胰岛素", "E": "餐前注射甘精胰岛素"}, "answer": "A"}, {"id": 382, "chapter": "第7-9章_内分泌风湿神经", "original_id": 382, "type": "single", "question": "秦某，女，30岁。Graves病史2年，抗甲状腺药物治疗效果不佳，拟行¹³¹I治疗。护士应告知病人治疗前需禁食含碘食物至少", "options": {"A": "3天", "B": "1周", "C": "2周", "D": "4周", "E": "6周"}, "answer": "C"}, {"id": 383, "chapter": "第7-9章_内分泌风湿神经", "original_id": 383, "type": "single", "question": "马某，男，58岁。2型糖尿病12年，近期查尿微量白蛋白220mg/24h，肾功能正常。该病人目前最可能处于糖尿病肾病的哪个阶段", "options": {"A": "Ⅰ期", "B": "Ⅱ期", "C": "Ⅲ期", "D": "Ⅳ期", "E": "Ⅴ期"}, "answer": "C"}, {"id": 384, "chapter": "第7-9章_内分泌风湿神经", "original_id": 384, "type": "single", "question": "蔡某，男，48岁。夜间突发右足第一跖趾关节剧烈疼痛，局部红肿发热，血尿酸620μmol/L。诊断为痛风急性发作。首选的治疗药物是", "options": {"A": "别嘌醇", "B": "苯溴马隆", "C": "秋水仙碱", "D": "丙磺舒", "E": "非布司他"}, "answer": "C"}, {"id": 385, "chapter": "第7-9章_内分泌风湿神经", "original_id": 385, "type": "single", "question": "王某，女，65岁。绝经15年。近1年来出现腰背部疼痛，身高缩短3cm。骨密度检查T值为-2.8。X线示胸椎压缩性骨折。该病人最主要的治疗和护理目标是", "options": {"A": "缓解疼痛", "B": "预防跌倒", "C": "增加体重", "D": "降低血糖", "E": "改善睡眠"}, "answer": "B"}, {"id": 386, "chapter": "第7-9章_内分泌风湿神经", "original_id": 386, "type": "single", "question": "郑某，女，50岁。2型糖尿病史8年，近半年来自觉双足趾端麻木，呈袜套样感觉减退，足背动脉搏动减弱。护士进行健康教育时，应告知病人避免的危险行为是", "options": {"A": "每天检查足部皮肤", "B": "用热水袋温暖双足或泡脚", "C": "穿宽松舒适的鞋袜", "D": "定期修剪趾甲", "E": "适当进行步行运动"}, "answer": "B"}, {"id": 387, "chapter": "第7-9章_内分泌风湿神经", "original_id": 387, "type": "single", "question": "谢某，男，28岁。1型糖尿病，使用胰岛素泵治疗。护士应指导其每隔多长时间更换一次注射部位", "options": {"A": "1～2天", "B": "2～3天", "C": "4～5天", "D": "5～7天", "E": "7～10天"}, "answer": "B"}, {"id": 388, "chapter": "第7-9章_内分泌风湿神经", "original_id": 388, "type": "single", "question": "糖尿病高渗性昏迷的特点不包括", "options": {"A": "多见于老年2型糖尿病患者", "B": "血糖常>33.3mmol/L", "C": "血渗透压常>330mOsm/L", "D": "酮症明显，酸中毒为主", "E": "脱水严重，可出现休克"}, "answer": "D"}, {"id": 389, "chapter": "第7-9章_内分泌风湿神经", "original_id": 389, "type": "single", "question": "糖化血红蛋白（HbA1c）反映的是糖尿病患者近多长时间内的平均血糖水平", "options": {"A": "1～2周", "B": "2～4周", "C": "4～8周", "D": "8～12周", "E": "6个月以上"}, "answer": "D"}, {"id": 390, "chapter": "第7-9章_内分泌风湿神经", "original_id": 390, "type": "single", "question": "口服磺脲类降糖药最常见的不良反应是", "options": {"A": "胃肠道反应", "B": "低血糖", "C": "肝功能损害", "D": "体重增加", "E": "皮肤过敏"}, "answer": "B"}, {"id": 391, "chapter": "第7-9章_内分泌风湿神经", "original_id": 391, "type": "single", "question": "双胍类降糖药最严重的不良反应是", "options": {"A": "低血糖", "B": "胃肠道反应", "C": "乳酸酸中毒", "D": "体重增加", "E": "肝肾功能损害"}, "answer": "C"}, {"id": 392, "chapter": "第7-9章_内分泌风湿神经", "original_id": 392, "type": "single", "question": "糖尿病足病人进行足部护理时，洗脚水温应控制在", "options": {"A": "30℃以下", "B": "35℃左右", "C": "37～40℃", "D": "42～45℃", "E": "50℃以上"}, "answer": "C"}, {"id": 393, "chapter": "第7-9章_内分泌风湿神经", "original_id": 393, "type": "single", "question": "痛风病人饮食指导中，应严格限制的食物是", "options": {"A": "鸡蛋、牛奶", "B": "新鲜蔬菜、水果", "C": "动物内脏、海鲜、浓肉汤", "D": "米饭、面条等主食", "E": "低脂乳制品"}, "answer": "C"}, {"id": 394, "chapter": "第7-9章_内分泌风湿神经", "original_id": 394, "type": "single", "question": "骨质疏松症患者补充钙剂时，为促进钙吸收，应同时补充", "options": {"A": "维生素B₁₂", "B": "维生素C", "C": "维生素D", "D": "叶酸", "E": "维生素K"}, "answer": "C"}, {"id": 395, "chapter": "第7-9章_内分泌风湿神经", "original_id": 395, "type": "multi", "question": "田某，男，48岁。因甲亢危象急诊入院，体温39.8℃，心率140次/分，大汗淋漓，烦躁不安。护士应立即采取的护理措施包括", "options": {"A": "物理降温", "B": "遵医嘱给予丙硫氧嘧啶", "C": "遵医嘱给予碘剂", "D": "遵医嘱给予β受体阻滞剂", "E": "给予乙酰水杨酸类药物退热"}, "answer": "A、B、C、D"}, {"id": 396, "chapter": "第7-9章_内分泌风湿神经", "original_id": 396, "type": "multi", "question": "宋某，女，60岁。2型糖尿病20年，目前使用胰岛素治疗，近日频繁出现凌晨低血糖，而空腹血糖反而升高。护士应告知病人可能的原因及处理措施包括", "options": {"A": "可能存在Somogyi效应（低血糖后反应性高血糖）", "B": "可能存在黎明现象", "C": "应监测凌晨3时血糖以鉴别", "D": "立即停用胰岛素", "E": "若为Somogyi效应应减少晚餐前胰岛素用量"}, "answer": "A、B、C、E"}, {"id": 397, "chapter": "第7-9章_内分泌风湿神经", "original_id": 397, "type": "multi", "question": "赵某，女，32岁。1型糖尿病患者，妊娠12周。该病人妊娠期的治疗注意事项包括", "options": {"A": "必须使用胰岛素控制血糖", "B": "口服降糖药可通过胎盘影响胎儿", "C": "妊娠早期胰岛素需要量可能减少", "D": "妊娠中晚期胰岛素需要量增加", "E": "产后胰岛素需要量恢复至孕前水平或减少"}, "answer": "A、B、C、D、E"}, {"id": 398, "chapter": "第7-9章_内分泌风湿神经", "original_id": 398, "type": "multi", "question": "黄某，男，52岁。痛风急性发作期，右足第一跖趾关节红肿热痛。护士应给予的健康指导包括", "options": {"A": "绝对卧床休息，抬高患肢", "B": "多饮水，每日>2000mL", "C": "避免进食高嘌呤食物", "D": "遵医嘱服用秋水仙碱", "E": "急性期可进行降尿酸治疗"}, "answer": "A、B、C、D"}, {"id": 399, "chapter": "第7-9章_内分泌风湿神经", "original_id": 399, "type": "multi", "question": "甲状腺功能亢进症病人常见的护理诊断/问题包括", "options": {"A": "营养失调：低于机体需要量", "B": "活动无耐力", "C": "体温过高", "D": "有感染的危险", "E": "自我形象紊乱"}, "answer": "A、B、C、E"}, {"id": 400, "chapter": "第7-9章_内分泌风湿神经", "original_id": 400, "type": "multi", "question": "甲状腺危象的常见诱因包括", "options": {"A": "感染", "B": "手术应激", "C": "突然停用抗甲状腺药物", "D": "精神创伤", "E": "放射性碘治疗后"}, "answer": "A、B、C、D、E"}, {"id": 401, "chapter": "第7-9章_内分泌风湿神经", "original_id": 401, "type": "multi", "question": "甲亢病人使用抗甲状腺药物期间，护士应观察和告知的内容包括", "options": {"A": "定期复查血常规，注意白细胞变化", "B": "出现发热、咽痛应立即就诊", "C": "定期复查肝功能", "D": "出现皮疹应及时报告", "E": "药物起效快，通常2周即可停药"}, "answer": "A、B、C、D"}, {"id": 402, "chapter": "第7-9章_内分泌风湿神经", "original_id": 402, "type": "multi", "question": "甲状腺功能减退症病人出现黏液性水肿昏迷的诱因包括", "options": {"A": "寒冷", "B": "感染", "C": "使用镇静剂", "D": "中断甲状腺激素替代治疗", "E": "手术应激"}, "answer": "A、B、C、D、E"}, {"id": 403, "chapter": "第7-9章_内分泌风湿神经", "original_id": 403, "type": "multi", "question": "皮质醇增多症病人的临床表现包括", "options": {"A": "向心性肥胖", "B": "高血压", "C": "低钾性碱中毒", "D": "骨质疏松", "E": "皮肤紫纹"}, "answer": "A、B、C、D、E"}, {"id": 404, "chapter": "第7-9章_内分泌风湿神经", "original_id": 404, "type": "multi", "question": "嗜铬细胞瘤病人术前护理措施包括", "options": {"A": "监测血压变化", "B": "遵医嘱给予α受体阻滞剂", "C": "限制钠盐摄入", "D": "鼓励病人高钠饮食、充分饮水扩容", "E": "避免情绪激动和腹部按压"}, "answer": "A、B、D、E"}, {"id": 405, "chapter": "第7-9章_内分泌风湿神经", "original_id": 405, "type": "multi", "question": "1型糖尿病的临床特点包括", "options": {"A": "多见于青少年", "B": "起病急，'三多一少'症状明显", "C": "胰岛素分泌绝对不足", "D": "易发生酮症酸中毒", "E": "口服降糖药治疗效果良好"}, "answer": "A、B、C、D"}, {"id": 406, "chapter": "第7-9章_内分泌风湿神经", "original_id": 406, "type": "multi", "question": "糖尿病患者发生低血糖时的临床表现包括", "options": {"A": "心悸、出汗、手颤", "B": "饥饿感", "C": "面色苍白、脉搏加快", "D": "多尿、烦渴", "E": "严重者出现意识障碍、抽搐"}, "answer": "A、B、C、E"}, {"id": 407, "chapter": "第7-9章_内分泌风湿神经", "original_id": 407, "type": "multi", "question": "糖尿病酮症酸中毒的治疗原则包括", "options": {"A": "大量补液纠正脱水", "B": "小剂量胰岛素持续静脉滴注", "C": "纠正电解质及酸碱平衡失调", "D": "积极处理诱因", "E": "立即给予大剂量胰岛素皮下注射"}, "answer": "A、B、C、D"}, {"id": 408, "chapter": "第7-9章_内分泌风湿神经", "original_id": 408, "type": "multi", "question": "糖尿病足的高危因素包括", "options": {"A": "周围神经病变", "B": "周围血管病变", "C": "足部畸形", "D": "血糖控制不佳", "E": "既往有足部溃疡史"}, "answer": "A、B、C、D、E"}, {"id": 409, "chapter": "第7-9章_内分泌风湿神经", "original_id": 409, "type": "multi", "question": "胰岛素注射的注意事项包括", "options": {"A": "注射部位应规律轮换", "B": "未开启的胰岛素应冷藏保存（2～8℃）", "C": "开启后的胰岛素可在室温（<25℃）保存28天", "D": "注射前应排气，确认针头通畅", "E": "速效胰岛素应在餐前30分钟注射"}, "answer": "A、B、C、D"}, {"id": 410, "chapter": "第7-9章_内分泌风湿神经", "original_id": 410, "type": "multi", "question": "口服葡萄糖耐量试验（OGTT）的正确操作方法包括", "options": {"A": "试验前3天每日碳水化合物摄入不少于150g", "B": "试验前禁食8～12小时", "C": "口服75g无水葡萄糖（溶于300mL水中，5分钟内饮完）", "D": "分别于空腹及服糖后2小时采血测血糖", "E": "试验期间可正常活动和进食"}, "answer": "A、B、C、D"}, {"id": 411, "chapter": "第7-9章_内分泌风湿神经", "original_id": 411, "type": "multi", "question": "痛风病人缓解期降尿酸治疗的药物包括", "options": {"A": "别嘌醇", "B": "苯溴马隆", "C": "非布司他", "D": "秋水仙碱", "E": "丙磺舒"}, "answer": "A、B、C、E"}, {"id": 412, "chapter": "第7-9章_内分泌风湿神经", "original_id": 412, "type": "multi", "question": "骨质疏松症的预防措施包括", "options": {"A": "适量补充钙剂和维生素D", "B": "适当进行负重运动", "C": "戒烟限酒", "D": "增加日照时间", "E": "长期卧床休息"}, "answer": "A、B、C、D"}, {"id": 413, "chapter": "第7-9章_内分泌风湿神经", "original_id": 413, "type": "multi", "question": "糖尿病病人的饮食治疗原则包括", "options": {"A": "控制总热量摄入", "B": "合理分配三大营养素比例", "C": "定时定量进餐", "D": "限制高纤维食物摄入", "E": "限制高脂高糖食物"}, "answer": "A、B、C、E"}, {"id": 414, "chapter": "第7-9章_内分泌风湿神经", "original_id": 414, "type": "judge", "question": "系统性红斑狼疮（SLE）病人面部蝶形红斑是其特征性的皮肤损害表现。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 415, "chapter": "第7-9章_内分泌风湿神经", "original_id": 415, "type": "judge", "question": "类风湿关节炎的关节症状以远端指间关节受累最为常见。", "options": {"A": "正确", "B": "错误"}, "answer": "B"}, {"id": 416, "chapter": "第7-9章_内分泌风湿神经", "original_id": 416, "type": "judge", "question": "强直性脊柱炎多见于青年男性，与HLA-B27基因密切相关。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 417, "chapter": "第7-9章_内分泌风湿神经", "original_id": 417, "type": "judge", "question": "干燥综合征病人主要表现为口干和眼干，不会出现内脏器官受累。", "options": {"A": "正确", "B": "错误"}, "answer": "B"}, {"id": 418, "chapter": "第7-9章_内分泌风湿神经", "original_id": 418, "type": "judge", "question": "SLE病人应避免阳光直射，外出时应采取遮阳措施，因为紫外线可诱发或加重病情。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 419, "chapter": "第7-9章_内分泌风湿神经", "original_id": 419, "type": "single", "question": "叶某，女，26岁。近3个月来面部出现蝶形红斑，伴乏力、低热。近日出现双下肢水肿。实验室检查：尿蛋白（+++），ANA阳性，抗ds-DNA抗体阳性，补体C3降低。该病人最可能的诊断是", "options": {"A": "类风湿关节炎", "B": "系统性红斑狼疮", "C": "干燥综合征", "D": "硬皮病", "E": "混合性结缔组织病"}, "answer": "B"}, {"id": 420, "chapter": "第7-9章_内分泌风湿神经", "original_id": 420, "type": "single", "question": "夏某，女，24岁。确诊SLE 1年，近日面部红斑加重，关节痛，尿蛋白（++）。实验室检查：抗ds-DNA抗体滴度升高，补体C3、C4降低。与该病人疾病活动性密切相关的指标是", "options": {"A": "ANA滴度", "B": "抗ds-DNA抗体滴度和补体C3、C4水平", "C": "类风湿因子", "D": "血沉", "E": "C反应蛋白"}, "answer": "B"}, {"id": 421, "chapter": "第7-9章_内分泌风湿神经", "original_id": 421, "type": "single", "question": "韩某，女，22岁。SLE病史2年，近日出现面部及双下肢水肿。查尿蛋白（++++），24小时尿蛋白定量3.5g，血白蛋白25g/L，血脂升高。该病人最可能的肾脏病理类型是", "options": {"A": "系膜增生性肾小球肾炎", "B": "膜性肾病", "C": "弥漫增殖性肾小球肾炎（Ⅳ型）", "D": "微小病变", "E": "局灶节段性硬化"}, "answer": "C"}, {"id": 422, "chapter": "第7-9章_内分泌风湿神经", "original_id": 422, "type": "single", "question": "程某，女，45岁。近2年来反复出现双手近端指间关节和掌指关节对称性肿痛，伴晨僵持续约2小时。查体可见双手天鹅颈样畸形。X线示关节间隙变窄。该病人最可能的诊断是", "options": {"A": "骨关节炎", "B": "类风湿关节炎", "C": "痛风性关节炎", "D": "强直性脊柱炎", "E": "银屑病关节炎"}, "answer": "B"}, {"id": 423, "chapter": "第7-9章_内分泌风湿神经", "original_id": 423, "type": "single", "question": "苏某，女，50岁。类风湿关节炎10年，双手呈天鹅颈样畸形。每日晨起后双手关节僵硬感明显，持续约2小时后方可缓解。关于该病人的晨僵护理，不正确的措施是", "options": {"A": "晨起后用温水浸泡僵硬关节", "B": "夜间可戴弹力手套保暖", "C": "急性期进行高强度关节负重训练", "D": "适当进行关节活动锻炼", "E": "用热水袋热敷僵硬关节"}, "answer": "C"}, {"id": 424, "chapter": "第7-9章_内分泌风湿神经", "original_id": 424, "type": "single", "question": "方某，男，40岁。类风湿关节炎5年，长期口服甲氨蝶呤和来氟米特治疗。近日出现口腔溃疡、恶心。护士应告知其使用免疫抑制剂期间应定期监测", "options": {"A": "血糖", "B": "血压", "C": "血常规和肝功能", "D": "肾功能", "E": "心电图"}, "answer": "C"}, {"id": 425, "chapter": "第7-9章_内分泌风湿神经", "original_id": 425, "type": "single", "question": "何某，男，25岁。近1年来反复出现腰背部疼痛和僵硬，以夜间和晨起为甚，活动后减轻。查HLA-B27阳性，骶髂关节CT示双侧骶髂关节模糊、关节间隙变窄。该病人最早和最常受累的部位是", "options": {"A": "颈椎", "B": "腰椎", "C": "骶髂关节", "D": "髋关节", "E": "膝关节"}, "answer": "C"}, {"id": 426, "chapter": "第7-9章_内分泌风湿神经", "original_id": 426, "type": "single", "question": "冯某，女，30岁。SLE病史3年，狼疮肾炎Ⅳ型，医嘱给予环磷酰胺冲击治疗。护士应特别注意观察的不良反应是", "options": {"A": "血糖变化", "B": "出血性膀胱炎和骨髓抑制", "C": "血压变化", "D": "心率变化", "E": "体重变化"}, "answer": "B"}, {"id": 427, "chapter": "第7-9章_内分泌风湿神经", "original_id": 427, "type": "single", "question": "朱某，女，28岁。SLE病史2年，目前病情稳定6个月以上，咨询能否妊娠。护士对其进行健康教育时，关于生育指导的说法正确的是", "options": {"A": "SLE病人都不能妊娠", "B": "病情缓解且稳定6个月以上可考虑妊娠", "C": "妊娠期间可以继续使用所有免疫抑制剂", "D": "妊娠不影响SLE病情", "E": "妊娠期间应停用糖皮质激素"}, "answer": "B"}, {"id": 428, "chapter": "第7-9章_内分泌风湿神经", "original_id": 428, "type": "single", "question": "钱某，女，48岁。反复口干、眼干3年，进食干性食物需用水送服，双侧腮腺反复肿大。泪液分泌试验和唾液流率均降低。抗SSA抗体和抗SSB抗体阳性。干燥综合征病人口腔护理的正确措施是", "options": {"A": "减少饮水量以避免加重口干", "B": "经常漱口保持口腔湿润，少量多次饮水", "C": "使用含酒精的漱口水", "D": "进食干硬食物以刺激唾液分泌", "E": "不需要特别的口腔护理"}, "answer": "B"}, {"id": 429, "chapter": "第7-9章_内分泌风湿神经", "original_id": 429, "type": "single", "question": "SLE病人特异性最高的自身抗体是", "options": {"A": "抗核抗体（ANA）", "B": "抗Sm抗体", "C": "类风湿因子（RF）", "D": "抗SSA抗体", "E": "抗中性粒细胞胞浆抗体（ANCA）"}, "answer": "B"}, {"id": 430, "chapter": "第7-9章_内分泌风湿神经", "original_id": 430, "type": "single", "question": "SLE病人最常见的死亡原因是", "options": {"A": "肺部感染", "B": "肾功能衰竭", "C": "心力衰竭", "D": "脑血管意外", "E": "肝功能衰竭"}, "answer": "B"}, {"id": 431, "chapter": "第7-9章_内分泌风湿神经", "original_id": 431, "type": "single", "question": "SLE病人使用糖皮质激素治疗期间，护士应重点观察的不良反应不包括", "options": {"A": "感染", "B": "消化道出血", "C": "骨质疏松", "D": "高血糖", "E": "白细胞升高"}, "answer": "E"}, {"id": 432, "chapter": "第7-9章_内分泌风湿神经", "original_id": 432, "type": "single", "question": "类风湿关节炎（RA）最早出现的关节症状是", "options": {"A": "关节畸形", "B": "关节晨僵", "C": "关节疼痛与肿胀", "D": "关节功能障碍", "E": "关节脱位"}, "answer": "C"}, {"id": 433, "chapter": "第7-9章_内分泌风湿神经", "original_id": 433, "type": "single", "question": "类风湿关节炎最具特征性的手部畸形是", "options": {"A": "猿手", "B": "爪形手", "C": "天鹅颈样畸形和纽扣花样畸形", "D": "垂腕", "E": "猿掌"}, "answer": "C"}, {"id": 434, "chapter": "第7-9章_内分泌风湿神经", "original_id": 434, "type": "single", "question": "强直性脊柱炎病人最重要的护理措施是", "options": {"A": "绝对卧床休息", "B": "指导病人进行脊柱伸展运动和姿势训练", "C": "高热量高脂肪饮食", "D": "避免所有运动", "E": "仅使用止痛药物"}, "answer": "B"}, {"id": 435, "chapter": "第7-9章_内分泌风湿神经", "original_id": 435, "type": "single", "question": "SLE病人出现光过敏时，护理措施不正确的是", "options": {"A": "避免在紫外线最强的时段外出", "B": "外出穿长袖衣物、戴宽边帽", "C": "使用SPF≥30的防晒霜", "D": "适当进行日光浴以增强免疫力", "E": "室内使用窗帘遮挡阳光"}, "answer": "D"}, {"id": 436, "chapter": "第7-9章_内分泌风湿神经", "original_id": 436, "type": "single", "question": "类风湿关节炎病人使用非甾体抗炎药（NSAIDs）时，护士应告知其最常见的不良反应是", "options": {"A": "肝肾损害", "B": "胃肠道反应", "C": "骨髓抑制", "D": "心律失常", "E": "血糖升高"}, "answer": "B"}, {"id": 437, "chapter": "第7-9章_内分泌风湿神经", "original_id": 437, "type": "single", "question": "风湿性疾病病人出现关节疼痛时，下列护理措施不正确的是", "options": {"A": "评估疼痛的部位、性质和程度", "B": "急性期卧床休息，减少关节活动", "C": "局部可给予热敷或冷敷", "D": "强制病人进行剧烈关节运动", "E": "遵医嘱给予止痛药物"}, "answer": "D"}, {"id": 438, "chapter": "第7-9章_内分泌风湿神经", "original_id": 438, "type": "single", "question": "类风湿关节炎病人关节受累的特点包括", "options": {"A": "以远端指间关节受累为主", "B": "对称性多关节受累，以近端指间关节和掌指关节为主", "C": "非对称性少关节受累", "D": "仅累及大关节", "E": "游走性关节受累"}, "answer": "B"}, {"id": 439, "chapter": "第7-9章_内分泌风湿神经", "original_id": 439, "type": "multi", "question": "罗某，女，25岁。确诊SLE，面部蝶形红斑明显，ANA阳性，抗ds-DNA抗体阳性，补体C3降低。该病人目前可能出现的临床表现包括", "options": {"A": "面部蝶形红斑", "B": "光过敏", "C": "口腔溃疡", "D": "关节痛", "E": "肾脏损害"}, "answer": "A、B、C、D、E"}, {"id": 440, "chapter": "第7-9章_内分泌风湿神经", "original_id": 440, "type": "multi", "question": "林某，男，28岁。强直性脊柱炎3年，骶髂关节X线分级为Ⅲ级。护士对其进行健康教育的内容应包括", "options": {"A": "坚持适当的脊柱伸展运动", "B": "睡硬板床，低枕", "C": "避免长时间保持一个姿势", "D": "戒烟", "E": "长期卧床以减轻疼痛"}, "answer": "A、B、C、D"}, {"id": 441, "chapter": "第7-9章_内分泌风湿神经", "original_id": 441, "type": "multi", "question": "吴某，女，42岁。类风湿关节炎8年，目前处于活动期，双手多个关节肿痛，晨僵>1小时。该病人的护理措施应包括", "options": {"A": "急性期卧床休息，减少关节负重", "B": "保持关节功能位", "C": "遵医嘱使用NSAIDs和DMARDs", "D": "晨起后温水浸泡僵硬关节", "E": "进行高强度关节运动以恢复功能"}, "answer": "A、B、C、D"}, {"id": 442, "chapter": "第7-9章_内分泌风湿神经", "original_id": 442, "type": "multi", "question": "杨某，女，35岁。SLE合并狼疮肾炎，正在使用糖皮质激素联合环磷酰胺治疗。该病人的用药护理注意事项包括", "options": {"A": "糖皮质激素不可突然停药，需逐渐减量", "B": "注意预防感染", "C": "补充钙剂和维生素D预防骨质疏松", "D": "环磷酰胺用药期间应充分水化以防出血性膀胱炎", "E": "监测血压、血糖变化"}, "answer": "A、B、C、D、E"}, {"id": 443, "chapter": "第7-9章_内分泌风湿神经", "original_id": 443, "type": "multi", "question": "SLE病人的诱发因素包括", "options": {"A": "紫外线照射", "B": "感染", "C": "妊娠", "D": "某些药物（如肼屈嗪、普鲁卡因酰胺）", "E": "精神创伤"}, "answer": "A、B、C、D、E"}, {"id": 444, "chapter": "第7-9章_内分泌风湿神经", "original_id": 444, "type": "multi", "question": "干燥综合征的典型表现包括", "options": {"A": "口干", "B": "眼干", "C": "猖獗龋齿", "D": "腮腺肿大", "E": "关节疼痛"}, "answer": "A、B、C、D、E"}, {"id": 445, "chapter": "第7-9章_内分泌风湿神经", "original_id": 445, "type": "multi", "question": "风湿性疾病病人使用糖皮质激素的注意事项包括", "options": {"A": "不可突然停药，需逐渐减量", "B": "注意预防感染", "C": "补充钙剂和维生素D预防骨质疏松", "D": "监测血压、血糖变化", "E": "长期大剂量使用无需监测"}, "answer": "A、B、C、D"}, {"id": 446, "chapter": "第7-9章_内分泌风湿神经", "original_id": 446, "type": "multi", "question": "类风湿关节炎的治疗药物包括", "options": {"A": "非甾体抗炎药", "B": "糖皮质激素", "C": "改善病情抗风湿药（DMARDs）", "D": "生物制剂", "E": "抗生素"}, "answer": "A、B、C、D"}, {"id": 447, "chapter": "第7-9章_内分泌风湿神经", "original_id": 447, "type": "multi", "question": "SLE病人的护理措施包括", "options": {"A": "避免日光直射，做好防晒", "B": "活动期卧床休息，缓解期适当活动", "C": "给予高蛋白、高维生素、低脂饮食", "D": "心理护理，减轻焦虑", "E": "观察有无肾脏损害表现"}, "answer": "A、B、C、D、E"}, {"id": 448, "chapter": "第7-9章_内分泌风湿神经", "original_id": 448, "type": "multi", "question": "类风湿关节炎的关节外表现包括", "options": {"A": "类风湿结节", "B": "类风湿血管炎", "C": "肺间质纤维化", "D": "干燥综合征", "E": "心脏瓣膜病变"}, "answer": "A、B、C、D"}, {"id": 449, "chapter": "第7-9章_内分泌风湿神经", "original_id": 449, "type": "multi", "question": "SLE病人可能出现的血液系统异常包括", "options": {"A": "白细胞减少", "B": "血小板减少", "C": "溶血性贫血", "D": "红细胞增多", "E": "淋巴细胞减少"}, "answer": "A、B、C、E"}, {"id": 450, "chapter": "第7-9章_内分泌风湿神经", "original_id": 450, "type": "multi", "question": "风湿性疾病病人康复期运动指导的原则包括", "options": {"A": "循序渐进，量力而行", "B": "急性炎症期减少关节负重活动", "C": "缓解期进行适当的功能锻炼", "D": "以关节活动度训练和肌力训练为主", "E": "运动量越大越好"}, "answer": "A、B、C、D"}, {"id": 451, "chapter": "第7-9章_内分泌风湿神经", "original_id": 451, "type": "multi", "question": "SLE病人使用羟氯喹治疗的注意事项包括", "options": {"A": "定期进行眼科检查", "B": "注意视网膜毒性", "C": "用药期间监测心电图", "D": "可快速静脉推注", "E": "注意心脏传导功能"}, "answer": "A、B、C、E"}, {"id": 452, "chapter": "第7-9章_内分泌风湿神经", "original_id": 452, "type": "multi", "question": "贺某，女，27岁。SLE病史1年，目前口服泼尼松15mg/d，病情稳定。护士对其进行出院健康教育的内容应包括", "options": {"A": "避免阳光直射，外出做好防晒", "B": "遵医嘱服药，不可自行减量或停药", "C": "定期复查血常规、尿常规和补体", "D": "病情稳定可考虑妊娠，需提前咨询", "E": "预防感染，避免去人群密集场所"}, "answer": "A、B、C、D、E"}, {"id": 453, "chapter": "第7-9章_内分泌风湿神经", "original_id": 453, "type": "judge", "question": "短暂性脑缺血发作（TIA）的典型特点是症状通常在24小时内完全恢复，不留后遗症。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 454, "chapter": "第7-9章_内分泌风湿神经", "original_id": 454, "type": "judge", "question": "脑出血最常见的出血部位是脑桥。", "options": {"A": "正确", "B": "错误"}, "answer": "B"}, {"id": 455, "chapter": "第7-9章_内分泌风湿神经", "original_id": 455, "type": "judge", "question": "蛛网膜下腔出血最突出的症状是突发剧烈头痛，常被描述为'一生中最剧烈的头痛'。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 456, "chapter": "第7-9章_内分泌风湿神经", "original_id": 456, "type": "judge", "question": "癫痫大发作时应立即强行按压病人肢体以制止抽搐。", "options": {"A": "正确", "B": "错误"}, "answer": "B"}, {"id": 457, "chapter": "第7-9章_内分泌风湿神经", "original_id": 457, "type": "judge", "question": "帕金森病病人典型的运动症状包括静止性震颤、肌强直、运动迟缓和姿势步态异常。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 458, "chapter": "第7-9章_内分泌风湿神经", "original_id": 458, "type": "judge", "question": "格林-巴利综合征（GBS）最危险的并发症是呼吸肌麻痹导致的呼吸衰竭。", "options": {"A": "正确", "B": "错误"}, "answer": "A"}, {"id": 459, "chapter": "第7-9章_内分泌风湿神经", "original_id": 459, "type": "judge", "question": "脑疝形成时，患侧瞳孔先缩小后散大，对光反射消失。", "options": {"A": "正确", "B": "错误"}, "answer": "B"}, {"id": 460, "chapter": "第7-9章_内分泌风湿神经", "original_id": 460, "type": "single", "question": "沈某，男，62岁。有高血压、糖尿病史。近3个月来反复出现短暂性右侧肢体无力，每次持续约20分钟后自行缓解，发作间期神经系统查体无异常。头颅MRI未见梗死灶。该病人最可能的诊断是", "options": {"A": "脑梗死", "B": "短暂性脑缺血发作", "C": "脑出血", "D": "蛛网膜下腔出血", "E": "癫痫"}, "answer": "B"}, {"id": 461, "chapter": "第7-9章_内分泌风湿神经", "original_id": 461, "type": "single", "question": "孙某，男，68岁。有高血压病史20年。晨起时发现右侧肢体无力，言语含糊，口角歪斜向左侧。头颅CT未见出血。发病时间约2小时。该病人最可能的诊断是", "options": {"A": "脑出血", "B": "蛛网膜下腔出血", "C": "急性脑梗死", "D": "短暂性脑缺血发作", "E": "脑栓塞"}, "answer": "C"}, {"id": 462, "chapter": "第7-9章_内分泌风湿神经", "original_id": 462, "type": "single", "question": "徐某，女，75岁。突发左侧肢体不能活动伴失语3小时入院。头颅CT排除脑出血，NIHSS评分14分。发病时间在溶栓时间窗内，无溶栓禁忌证。该病人超早期溶栓治疗最常用的药物是", "options": {"A": "尿激酶", "B": "重组组织型纤溶酶原激活剂（rt-PA）", "C": "链激酶", "D": "肝素", "E": "华法林"}, "answer": "B"}, {"id": 463, "chapter": "第7-9章_内分泌风湿神经", "original_id": 463, "type": "single", "question": "曹某，男，58岁。有高血压病史15年，未规律服药。情绪激动时突发剧烈头痛，随即出现右侧肢体偏瘫、失语，呕吐胃内容物一次。血压200/110mmHg。头颅CT示左侧基底节区高密度影。该病人最可能的诊断是", "options": {"A": "脑梗死", "B": "脑出血", "C": "蛛网膜下腔出血", "D": "TIA", "E": "脑膜炎"}, "answer": "B"}, {"id": 464, "chapter": "第7-9章_内分泌风湿神经", "original_id": 464, "type": "single", "question": "脑出血急性期病人应绝对卧床休息，一般要求卧床", "options": {"A": "1～2周", "B": "2～4周", "C": "4～6周", "D": "6～8周", "E": "8～10周"}, "answer": "B"}, {"id": 465, "chapter": "第7-9章_内分泌风湿神经", "original_id": 465, "type": "single", "question": "脑出血急性期应将床头抬高", "options": {"A": "5°～10°", "B": "15°～30°", "C": "30°～45°", "D": "45°～60°", "E": "60°～90°"}, "answer": "B"}, {"id": 466, "chapter": "第7-9章_内分泌风湿神经", "original_id": 466, "type": "single", "question": "袁某，女，45岁。在用力排便时突发剧烈头痛，呈炸裂样，伴恶心、呕吐。查体：颈项强直，Kernig征阳性。头颅CT示脑沟、脑池内高密度影。该病人最可能的诊断是", "options": {"A": "脑出血", "B": "脑梗死", "C": "蛛网膜下腔出血", "D": "脑膜炎", "E": "偏头痛"}, "answer": "C"}, {"id": 467, "chapter": "第7-9章_内分泌风湿神经", "original_id": 467, "type": "single", "question": "蛛网膜下腔出血最常见的病因是", "options": {"A": "高血压", "B": "颅内动脉瘤破裂", "C": "脑动静脉畸形", "D": "脑肿瘤", "E": "血液病"}, "answer": "B"}, {"id": 468, "chapter": "第7-9章_内分泌风湿神经", "original_id": 468, "type": "single", "question": "蛛网膜下腔出血病人为防止再出血，护理措施不正确的是", "options": {"A": "绝对卧床休息4～6周", "B": "避免用力排便、咳嗽等诱因", "C": "保持大便通畅", "D": "鼓励病人早期下床活动", "E": "保持环境安静"}, "answer": "D"}, {"id": 469, "chapter": "第7-9章_内分泌风湿神经", "original_id": 469, "type": "single", "question": "丁某，女，22岁。癫痫病史5年。今日凌晨突然意识丧失，全身强直-阵挛性发作，双眼上翻，口吐白沫，持续约2分钟自行缓解。癫痫大发作时，护士首先应采取的护理措施是", "options": {"A": "立即通知医生", "B": "保持呼吸道通畅，防止窒息", "C": "立即静脉注射地西泮", "D": "强行按压病人肢体", "E": "立即进行心肺复苏"}, "answer": "B"}, {"id": 470, "chapter": "第7-9章_内分泌风湿神经", "original_id": 470, "type": "single", "question": "邹某，男，30岁。癫痫持续发作约40分钟未自行停止，表现为全身强直-阵挛性抽搐。急诊送入。护士应立即协助医生首先采取的措施是", "options": {"A": "口服苯妥英钠", "B": "静脉缓慢注射地西泮", "C": "肌肉注射苯巴比妥", "D": "口服丙戊酸钠", "E": "灌肠给药"}, "answer": "B"}, {"id": 471, "chapter": "第7-9章_内分泌风湿神经", "original_id": 471, "type": "single", "question": "蒋某，男，65岁。近2年来逐渐出现右手不自主抖动，安静时明显，活动时减轻，伴动作迟缓、面部表情减少、起步困难。帕金森病病人使用左旋多巴治疗时，护士应告知其最常见的早期不良反应是", "options": {"A": "幻觉", "B": "恶心、呕吐等胃肠道反应", "C": "直立性低血压", "D": "运动障碍", "E": "失眠"}, "answer": "B"}, {"id": 472, "chapter": "第7-9章_内分泌风湿神经", "original_id": 472, "type": "single", "question": "帕金森病病人的饮食指导中，有助于改善症状的措施是", "options": {"A": "高蛋白饮食", "B": "低纤维饮食", "C": "增加膳食纤维摄入，预防便秘", "D": "减少饮水量", "E": "高脂肪饮食"}, "answer": "C"}, {"id": 473, "chapter": "第7-9章_内分泌风湿神经", "original_id": 473, "type": "single", "question": "许某，女，38岁。近半年来出现双眼睑下垂，晨轻暮重，近1个月来出现吞咽困难、饮水呛咳。新斯的明试验阳性。该病人最可能的诊断是", "options": {"A": "脑梗死", "B": "脑干肿瘤", "C": "重症肌无力", "D": "格林-巴利综合征", "E": "多发性硬化"}, "answer": "C"}, {"id": 474, "chapter": "第7-9章_内分泌风湿神经", "original_id": 474, "type": "single", "question": "重症肌无力病人使用新斯的明治疗时，护士应重点观察的不良反应是", "options": {"A": "血压升高", "B": "心率减慢、腹痛、腹泻等毒蕈碱样反应", "C": "高血糖", "D": "肝功能损害", "E": "肾功能损害"}, "answer": "B"}, {"id": 475, "chapter": "第7-9章_内分泌风湿神经", "original_id": 475, "type": "single", "question": "王某，男，30岁。2周前有腹泻病史。近3天来出现双下肢对称性无力，逐渐向上发展至双上肢，伴四肢末端感觉异常。脑脊液检查示蛋白升高、细胞数正常。该病人最可能的诊断是", "options": {"A": "急性脊髓炎", "B": "格林-巴利综合征", "C": "重症肌无力", "D": "周期性麻痹", "E": "多发性硬化"}, "answer": "B"}, {"id": 476, "chapter": "第7-9章_内分泌风湿神经", "original_id": 476, "type": "single", "question": "颅内压增高三主征是指", "options": {"A": "头痛、呕吐、视乳头水肿", "B": "头痛、发热、颈项强直", "C": "昏迷、高热、瞳孔散大", "D": "偏瘫、失语、偏身感觉障碍", "E": "头晕、恶心、步态不稳"}, "answer": "A"}, {"id": 477, "chapter": "第7-9章_内分泌风湿神经", "original_id": 477, "type": "single", "question": "梁某，男，50岁。脑出血后第2天，护士巡视发现病人意识障碍加重，呼之不应。查体：左侧瞳孔直径5mm，右侧3mm，对光反射迟钝，右侧肢体偏瘫。该病人最可能发生了", "options": {"A": "脑出血加重", "B": "再出血", "C": "小脑幕切迹疝", "D": "枕骨大孔疝", "E": "癫痫发作"}, "answer": "C"}, {"id": 478, "chapter": "第7-9章_内分泌风湿神经", "original_id": 478, "type": "single", "question": "枕骨大孔疝最危险的表现是", "options": {"A": "剧烈头痛", "B": "频繁呕吐", "C": "突然呼吸骤停", "D": "瞳孔散大", "E": "偏瘫"}, "answer": "C"}, {"id": 479, "chapter": "第7-9章_内分泌风湿神经", "original_id": 479, "type": "single", "question": "降低颅内压的首选药物是", "options": {"A": "呋塞米", "B": "20%甘露醇", "C": "甘油果糖", "D": "地塞米松", "E": "白蛋白"}, "answer": "B"}, {"id": 480, "chapter": "第7-9章_内分泌风湿神经", "original_id": 480, "type": "single", "question": "甘露醇脱水治疗时，输液速度要求为", "options": {"A": "缓慢滴注，>2小时", "B": "一般速度，60～80滴/分", "C": "快速滴注，250mL在15～30分钟内滴完", "D": "推注给药", "E": "与常规液体等速滴注"}, "answer": "C"}, {"id": 481, "chapter": "第7-9章_内分泌风湿神经", "original_id": 481, "type": "single", "question": "于某，男，45岁。颅脑外伤后出现剧烈头痛、喷射性呕吐、视乳头水肿。颅内压监测示颅内压25mmHg。该病人目前最首要的护理诊断是", "options": {"A": "疼痛", "B": "脑组织灌注无效", "C": "有受伤的危险", "D": "焦虑", "E": "体温过高"}, "answer": "B"}, {"id": 482, "chapter": "第7-9章_内分泌风湿神经", "original_id": 482, "type": "single", "question": "脑出血病人急性期血压处理的原则是", "options": {"A": "立即将血压降至正常水平", "B": "快速降压至收缩压<120mmHg", "C": "不宜急剧降压，当收缩压>200mmHg时适当降压", "D": "无需监测血压", "E": "使用口服降压药缓慢降压"}, "answer": "C"}, {"id": 483, "chapter": "第7-9章_内分泌风湿神经", "original_id": 483, "type": "single", "question": "脑卒中病人吞咽困难的护理措施不包括", "options": {"A": "评估吞咽功能", "B": "取坐位或半卧位进食", "C": "给予糊状或软食", "D": "鼓励快速大量进食", "E": "必要时给予鼻饲"}, "answer": "D"}, {"id": 484, "chapter": "第7-9章_内分泌风湿神经", "original_id": 484, "type": "single", "question": "格林-巴利综合征病人呼吸肌麻痹时的首要处理措施是", "options": {"A": "给予高流量吸氧", "B": "立即气管插管或气管切开，机械通气", "C": "静脉注射新斯的明", "D": "大剂量糖皮质激素冲击", "E": "给予呼吸兴奋剂"}, "answer": "B"}, {"id": 485, "chapter": "第7-9章_内分泌风湿神经", "original_id": 485, "type": "single", "question": "卢某，男，25岁。格林-巴利综合征。护士为其行腰椎穿刺术，采集脑脊液送检。该病人脑脊液检查的特征性表现是", "options": {"A": "细胞数和蛋白均升高", "B": "细胞数正常而蛋白升高（蛋白-细胞分离现象）", "C": "细胞数升高而蛋白正常", "D": "细胞数和蛋白均降低", "E": "脑脊液呈血性"}, "answer": "B"}, {"id": 486, "chapter": "第7-9章_内分泌风湿神经", "original_id": 486, "type": "single", "question": "脑出血病人使用甘露醇时，护士应重点观察的指标是", "options": {"A": "体温变化", "B": "尿量和肾功能", "C": "心率变化", "D": "血糖变化", "E": "血红蛋白变化"}, "answer": "B"}, {"id": 487, "chapter": "第7-9章_内分泌风湿神经", "original_id": 487, "type": "single", "question": "小脑幕切迹疝（颞叶钩回疝）的典型表现为", "options": {"A": "双侧瞳孔缩小", "B": "患侧瞳孔先缩小后散大，对侧肢体瘫痪", "C": "双侧瞳孔散大", "D": "患侧瞳孔散大，同侧肢体瘫痪", "E": "意识清醒，无瞳孔变化"}, "answer": "B"}, {"id": 488, "chapter": "第7-9章_内分泌风湿神经", "original_id": 488, "type": "multi", "question": "崔某，男，60岁。脑出血急性期，目前昏迷，血压180/100mmHg。护士应立即采取的护理措施包括", "options": {"A": "绝对卧床休息，避免搬动", "B": "头部抬高15°～30°", "C": "保持呼吸道通畅", "D": "密切观察意识、瞳孔、生命体征变化", "E": "鼓励病人早期下床活动"}, "answer": "A、B、C、D"}, {"id": 489, "chapter": "第7-9章_内分泌风湿神经", "original_id": 489, "type": "multi", "question": "魏某，女，55岁。蛛网膜下腔出血后行腰椎穿刺术，脑脊液呈均匀血性。该病人为防止再出血，护士应采取的护理措施包括", "options": {"A": "绝对卧床休息4～6周", "B": "避免用力排便", "C": "避免剧烈咳嗽", "D": "保持环境安静", "E": "鼓励早期下床活动"}, "answer": "A、B、C、D"}, {"id": 490, "chapter": "第7-9章_内分泌风湿神经", "original_id": 490, "type": "multi", "question": "邓某，男，35岁。癫痫大发作时突然倒地，全身抽搐，口吐白沫。在场的护士应立即采取的措施包括", "options": {"A": "将病人平卧，头偏向一侧", "B": "松解衣领、腰带", "C": "将压舌板或纱布包裹的开口器放入上下臼齿之间", "D": "记录发作持续时间和表现", "E": "强行按压抽搐肢体以制止"}, "answer": "A、B、C、D"}, {"id": 491, "chapter": "第7-9章_内分泌风湿神经", "original_id": 491, "type": "multi", "question": "龚某，男，68岁。帕金森病5年，目前使用左旋多巴/苄丝肼治疗。护士对其进行用药指导和饮食指导应包括", "options": {"A": "左旋多巴应与高蛋白饮食分开服用", "B": "增加膳食纤维摄入，预防便秘", "C": "起床时动作宜缓慢，预防直立性低血压", "D": "鼓励病人进行步态训练", "E": "症状改善后可自行停药"}, "answer": "A、B、C、D"}, {"id": 492, "chapter": "第7-9章_内分泌风湿神经", "original_id": 492, "type": "multi", "question": "廖某，女，40岁。重症肌无力住院病人，突然出现呼吸困难、发绀。新斯的明试验后症状无改善反而加重。护士判断该病人可能发生了胆碱能危象，应立即采取的措施包括", "options": {"A": "立即停用抗胆碱酯酶药物", "B": "保持呼吸道通畅，必要时机械通气", "C": "遵医嘱给予阿托品", "D": "加大新斯的明剂量", "E": "密切监测血氧饱和度"}, "answer": "A、B、C、E"}, {"id": 493, "chapter": "第7-9章_内分泌风湿神经", "original_id": 493, "type": "multi", "question": "潘某，男，28岁。格林-巴利综合征住院，目前四肢肌力2级，呼吸功能尚可。护士应采取的护理措施包括", "options": {"A": "密切监测呼吸频率和血氧饱和度", "B": "做好气管插管或切开的准备", "C": "协助翻身，保持皮肤完整", "D": "进行被动关节活动", "E": "给予高蛋白、高维生素饮食"}, "answer": "A、B、C、D、E"}, {"id": 494, "chapter": "第7-9章_内分泌风湿神经", "original_id": 494, "type": "multi", "question": "石某，男，70岁。脑梗死行rt-PA静脉溶栓治疗后2小时。护士应重点观察的内容包括", "options": {"A": "密切监测意识、瞳孔、生命体征", "B": "观察有无出血征象", "C": "评估神经功能改善或恶化情况", "D": "24小时内避免侵入性操作", "E": "立即给予肝素抗凝治疗"}, "answer": "A、B、C、D"}, {"id": 495, "chapter": "第7-9章_内分泌风湿神经", "original_id": 495, "type": "multi", "question": "邵某，女，60岁。脑出血恢复期，左侧肢体偏瘫，语言含糊。护士为其制定康复计划应包括", "options": {"A": "尽早开始康复训练", "B": "循序渐进，从被动运动到主动运动", "C": "兼顾运动、语言、认知功能康复", "D": "每2小时翻身一次预防压疮", "E": "患侧肢体保持功能位"}, "answer": "A、B、C、D、E"}, {"id": 496, "chapter": "第7-9章_内分泌风湿神经", "original_id": 496, "type": "multi", "question": "脑出血的常见诱因包括", "options": {"A": "情绪激动", "B": "用力排便", "C": "剧烈咳嗽", "D": "过度劳累", "E": "气候变化"}, "answer": "A、B、C、D"}, {"id": 497, "chapter": "第7-9章_内分泌风湿神经", "original_id": 497, "type": "multi", "question": "蛛网膜下腔出血的临床表现包括", "options": {"A": "突发剧烈头痛", "B": "恶心、呕吐", "C": "脑膜刺激征阳性", "D": "偏瘫", "E": "血性脑脊液"}, "answer": "A、B、C、E"}, {"id": 498, "chapter": "第7-9章_内分泌风湿神经", "original_id": 498, "type": "multi", "question": "重症肌无力的临床特点包括", "options": {"A": "受累骨骼肌易疲劳，活动后加重，休息后减轻", "B": "晨轻暮重", "C": "常累及眼外肌，表现为上睑下垂", "D": "可累及呼吸肌导致呼吸困难", "E": "腱反射消失"}, "answer": "A、B、C、D"}, {"id": 499, "chapter": "第7-9章_内分泌风湿神经", "original_id": 499, "type": "multi", "question": "格林-巴利综合征（GBS）的临床表现包括", "options": {"A": "对称性肢体弛缓性瘫痪", "B": "感觉障碍呈手套袜套样分布", "C": "脑脊液蛋白-细胞分离", "D": "可出现呼吸肌麻痹", "E": "腱反射亢进"}, "answer": "A、B、C、D"}, {"id": 500, "chapter": "第7-9章_内分泌风湿神经", "original_id": 500, "type": "multi", "question": "颅内压增高的常见原因包括", "options": {"A": "脑水肿", "B": "颅内占位性病变", "C": "脑脊液循环障碍", "D": "脑血流增加", "E": "颅腔容积缩小"}, "answer": "A、B、C、D、E"}, {"id": 501, "chapter": "第7-9章_内分泌风湿神经", "original_id": 501, "type": "multi", "question": "脑疝的先兆表现包括", "options": {"A": "剧烈头痛，频繁呕吐", "B": "烦躁不安", "C": "意识障碍进行性加重", "D": "一侧瞳孔进行性散大", "E": "生命体征紊乱（Cushing反应）"}, "answer": "A、B、C、D、E"}, {"id": 502, "chapter": "第7-9章_内分泌风湿神经", "original_id": 502, "type": "multi", "question": "脑梗死的危险因素包括", "options": {"A": "高血压", "B": "糖尿病", "C": "高脂血症", "D": "心房颤动", "E": "吸烟"}, "answer": "A、B、C、D、E"}, {"id": 503, "chapter": "第7-9章_内分泌风湿神经", "original_id": 503, "type": "multi", "question": "TIA病人的健康教育内容包括", "options": {"A": "积极控制高血压、糖尿病等危险因素", "B": "遵医嘱服用抗血小板药物", "C": "合理饮食，低盐低脂", "D": "TIA症状轻微，无需重视", "E": "定期复查，出现症状及时就诊"}, "answer": "A、B、C、E"}, {"id": 504, "chapter": "第7-9章_内分泌风湿神经", "original_id": 504, "type": "multi", "question": "癫痫病人的健康指导包括", "options": {"A": "规律服药，不随意停药或减量", "B": "避免过度疲劳、情绪激动等诱因", "C": "禁止驾驶车辆、高空作业等危险活动", "D": "饮食清淡，避免饮酒和含咖啡因饮料", "E": "发作停止1年后即可自行停药"}, "answer": "A、B、C、D"}, {"id": 505, "chapter": "第7-9章_内分泌风湿神经", "original_id": 505, "type": "multi", "question": "帕金森病病人的护理诊断/问题包括", "options": {"A": "躯体活动障碍", "B": "有跌倒的危险", "C": "便秘", "D": "自我照顾能力缺陷", "E": "睡眠形态紊乱"}, "answer": "A、B、C、D、E"}, {"id": 506, "chapter": "第7-9章_内分泌风湿神经", "original_id": 506, "type": "multi", "question": "腰椎穿刺术后病人的护理措施包括", "options": {"A": "去枕平卧4～6小时", "B": "鼓励病人尽早下床活动", "C": "观察穿刺部位有无渗液、渗血", "D": "注意观察意识、瞳孔及生命体征变化", "E": "鼓励多饮水"}, "answer": "A、C、D、E"}, {"id": 507, "chapter": "第7-9章_内分泌风湿神经", "original_id": 507, "type": "single", "question": "护士在进行静脉输液时，发现穿刺部位出现肿胀、疼痛，回抽无回血。正确的处理措施是", "options": {"A": "减慢输液速度继续观察", "B": "局部热敷后继续输液", "C": "立即停止输液，拔针重新穿刺", "D": "加压输液以冲开阻塞", "E": "调整针头角度继续输液"}, "answer": "C"}, {"id": 508, "chapter": "第7-9章_内分泌风湿神经", "original_id": 508, "type": "single", "question": "护理文件书写的基本要求不包括", "options": {"A": "客观、真实、准确", "B": "及时、完整", "C": "字迹清晰，不得涂改", "D": "可以使用涂改液修改错误", "E": "使用医学术语"}, "answer": "D"}, {"id": 509, "chapter": "第7-9章_内分泌风湿神经", "original_id": 509, "type": "multi", "question": "护理交接班时应重点交接的内容包括", "options": {"A": "危重病人的病情变化和特殊处理", "B": "新入院病人和手术病人的情况", "C": "各种引流管的通畅情况", "D": "特殊用药的执行情况", "E": "病人的情绪状态和家属需求"}, "answer": "A、B、C、D、E"}, {"id": 510, "chapter": "第7-9章_内分泌风湿神经", "original_id": 510, "type": "multi", "question": "患者安全管理的措施包括", "options": {"A": "严格执行查对制度", "B": "落实跌倒/坠床风险评估及防范措施", "C": "正确使用约束带并做好记录", "D": "做好管路滑脱的预防", "E": "加强护患沟通，落实知情同意"}, "answer": "A、B、C、D、E"}];